-- Poems batch 50
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1caf8ee7-8aad-4b43-9f08-124c35369875','贈遠二首 一','薛濤','唐','唐诗','tang','','[]','芙蓉新落蜀山秋，錦字開緘到是愁。',32,'全唐诗/poet.tang.44000.json','["芙蓉新落蜀山秋，錦字開緘到是愁。", "閨閣不知戎馬事，月高還上望夫樓。"]'),
('4d99e6d2-1637-43d6-840e-730704032114','贈遠二首 二','薛濤','唐','唐诗','tang','','[]','擾弱新蒲葉又齊，春深花落塞前溪。',32,'全唐诗/poet.tang.44000.json','["擾弱新蒲葉又齊，春深花落塞前溪。", "知君未轉秦關騎，月照千門掩袖啼。"]'),
('e87f04dd-4dea-4274-abc3-4f53da494a58','秋泉','薛濤','唐','唐诗','tang','','[]','冷色初澄一帶煙，幽聲遙瀉十絲弦。',32,'全唐诗/poet.tang.44000.json','["冷色初澄一帶煙，幽聲遙瀉十絲弦。", "長來枕上牽情思，不使愁人半夜眠。"]'),
('c6f3cf07-5f0f-4a52-8234-021dfe64a58e','柳絮','薛濤','唐','唐诗','tang','','[]','二月楊花輕復微，春風搖蕩惹人衣。',32,'全唐诗/poet.tang.44000.json','["二月楊花輕復微，春風搖蕩惹人衣。", "他家本是無情物，一任南飛又北飛。"]'),
('53e61e16-6dc4-442e-b776-fee363979578','續嘉陵驛詩獻武相國','薛濤','唐','唐诗','tang','','[]','蜀門西更上青天，強爲公歌蜀國弦。',32,'全唐诗/poet.tang.44000.json','["蜀門西更上青天，強爲公歌蜀國弦。", "卓氏長卿稱士女，錦江玉壘獻山川。"]'),
('8bc58b7c-45e8-4ba5-b70f-655885433cc9','段相國遊武擔寺病不能從題寄','薛濤','唐','唐诗','tang','','[]','消瘦翻堪見令公，落花無那恨東風。',32,'全唐诗/poet.tang.44000.json','["消瘦翻堪見令公，落花無那恨東風。", "儂心猶道青春在，羞看飛蓬石鏡中。"]'),
('bbea22bb-e2b3-4cb3-baab-55f91144a159','贈段校書','薛濤','唐','唐诗','tang','','[]','公子翩翩說校書，玉弓金勒紫綃裾。',32,'全唐诗/poet.tang.44000.json','["公子翩翩說校書，玉弓金勒紫綃裾。", "玄成莫便驕名譽，文采風流定不如。"]'),
('56319d20-e3fc-46fe-9ec8-e0ab1100f013','十離詩 犬離主','薛濤','唐','唐诗','tang','','[]','馴擾朱門四五年，毛香足淨主人憐。',32,'全唐诗/poet.tang.44000.json','["馴擾朱門四五年，毛香足淨主人憐。", "無端咬著親情客，不得紅絲毯上眠。"]'),
('137c03fc-4837-4508-9f83-6fde20ca0721','十離詩 筆離手','薛濤','唐','唐诗','tang','','[]','越管宣毫始稱情，紅箋紙上撒花瓊。',32,'全唐诗/poet.tang.44000.json','["越管宣毫始稱情，紅箋紙上撒花瓊。", "都緣用久鋒頭盡，不得羲之手裏擎。"]'),
('038324a3-80a3-4127-9c47-f5967f5784be','十離詩 馬離廐','薛濤','唐','唐诗','tang','','[]','雪耳紅毛淺碧蹄，追風曾到日東西。',32,'全唐诗/poet.tang.44000.json','["雪耳紅毛淺碧蹄，追風曾到日東西。", "爲驚玉貌郎君墜，不得華軒更一嘶。"]'),
('cf202f23-9e0f-476a-b478-1a05a2fc85d0','十離詩 鸚鵡離籠','薛濤','唐','唐诗','tang','','[]','隴西獨自一孤身，飛去飛來上錦茵。',32,'全唐诗/poet.tang.44000.json','["隴西獨自一孤身，飛去飛來上錦茵。", "都緣出語無方便，不得籠中再喚人。"]'),
('db1f510a-cc7a-4717-83d0-a6579e6fa78b','十離詩 燕離巢','薛濤','唐','唐诗','tang','','[]','出入朱門未忍拋，主人常愛語交交。',32,'全唐诗/poet.tang.44000.json','["出入朱門未忍拋，主人常愛語交交。", "銜泥穢汚珊瑚枕，不得梁間更壘巢。"]'),
('4bb9b455-96ce-40dd-b844-40c3eff39445','十離詩 珠離掌','薛濤','唐','唐诗','tang','','[]','皎潔圓明內外通，清光似照水晶宮。',32,'全唐诗/poet.tang.44000.json','["皎潔圓明內外通，清光似照水晶宮。", "只緣一點玷相穢，不得終宵在掌中。"]'),
('a4f14df4-0dbb-4ccd-99f7-69f4c67f7d09','十離詩 魚離池','薛濤','唐','唐诗','tang','','[]','跳躍深池四五秋，常搖朱尾弄綸鉤。',32,'全唐诗/poet.tang.44000.json','["跳躍深池四五秋，常搖朱尾弄綸鉤。", "無端擺斷芙蓉朵，不得清波更一遊。"]'),
('6ea3902e-f875-4197-a611-256d74419476','十離詩 魚離池','薛濤','唐','唐诗','tang','','[]','戲躍蓮池四五秋，常揺朱尾弄銀鈎。',32,'全唐诗/poet.tang.44000.json','["戲躍蓮池四五秋，常揺朱尾弄銀鈎。", "無緣擺罷芙蓉朶，不得清波更一遊。"]'),
('49b89e56-bc2a-40d2-a5bd-18ac58ce688d','十離詩 鷹離鞲','薛濤','唐','唐诗','tang','','[]','爪利如鋒眼似鈴，平原捉兔稱高情。',32,'全唐诗/poet.tang.44000.json','["爪利如鋒眼似鈴，平原捉兔稱高情。", "無端竄向青雲外，不得君王臂上擎。"]'),
('75d1604c-46e7-446e-81db-70d01702c830','十離詩 竹離亭','薛濤','唐','唐诗','tang','','[]','蓊鬱新栽四五行，常將勁節負秋霜。',32,'全唐诗/poet.tang.44000.json','["蓊鬱新栽四五行，常將勁節負秋霜。", "爲緣春筍鑽墻破，不得垂陰覆玉堂。"]'),
('a65df373-13a1-4910-a348-7f0e987275c6','十離詩 鏡離臺','薛濤','唐','唐诗','tang','','[]','鑄瀉黃金鏡始開，初生三五月裴回。',32,'全唐诗/poet.tang.44000.json','["鑄瀉黃金鏡始開，初生三五月裴回。", "爲遭無限塵蒙蔽，不得華堂上玉臺。"]'),
('105c5d0c-4f32-4dec-b127-eb4a748d2f63','酬杜舍人','薛濤','唐','唐诗','tang','','[]','雙魚底事到儂家，撲手新詩片片霞。',32,'全唐诗/poet.tang.44000.json','["雙魚底事到儂家，撲手新詩片片霞。", "唱到白蘋洲畔曲，芙蓉空老蜀江花。"]'),
('50bf921e-d496-4e51-a962-87553ae33706','籌邊樓','薛濤','唐','唐诗','tang','','[]','平臨雲鳥八窗秋，壯壓西川四十州。',32,'全唐诗/poet.tang.44000.json','["平臨雲鳥八窗秋，壯壓西川四十州。", "諸將莫貪羌族馬，最高層處見邊頭。"]'),
('7c06078e-4c2e-4a17-bee2-08c69dc6003c','贈韋校書','薛濤','唐','唐诗','tang','','[]','芸香誤比荆山玉，那似登科甲乙年。',32,'全唐诗/poet.tang.44000.json','["芸香誤比荆山玉，那似登科甲乙年。", "澹地鮮風將綺思，飄花散蕊媚青天。"]'),
('bba93597-f20c-4723-a7ee-fb6720ea164b','江月樓','薛濤','唐','唐诗','tang','','[]','秋風彷彿吳江冷，鷗鷺參差夕陽影。',48,'全唐诗/poet.tang.44000.json','["秋風彷彿吳江冷，鷗鷺參差夕陽影。", "垂虹納納臥譙門，雉堞眈眈俯漁艇。", "陽安小兒拍手笑，使君幻出江南景。"]'),
('458cf11a-4c09-46c7-88ef-cc2207274c92','西巖','薛濤','唐','唐诗','tang','','[]','凭闌却憶騎鯨客，把酒臨風手自招。',32,'全唐诗/poet.tang.44000.json','["凭闌却憶騎鯨客，把酒臨風手自招。", "細雨聲中停去馬，夕陽影裏亂鳴蜩。"]'),
('b247cf1d-ce88-4d8b-a45c-70b79c873457','罰赴邊上武相公二首 一','薛濤','唐','唐诗','tang','','[]','螢在荒蕪月在天，螢飛豈到月輪邊。',32,'全唐诗/poet.tang.44000.json','["螢在荒蕪月在天，螢飛豈到月輪邊。", "重光萬里應相照，目斷雲霄信不傳。"]'),
('a22d6f83-4ec4-471a-9c1c-9414be712b97','罰赴邊上武相公二首 二','薛濤','唐','唐诗','tang','','[]','按轡嶺頭寒復寒，微風細雨徹心肝。',32,'全唐诗/poet.tang.44000.json','["按轡嶺頭寒復寒，微風細雨徹心肝。", "但得放兒歸舍去，山水屏風永不看。"]'),
('e034923b-7a90-4b47-95f5-ef38508ad2d8','寄舊詩與元微之','薛濤','唐','唐诗','tang','','[]','詩篇調態人皆有，細膩風光我獨知。',64,'全唐诗/poet.tang.44000.json','["詩篇調態人皆有，細膩風光我獨知。", "月下詠花憐暗澹，雨朝題柳爲欹垂。", "長教碧玉藏深處，總向紅牋寫自隨。", "老大不能收拾得，與君開似教男兒。"]'),
('464e00a8-aebe-4dec-88a3-0c3bad290f7a','句','薛濤','唐','唐诗','tang','','[]','枝迎南北鳥，葉送往來風。',12,'全唐诗/poet.tang.44000.json','["枝迎南北鳥，葉送往來風。"]'),
('af2e957f-d736-40f6-87aa-69883b6b7fcb','賦得江邊柳','魚玄機','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u67f3\u6811", "\u6101\u7eea"]','翠色連荒岸，煙姿入遠樓。',48,'全唐诗/poet.tang.44000.json','["翠色連荒岸，煙姿入遠樓。", "影鋪秋水面，花落釣人頭。", "根老藏魚窟，枝低繫客舟。", "蕭蕭風雨夜，驚夢復添愁。"]'),
('218696ee-228c-4a50-905f-93801105dd89','贈鄰女','魚玄機','唐','唐诗','tang','','["\u54f2\u7406", "\u5973\u5b50", "\u7231\u60c5"]','羞日遮羅袖，愁春嬾起妝。',48,'全唐诗/poet.tang.44000.json','["羞日遮羅袖，愁春嬾起妝。", "易求無價寶，難得有心郎。", "枕上潛垂淚，花間暗斷腸。", "自能窺宋玉，何必恨王昌。"]'),
('aaa530a1-62c1-4f0d-8812-383d63a5ab09','寄國香','魚玄機','唐','唐诗','tang','','[]','旦夕醉吟身，相思又此春。',48,'全唐诗/poet.tang.44000.json','["旦夕醉吟身，相思又此春。", "雨中寄書使，窗下斷腸人。", "山捲珠簾看，愁隨芳草新。", "別來清宴上，幾度落梁塵。"]'),
('2b9c2e57-adfe-4167-b1dd-856ece58cc89','寄題鍊師','魚玄機','唐','唐诗','tang','','[]','霞彩翦爲衣，添香出繡幃。',48,'全唐诗/poet.tang.44000.json','["霞彩翦爲衣，添香出繡幃。", "芙蓉花葉□，山水帔□稀。", "駐履聞鶯語，開籠放鶴飛。", "高堂春睡覺，暮雨正霏霏。"]'),
('03776353-346e-4356-a77a-e88cefbe94f9','寄劉尚書','魚玄機','唐','唐诗','tang','','[]','八座鎮雄軍，歌謠滿路新。',72,'全唐诗/poet.tang.44000.json','["八座鎮雄軍，歌謠滿路新。", "汾川三月雨，晉水百花春。", "囹圄長空鎖，干戈久覆塵。", "儒僧觀子夜，羈客醉紅茵。", "筆硯行隨手，詩書坐繞身。", "小材多顧盼，得作食魚人。"]'),
('7a9e1e6f-4d38-4d21-aca4-89aa3f9dc492','浣紗廟','魚玄機','唐','唐诗','tang','','["\u957f\u6c5f"]','吳越相謀計策多，浣紗神女已相和。',64,'全唐诗/poet.tang.44000.json','["吳越相謀計策多，浣紗神女已相和。", "一雙笑靨纔回面，十萬精兵盡倒戈。", "范蠡功成身隱遯，伍胥諫死國消磨。", "只今諸暨長江畔，空有青山號苧蘿。"]'),
('2508eb4f-b21a-4021-b4cb-3a6b6faa4372','賣殘牡丹','魚玄機','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u82b1", "\u611f\u6168", "\u5199\u82b1"]','臨風興歎落花頻，芳意潛消又一春。',64,'全唐诗/poet.tang.44000.json','["臨風興歎落花頻，芳意潛消又一春。", "應爲價高人不問，却緣香甚蝶難親。", "紅英只稱生宮裏，翠葉那堪染路塵。", "及至移根上林苑，王孫方恨買無因。"]'),
('226575d5-5828-4faa-9b0d-d5f6feea4161','酬李學士寄簟','魚玄機','唐','唐诗','tang','','[]','珍簟新鋪翡翠樓，泓澄玉水記方流。',32,'全唐诗/poet.tang.44000.json','["珍簟新鋪翡翠樓，泓澄玉水記方流。", "唯應雲扇情相似，同向銀牀恨早秋。"]'),
('2bd21d2d-c98a-46ec-a1be-c48ca863ac4c','情書寄李子安','魚玄機','唐','唐诗','tang','','[]','飲冰食蘗志無功，晉水壺關在夢中。',64,'全唐诗/poet.tang.44000.json','["飲冰食蘗志無功，晉水壺關在夢中。", "秦鏡欲分愁墮鵲，舜琴將弄怨飛鴻。", "井邊桐葉鳴秋雨，窗下銀燈暗曉風。", "書信茫茫何處問，持竿盡日碧江空。"]'),
('73f36d4e-511e-48fe-8514-127db8b1a2aa','閨怨','魚玄機','唐','唐诗','tang','','[]','蘼蕪盈手泣斜暉，聞道鄰家夫壻歸。',64,'全唐诗/poet.tang.44000.json','["蘼蕪盈手泣斜暉，聞道鄰家夫壻歸。", "別日南鴻纔北去，今朝北鴈又南飛。", "春來秋去相思在，秋去春來信息稀。", "扃閉朱門人不到，砧聲何事透羅幃。"]'),
('c1ed9ddf-27e5-483e-9966-2c304f1c2fa3','春情寄子安','魚玄機','唐','唐诗','tang','','["\u6292\u60c5", "\u76f8\u601d"]','山路敧斜石磴危，不愁行苦苦相思。',96,'全唐诗/poet.tang.44000.json','["山路敧斜石磴危，不愁行苦苦相思。", "冰銷遠磵憐清韻，雪遠寒峰想玉姿。", "莫聽凡歌春病酒，休招閑客夜貪棊。", "如松匪石盟長在，比翼連襟會肯遲。", "雖恨獨行冬盡日，終期相見月圓時。", "別君何物堪持贈，淚落晴光一首詩。"]'),
('c6549f01-c55e-4bbf-8c98-54bdad1abacd','打毬作','魚玄機','唐','唐诗','tang','','[]','堅圓淨滑一星流，月杖爭敲未擬休。',64,'全唐诗/poet.tang.44000.json','["堅圓淨滑一星流，月杖爭敲未擬休。", "無滯礙時從撥弄，有遮欄處任鉤留。", "不辭宛轉長隨手，却恐相將不到頭。", "畢竟入門應始了，願君爭取最前籌。"]'),
('0c476b10-38e2-4ac9-8eb6-37d597c7027f','暮春有感寄友人','魚玄機','唐','唐诗','tang','','["\u6292\u60c5", "\u5b64\u5bc2", "\u5199\u666f"]','鶯語驚殘夢，輕妝改淚容。',48,'全唐诗/poet.tang.44000.json','["鶯語驚殘夢，輕妝改淚容。", "竹陰初月薄，江靜晚煙濃。", "溼觜銜泥燕，香鬚採蕊蜂。", "獨憐無限思，吟罷亞枝松。"]'),
('e101833b-5d56-435d-9f9f-5863c87e96c2','冬夜寄溫飛卿','魚玄機','唐','唐诗','tang','','["\u6000\u4eba", "\u601d\u5ff5", "\u4f24\u611f"]','苦思搜詩燈下吟，不眠長夜怕寒衾。',64,'全唐诗/poet.tang.44000.json','["苦思搜詩燈下吟，不眠長夜怕寒衾。", "滿庭木葉愁風起，透幌紗窗惜月沈。", "疎散未閑終遂願，盛衰空見本來心。", "幽棲莫定梧桐處，暮雀啾啾空繞林。"]'),
('89044e17-bb20-4403-ae27-8cce6c955a78','酬李郢夏日釣魚回見示','魚玄機','唐','唐诗','tang','','[]','住處雖同巷，經年不一過。',48,'全唐诗/poet.tang.44000.json','["住處雖同巷，經年不一過。", "清詞勸舊女，香桂折新柯。", "道性欺冰雪，禪心笑綺羅。", "跡登霄漢上，無路接煙波。"]'),
('f943da34-6491-4bc4-919a-415a8b841b91','次韻西鄰新居兼乞酒','魚玄機','唐','唐诗','tang','','[]','一首詩來百度吟，新情字字又聲金。',64,'全唐诗/poet.tang.44000.json','["一首詩來百度吟，新情字字又聲金。", "西看已有登垣意，遠望能無化石心。", "河漢期賒空極目，瀟湘夢斷罷調琴。", "況逢寒節添鄉思，叔夜佳醪莫獨斟。"]'),
('27bb7e56-9935-4171-83a5-7069c101bb47','和友人次韻','魚玄機','唐','唐诗','tang','','[]','何事能銷旅館愁，紅牋開處見銀鉤。',64,'全唐诗/poet.tang.44000.json','["何事能銷旅館愁，紅牋開處見銀鉤。", "蓬山雨灑千峰小，嶰谷風吹萬葉秋。", "字字朝看輕碧玉，篇篇夜誦在衾裯。", "欲將香匣收藏却，且惜時吟在手頭。"]'),
('82023a62-b0b0-4d67-bf07-4ea456ddaca6','和新及第悼亡詩二首 一','魚玄機','唐','唐诗','tang','','[]','仙籍人間不久留，片時已過十經秋。',64,'全唐诗/poet.tang.44000.json','["仙籍人間不久留，片時已過十經秋。", "鴛鴦帳下香猶暖，鸚鵡籠中語未休。", "朝露綴花如臉恨，晚風敧柳似眉愁。", "彩雲一去無消息，潘岳多情欲白頭。"]'),
('111e6d09-6699-449b-bb5b-38608630ab98','和新及第悼亡詩二首 二','魚玄機','唐','唐诗','tang','','[]','一枝月桂和煙秀，萬樹江桃帶雨紅。',32,'全唐诗/poet.tang.44000.json','["一枝月桂和煙秀，萬樹江桃帶雨紅。", "且醉尊前休悵望，古來悲樂與今同。"]'),
('178f9489-55b1-4ec4-8de6-ee3bdb0ea1e5','遊崇真觀南樓覩新及第題名處','魚玄機','唐','唐诗','tang','','[]','雲峰滿目放春晴，歷歷銀鉤指下生。',32,'全唐诗/poet.tang.44000.json','["雲峰滿目放春晴，歷歷銀鉤指下生。", "自恨羅衣掩詩句，舉頭空羨榜中名。"]'),
('c2cc72ba-d62c-48c2-ba5c-b21d0e342b10','愁思','魚玄機','唐','唐诗','tang','','[]','落葉紛紛暮雨和，朱絲獨撫自清歌。',64,'全唐诗/poet.tang.44000.json','["落葉紛紛暮雨和，朱絲獨撫自清歌。", "放情休恨無心友，養性空拋苦海波。", "長者車音門外有，道家書卷枕前多。", "布衣終作雲霄客，綠水青山時一過。"]'),
('d394769d-918d-43ea-96f4-a657356fbe3e','秋怨','魚玄機','唐','唐诗','tang','','[]','自歎多情是足愁，況當風月滿庭秋。',32,'全唐诗/poet.tang.44000.json','["自歎多情是足愁，況當風月滿庭秋。", "洞房偏與更聲近，夜夜燈前欲白頭。"]'),
('1c8cb1d0-293d-4cb7-a2ec-6bd9fcfeb1a5','江行 一','魚玄機','唐','唐诗','tang','','[]','大江橫抱武昌斜，鸚鵡洲前戶萬家。',32,'全唐诗/poet.tang.44000.json','["大江橫抱武昌斜，鸚鵡洲前戶萬家。", "畫舸春眠朝未足，夢爲蝴蝶也尋花。"]'),
('833614c6-a4f2-4d7f-bb90-6e15f5fb249b','江行 二','魚玄機','唐','唐诗','tang','','[]','煙花已入鸕鷀港，畫舸猶沿鸚鵡洲。',32,'全唐诗/poet.tang.44000.json','["煙花已入鸕鷀港，畫舸猶沿鸚鵡洲。", "醉臥醒吟都不覺，今朝驚在漢江頭。"]'),
('1bda9a76-7c2f-487c-b8ae-e49add76feb3','聞李端公垂釣回寄贈','魚玄機','唐','唐诗','tang','','["\u7231\u60c5", "\u6d6a\u6f2b"]','無限荷香染暑衣，阮郎何處弄船歸。',32,'全唐诗/poet.tang.44000.json','["無限荷香染暑衣，阮郎何處弄船歸。", "自慙不及鴛鴦侶，猶得雙雙近釣磯。"]'),
('56b64c2a-96b3-424d-96da-a0f08bdff52a','題任處士刱資福寺','魚玄機','唐','唐诗','tang','','[]','幽人刱奇境，遊客駐行程。',48,'全唐诗/poet.tang.44000.json','["幽人刱奇境，遊客駐行程。", "粉壁空留字，蓮宮未有名。", "鑿池泉自出，開徑草重生。", "百尺金輪閣，當川豁眼明。"]'),
('ff2b9581-24f6-4323-8a44-822132ad4660','題隱霧亭','魚玄機','唐','唐诗','tang','','[]','春花秋月入詩篇，白日清宵是散仙。',32,'全唐诗/poet.tang.44000.json','["春花秋月入詩篇，白日清宵是散仙。", "空捲珠簾不曾下，長移一榻對山眠。"]'),
('cf84d377-0e3d-4b16-9a28-0e5c632804c5','重陽阻雨','魚玄機','唐','唐诗','tang','','[]','滿庭黃菊籬邊拆，兩朵芙蓉鏡裏開。',32,'全唐诗/poet.tang.44000.json','["滿庭黃菊籬邊拆，兩朵芙蓉鏡裏開。", "落帽臺前風雨阻，不知何處醉金杯。"]'),
('37e227dd-a924-4b33-b9c4-f48e7bf7a173','早秋','魚玄機','唐','唐诗','tang','','[]','嫩菊含新彩，遠山閑夕煙。',48,'全唐诗/poet.tang.44000.json','["嫩菊含新彩，遠山閑夕煙。", "涼風驚綠樹，清韻入朱弦。", "思婦機中錦，征人塞外天。", "鴈飛魚在水，書信若爲傳。"]'),
('c13506de-d6e2-4ff3-a3da-722337baa3a3','感懷寄人','魚玄機','唐','唐诗','tang','','[]','恨寄朱弦上，含情意不任。',72,'全唐诗/poet.tang.44000.json','["恨寄朱弦上，含情意不任。", "早知雲雨會，未起蕙蘭心。", "灼灼桃兼李，無妨國士尋。", "蒼蒼松與桂，仍羨世人欽。", "月色苔階淨，歌聲竹院深。", "門前紅葉地，不埽待知音。"]'),
('4fc9f8d3-f9ea-4a13-8b33-eff4cf03c1bf','期友人阻雨不至','魚玄機','唐','唐诗','tang','','[]','鴈魚空有信，雞黍恨無期。',48,'全唐诗/poet.tang.44000.json','["鴈魚空有信，雞黍恨無期。", "閉戶方籠月，褰簾已散絲。", "近泉鳴砌畔，遠浪漲江湄。", "鄉思悲秋客，愁吟五字詩。"]'),
('3e83ef25-9fff-48b2-bf5c-4a5483235e5c','訪趙鍊師不遇','魚玄機','唐','唐诗','tang','','[]','何處同仙侶，青衣獨在家。',48,'全唐诗/poet.tang.44000.json','["何處同仙侶，青衣獨在家。", "暖爐留煮藥，鄰院爲煎茶。", "畫壁燈光暗，幡竿日影斜。", "殷勤重回首，牆外數枝花。"]'),
('ff4bae90-c446-4c04-9cf7-95172b439842','遣懷','魚玄機','唐','唐诗','tang','','[]','閑散身無事，風光獨自遊。',96,'全唐诗/poet.tang.44000.json','["閑散身無事，風光獨自遊。", "斷雲江上月，解纜海中舟。", "琴弄蕭梁寺，詩吟庾亮樓。", "叢篁堪作伴，片石好爲儔。", "燕雀徒爲貴，金銀志不求。", "滿杯春酒綠，對月夜窗幽。", "繞砌澄清沼，抽簪映細流。", "臥牀書冊徧，半醉起梳頭。"]'),
('e500339a-7ca1-421d-b666-d64ed98ae380','寄飛卿','魚玄機','唐','唐诗','tang','','[]','階砌亂蛩鳴，庭柯煙露清。',48,'全唐诗/poet.tang.44000.json','["階砌亂蛩鳴，庭柯煙露清。", "月中鄰樂響，樓上遠山明。", "珍簟涼風著，瑤琴寄恨生。", "嵇君嬾書札，底物慰秋情。"]'),
('741cdc44-6aa1-4d1a-97fa-12e7fbe27d88','過鄂州','魚玄機','唐','唐诗','tang','','[]','柳拂蘭橈花滿枝，石城城下暮帆遲。',64,'全唐诗/poet.tang.44000.json','["柳拂蘭橈花滿枝，石城城下暮帆遲。", "折牌峰上三閭墓，遠火山頭五馬旗。", "白雪調高題舊寺，陽春歌在喚新詞。", "莫愁魂逐清江去，空使行人萬首詩。"]'),
('9867cdce-b967-4b8f-a459-c7c2a28b2d5b','夏日山居','魚玄機','唐','唐诗','tang','','[]','移得仙居此地來，花叢自徧不曾栽。',64,'全唐诗/poet.tang.44000.json','["移得仙居此地來，花叢自徧不曾栽。", "庭前亞樹張衣桁，坐上新泉泛酒杯。", "軒檻暗傳深竹徑，綺羅長擁亂書堆。", "閑乘畫舫吟明月，信任輕風吹却回。"]'),
('4435e46e-be32-47fc-8347-03398e3c18e2','暮春即事','魚玄機','唐','唐诗','tang','','[]','深巷窮門少侶儔，阮郎唯有夢中留。',64,'全唐诗/poet.tang.44000.json','["深巷窮門少侶儔，阮郎唯有夢中留。", "香飄羅綺誰家席，風送歌聲何處樓。", "街近鼓鼙喧曉睡，庭閑鵲語亂春愁。", "安能追逐人間事，萬里身同不繫舟。"]'),
('3332b84d-4c70-43ad-8f84-da1f6e0c1ef2','代人悼亡','魚玄機','唐','唐诗','tang','','[]','曾覩夭桃想玉姿，帶風楊柳認蛾眉。',64,'全唐诗/poet.tang.44000.json','["曾覩夭桃想玉姿，帶風楊柳認蛾眉。", "珠歸龍窟知誰見，鏡在鸞臺話向誰。", "從此夢悲煙雨夜，不堪吟苦寂寥時。", "西山日落東山月，恨想無因有了期。"]'),
('15dcd0c4-52a0-42de-bdc6-931920f8a3a3','和人','魚玄機','唐','唐诗','tang','','[]','茫茫九陌無知己，暮去朝來典繡衣。',64,'全唐诗/poet.tang.44000.json','["茫茫九陌無知己，暮去朝來典繡衣。", "寶匣鏡昏蟬鬢亂，博山爐暖麝煙微。", "多情公子春留句，少思文君晝掩扉。", "莫惜羊車頻列載，柳絲梅綻正芳菲。"]'),
('e1fbe21d-629e-4638-8468-8f5a81467dda','隔漢江寄子安','魚玄機','唐','唐诗','tang','','["\u7231\u60c5", "\u76f8\u601d"]','江南江北愁望，相思相憶空吟。',56,'全唐诗/poet.tang.44000.json','["江南江北愁望，相思相憶空吟。", "鴛鴦暖臥沙浦，鸂𪆟閑飛橘林。", "煙裏歌聲隱隱，渡頭月色沈沈。", "含情咫尺千里，況聽家家遠砧。"]'),
('c4142639-29cf-4e88-b506-9e2eb10d0243','寓言','魚玄機','唐','唐诗','tang','','[]','紅桃處處春色，碧柳家家月明。',56,'全唐诗/poet.tang.44000.json','["紅桃處處春色，碧柳家家月明。", "樓上新妝待夜，閨中獨坐含情。", "芙蓉月下魚戲，螮蝀天邊雀聲。", "人世悲歡一夢，如何得作雙成。"]'),
('47fdc2ee-45e6-4f4c-a661-257589c5f739','江陵愁望寄子安','魚玄機','唐','唐诗','tang','','["\u957f\u6c5f", "\u601d\u5ff5", "\u5199\u666f"]','楓葉千枝復萬枝，江橋掩映暮帆遲。',32,'全唐诗/poet.tang.44000.json','["楓葉千枝復萬枝，江橋掩映暮帆遲。", "憶君心似西江水，日夜東流無歇時。"]'),
('253849e9-cfff-4a60-86a4-a01d3bc1c494','寄子安','魚玄機','唐','唐诗','tang','','[]','醉別千巵不浣愁，離腸百結解無由。',64,'全唐诗/poet.tang.44000.json','["醉別千巵不浣愁，離腸百結解無由。", "蕙蘭銷歇歸春圃，楊柳東西絆客舟。", "聚散已悲雲不定，恩情須學水長流。", "有花時節知難遇，未肯厭厭醉玉樓。"]'),
('f60aa9e3-5b13-4265-9116-59747cecf8e0','送別','魚玄機','唐','唐诗','tang','','[]','秦樓幾夜愜心期，不料仙郎有別離。',32,'全唐诗/poet.tang.44000.json','["秦樓幾夜愜心期，不料仙郎有別離。", "睡覺莫言雲去處，殘燈一醆野蛾飛。"]'),
('bcca1075-392a-4299-8a82-a750fcbaf4cd','迎李近仁員外','魚玄機','唐','唐诗','tang','','[]','今日喜時聞喜鵲，昨宵燈下拜燈花。',32,'全唐诗/poet.tang.44000.json','["今日喜時聞喜鵲，昨宵燈下拜燈花。", "焚香出戶迎潘岳，不羨牽牛織女家。"]'),
('962780a7-c4a0-4ce7-ab03-96b957f047a8','送別','魚玄機','唐','唐诗','tang','','[]','水柔逐器知難定，雲出無心肯再歸。',32,'全唐诗/poet.tang.44000.json','["水柔逐器知難定，雲出無心肯再歸。", "惆悵春風楚江暮，鴛鴦一隻失羣飛。"]'),
('5d8a209f-7b1c-4afb-a21d-3cff24520ef5','左名場自澤州至京使人傳語','魚玄機','唐','唐诗','tang','','[]','閑居作賦幾年愁，王屋山前是舊遊。',96,'全唐诗/poet.tang.44000.json','["閑居作賦幾年愁，王屋山前是舊遊。", "詩詠東西千嶂亂，馬隨南北一泉流。", "曾陪雨夜同歡席，別後花時獨上樓。", "忽喜扣門傳語至，爲憐鄰巷小房幽。", "相如琴罷朱弦斷，雙燕巢分白露秋。", "莫倦蓬門時一訪，每春忙在曲江頭。"]'),
('c986d783-80bd-450f-bd0c-4c53eed19735','和人次韻','魚玄機','唐','唐诗','tang','','[]','喧喧朱紫雜人寰，獨自清吟日色間。',64,'全唐诗/poet.tang.44000.json','["喧喧朱紫雜人寰，獨自清吟日色間。", "何事玉郎搜藻思，忽將瓊韻扣柴關。", "白花發詠慙稱謝，僻巷深居謬學顏。", "不用多情欲相見，松蘿高處是前山。"]'),
('601cb6a0-7e9c-40e9-861b-0621c997a632','光威裒姊妹三人少孤而始妍乃有是作精粹難儔雖謝家聯雪何以加之有客自京師來者示予因次其韻','魚玄機','唐','唐诗','tang','','[]','昔聞南國容華少，今日東鄰姊妹三。',192,'全唐诗/poet.tang.44000.json','["昔聞南國容華少，今日東鄰姊妹三。", "妝閣相看鸚鵡賦，碧窗應繡鳳凰衫。", "紅芳滿院參差折，綠醑盈杯次第銜。", "恐向瑤池曾作女，謫來塵世未爲男。", "文姬有貌終堪比，西子無言我更慚。", "一曲豔歌琴杳杳，四弦輕撥語喃喃。", "當臺競鬬青絲髮，對月爭誇白玉簪。", "小有洞中松露滴，大羅天上柳煙含。", "但能爲雨心長在，不怕吹簫事未諳。", "阿母幾嗔花下語，潘郎曾向夢中參。", "暫持清句魂猶斷，若覩紅顏死亦甘。", "悵望佳人何處在，行雲歸北又歸南。"]'),
('b8c5b8da-ee5a-4b1f-a669-8310c69530eb','折楊柳','魚玄機','唐','唐诗','tang','','[]','朝朝送別泣花鈿，折盡春風楊柳煙。',32,'全唐诗/poet.tang.44000.json','["朝朝送別泣花鈿，折盡春風楊柳煙。", "願得西山無樹木，免教人作淚懸懸。"]'),
('90f3b085-e508-4d80-8d47-b338daca575a','句','魚玄機','唐','唐诗','tang','','[]','焚香登玉壇，端簡禮金闕。',64,'全唐诗/poet.tang.44000.json','["焚香登玉壇，端簡禮金闕。", "明月照幽隙，清風開短襟。", "綺陌春望遠，瑤徽春興多。", "殷勤不得語，紅淚一雙流。", "雲情自鬱爭同夢，仙貌長芳又勝花。"]'),
('edf462ca-8b6f-4b86-9858-14b1c62cb7c1','湖上臥病喜陸鴻漸至','李冶','唐','唐诗','tang','','[]','昔去繁霜月，今來苦霧時。',48,'全唐诗/poet.tang.44000.json','["昔去繁霜月，今來苦霧時。", "相逢仍臥病，欲語淚先垂。", "強勸陶家酒，還吟謝客詩。", "偶然成一醉，此外更何之。"]'),
('2dcc8efe-4fc4-43f3-99bb-ea56e48ffffd','寄校書七兄','李冶','唐','唐诗','tang','','[]','無事烏程縣，蹉跎歲月餘。',48,'全唐诗/poet.tang.44000.json','["無事烏程縣，蹉跎歲月餘。", "不知芸閣吏，寂寞竟何如。", "遠水浮仙棹，寒星伴使車。", "因過大雷岸，莫忘八行書。"]'),
('7c071b26-32b2-40c7-8daa-b3a9de3a0d7a','寄朱放','李冶','唐','唐诗','tang','','[]','望水試登山，山高湖又闊。',48,'全唐诗/poet.tang.44000.json','["望水試登山，山高湖又闊。", "相思無曉夕，相望經年月。", "鬱鬱山木榮，綿綿野花發。", "別後無限情，相逢一時說。"]'),
('b4a37c2e-4bf7-47f4-a5b1-d05915432fbf','送韓揆之江西','李冶','唐','唐诗','tang','','[]','相看指楊柳，別恨轉依依。',48,'全唐诗/poet.tang.44000.json','["相看指楊柳，別恨轉依依。", "萬里江西水，孤舟何處歸？", "湓城潮不到，夏口信應稀。", "唯有衡陽雁，年年來去飛。"]'),
('aff9d01d-966b-4559-90bc-6fe22624c5d0','道意寄崔侍郎','李冶','唐','唐诗','tang','','[]','莫漫戀浮名，應須薄宦情。',48,'全唐诗/poet.tang.44000.json','["莫漫戀浮名，應須薄宦情。", "百年齊旦暮，前事盡虛盈。", "愁鬢行看白，童顏學未成。", "無過天竺國，依止古先生。"]'),
('956af6b8-a933-4286-9109-25357e8a8ce7','從蕭叔子聽彈琴賦得三峽流泉歌','李冶','唐','唐诗','tang','','[]','妾家本住巫山雲，巫山流泉常自聞。',128,'全唐诗/poet.tang.44000.json','["妾家本住巫山雲，巫山流泉常自聞。", "玉琴彈出轉寥敻，直是當時夢裏聽。", "三峽迢迢幾千里，一時流入幽閨裏。", "巨石崩崖指下生，飛泉走浪弦中起。", "初疑憤怒含雷風，又似嗚咽流不通。", "迴湍曲瀨勢將盡，時復滴瀝平沙中。", "憶昔阮公爲此曲，能令仲容聽不足。", "一彈既罷復一彈，願作流泉鎮相續。"]'),
('56311c63-5446-48bc-a3f6-5cefe7b6d87c','相思怨','李冶','唐','唐诗','tang','','[]','人道海水深，不抵相思半。',48,'全唐诗/poet.tang.44000.json','["人道海水深，不抵相思半。", "海水尚有涯，相思渺無畔。", "攜琴上高樓，樓虛月華滿。", "彈著相思曲，弦腸一時斷。"]'),
('851b229b-a506-41b7-94a5-6844f02941a1','感興','李冶','唐','唐诗','tang','','[]','朝雲暮雨鎮相隨，去雁來人有返期。',64,'全唐诗/poet.tang.44000.json','["朝雲暮雨鎮相隨，去雁來人有返期。", "玉枕秪知長下淚，銀燈空照不眠時。", "仰看明月翻含意，俯眄流波欲寄詞。", "却憶初聞鳳樓曲，教人寂寞復相思。"]'),
('bb77b561-cadd-4aca-acf4-bf56fd49a533','恩命追入留別廣陵故人','李冶','唐','唐诗','tang','','[]','無才多病分龍鍾，不料虛名達九重。',64,'全唐诗/poet.tang.44000.json','["無才多病分龍鍾，不料虛名達九重。", "仰媿彈冠上華髮，多慙拂鏡理衰容。", "馳心北闕隨芳草，極目南山望舊峰。", "桂樹不能留野客，沙鷗出浦謾相逢。"]'),
('05a09b49-ef3f-428d-ad40-82d739e810a2','八至','李冶','唐','唐诗','tang','','["\u54f2\u7406"]','至近至遠東西，至深至淺清溪。',28,'全唐诗/poet.tang.44000.json','["至近至遠東西，至深至淺清溪。", "至高至明日月，至親至疎夫妻。"]'),
('fe1fef2a-a07b-44c0-a7a7-86d1dd3b53a2','送閻二十六赴剡縣','李冶','唐','唐诗','tang','','[]','流水閶門外，孤舟日復西。',48,'全唐诗/poet.tang.44000.json','["流水閶門外，孤舟日復西。", "離情遍芳草，無處不萋萋。", "妾夢經吳苑，君行到剡溪。", "歸來重相訪，莫學阮郎迷。"]'),
('bf797a72-c763-4fc1-a2da-da2d1f3c0867','得閻伯鈞書','李冶','唐','唐诗','tang','','[]','情來對鏡嬾梳頭，暮雨蕭蕭庭樹秋。',32,'全唐诗/poet.tang.44000.json','["情來對鏡嬾梳頭，暮雨蕭蕭庭樹秋。", "莫怪闌干垂玉筯，只緣惆悵對銀鉤。"]'),
('8711b7ec-9746-44d6-a00e-cd8b1736d363','結素魚貽友人','李冶','唐','唐诗','tang','','[]','尺素如殘雪，結爲雙鯉魚。',24,'全唐诗/poet.tang.44000.json','["尺素如殘雪，結爲雙鯉魚。", "欲知心裏事，看取腹中書。"]'),
('6a6d75ed-f854-4448-aaf7-b77d85729ad3','偶居','李冶','唐','唐诗','tang','','[]','心遠浮雲知不還，心雲併在有無間。',32,'全唐诗/poet.tang.44000.json','["心遠浮雲知不還，心雲併在有無間。", "狂風何事相搖蕩，吹向南山復北山。"]'),
('b30662ff-1491-4933-80f9-f871b20ac43b','明月夜留別','李冶','唐','唐诗','tang','','[]','離人無語月無聲，明月有光人有情。',32,'全唐诗/poet.tang.44000.json','["離人無語月無聲，明月有光人有情。", "別後相思人似月，雲間水上到層城。"]'),
('a856728f-cb8f-4bc0-8068-6ac77d5bc446','春閨怨','李冶','唐','唐诗','tang','','[]','百尺井欄上，數株桃已紅。',24,'全唐诗/poet.tang.44000.json','["百尺井欄上，數株桃已紅。", "念君遼海北，拋妾宋家東。"]'),
('c41e4b44-0abe-4f82-b6c1-c09c4ddbc40f','句','李冶','唐','唐诗','tang','','[]','經時未架却，心緒亂縱橫。',52,'全唐诗/poet.tang.44000.json','["經時未架却，心緒亂縱橫。", "已看雲鬢散，更念木枯榮。", "鞞鼓喧行選，旌旗拂座隅。", "不覩河陽一縣花，空見青山三兩點。"]'),
('6fafff7d-d7cc-4fe0-a717-0bf8797d82e7','寄洛中諸姊','元淳','唐','唐诗','tang','','[]','舊國經年別，關河萬里思。',48,'全唐诗/poet.tang.44000.json','["舊國經年別，關河萬里思。", "題詩憑鴈翼，望月想蛾眉。", "白髮愁偏覺，歸心夢獨知。", "誰堪離亂處，掩淚向南枝。"]'),
('0d67b649-5b23-449c-93fe-56c4ad006a51','秦中春望','元淳','唐','唐诗','tang','','[]','鳳樓春望好，宮闕一重重。',48,'全唐诗/poet.tang.44000.json','["鳳樓春望好，宮闕一重重。", "上苑雨中樹，終南霽後峰。", "落花行處徧，佳氣晚來濃。", "喜見休明代，霓裳躡道蹤。"]'),
('6c7b7e59-440b-4241-8c20-96c1b4050832','句','元淳','唐','唐诗','tang','','[]','弟兄俱已盡，松柏問何人。',60,'全唐诗/poet.tang.44000.json','["弟兄俱已盡，松柏問何人。", "聞道茂陵山水好，碧溪流水有桃源。", "赤城峭壁無人到，丹竈芝田有鶴來。", "三千宮女露蛾眉，笑煮黃金日月遲。"]'),
('bb794bf1-a1ec-4ac3-991f-cbd58e73a860','舟夜一章','海印','唐','唐诗','tang','','[]','水色連天色，風聲益浪聲。',48,'全唐诗/poet.tang.44000.json','["水色連天色，風聲益浪聲。", "旅人歸思苦，漁叟夢魂驚。", "舉棹雲先到，移舟月逐行。", "旋吟詩句罷，猶見遠山橫。"]'),
('3f7b2589-310f-4075-8ed5-9085bcdfd429','詩三百三首 一','寒山','唐','唐诗','tang','','[]','凡讀我詩者，心中須護淨。',48,'全唐诗/poet.tang.44000.json','["凡讀我詩者，心中須護淨。", "慳貪繼日廉，諂曲登時正。", "驅遣除惡業，歸依受真性。", "今日得佛身，急急如律令。"]'),
('09db3190-bd2b-4ee6-9172-5aa3224adcdd','詩三百三首 二','寒山','唐','唐诗','tang','','[]','重巖我卜居，鳥道絕人迹。',48,'全唐诗/poet.tang.44000.json','["重巖我卜居，鳥道絕人迹。", "庭際何所有，白雲抱幽石。", "住茲凡幾年，屢見春冬易。", "寄語鍾鼎家，虛名定無益。"]'),
('4af0dd7e-f73d-45ea-94f9-f166719e4818','詩三百三首 三','寒山','唐','唐诗','tang','','[]','可笑寒山道，而無車馬蹤。',48,'全唐诗/poet.tang.44000.json','["可笑寒山道，而無車馬蹤。", "聯谿難記曲，疊嶂不知重。", "泣露千般草，吟風一樣松。", "此時迷徑處，形問影何從。"]'),
('46216b9e-0443-45b7-9e14-fd4990d06def','詩三百三首 四','寒山','唐','唐诗','tang','','[]','吾家好隱淪，居處絕囂塵。',48,'全唐诗/poet.tang.44000.json','["吾家好隱淪，居處絕囂塵。", "踐草成三徑，瞻雲作四鄰。", "助歌聲有鳥，問法語無人。", "今日娑婆樹，幾年爲一春。"]'),
('982b7b73-b460-495f-a3b2-dba8f60cd222','詩三百三首 五','寒山','唐','唐诗','tang','','[]','琴書須自隨，祿位用何爲。',48,'全唐诗/poet.tang.44000.json','["琴書須自隨，祿位用何爲。", "投輦從賢婦，巾車有孝兒。", "風吹曝麥地，水溢沃魚池。", "常念鷦鷯鳥，安身在一枝。"]'),
('fb8ac120-2981-48d3-b84b-b883fda5bd36','詩三百三首 六','寒山','唐','唐诗','tang','','[]','弟兄同五郡，父子本三州。',48,'全唐诗/poet.tang.44000.json','["弟兄同五郡，父子本三州。", "欲驗飛鳧集，須徵白兔遊。", "靈瓜夢裏受，神橘座中收。", "鄉國何迢遰，同魚寄水流。"]'),
('c09918c7-e839-44bc-800a-0b2bcc437334','詩三百三首 七','寒山','唐','唐诗','tang','','[]','一爲書劒客，二遇聖明君。',48,'全唐诗/poet.tang.44000.json','["一爲書劒客，二遇聖明君。", "東守文不賞，西征武不勳。", "學文兼學武，學武兼學文。", "今日既老矣，餘生不足云。"]'),
('ac39eafa-fde9-4fdf-8a19-effb1e32117f','詩三百三首 八','寒山','唐','唐诗','tang','','[]','莊子說送終，天地爲棺槨。',48,'全唐诗/poet.tang.44000.json','["莊子說送終，天地爲棺槨。", "吾歸此有時，唯須一番箔。", "死將餧青蠅，弔不勞白鶴。", "餓著首陽山，生廉死亦樂。"]'),
('1593b477-c934-4f38-9024-98b33e779963','詩三百三首 九','寒山','唐','唐诗','tang','','[]','人問寒山道，寒山路不通。',48,'全唐诗/poet.tang.44000.json','["人問寒山道，寒山路不通。", "夏天冰未釋，日出霧朦朧。", "似我何由屆，與君心不同。", "君心若似我，還得到其中。"]'),
('538c8971-1e0e-416d-b3d2-242224bb64e2','詩三百三首 十','寒山','唐','唐诗','tang','','[]','天生百尺樹，翦作長條木。',48,'全唐诗/poet.tang.44000.json','["天生百尺樹，翦作長條木。", "可惜棟梁材，拋之在幽谷。", "年多心尚勁，日久皮漸禿。", "識者取將來，猶堪柱馬屋。"]'),
('b1d5eda2-7d74-481e-aee5-f64090796d3e','詩三百三首 十一','寒山','唐','唐诗','tang','','[]','驅馬度荒城，荒城動客情。',48,'全唐诗/poet.tang.44000.json','["驅馬度荒城，荒城動客情。", "高低舊雉堞，大小古墳塋。", "自振孤蓬影，長凝拱木聲。", "所嗟皆俗骨，仙史更無名。"]'),
('dcbb69f8-485e-4a9c-90bb-4232a1e64b11','詩三百三首 十二','寒山','唐','唐诗','tang','','[]','鸚鵡宅西國，虞羅捕得歸。',48,'全唐诗/poet.tang.44000.json','["鸚鵡宅西國，虞羅捕得歸。", "美人朝夕弄，出入在庭幃。", "賜以金籠貯，扃哉損羽衣。", "不如鴻與鶴，颻颺入雲飛。"]'),
('b7c80de1-c4ac-4a4e-99ff-ae255ed6184d','詩三百三首 十三','寒山','唐','唐诗','tang','','[]','玉堂挂珠簾，中有嬋娟子。',48,'全唐诗/poet.tang.44000.json','["玉堂挂珠簾，中有嬋娟子。", "其貌勝神仙，容華若桃李。", "東家春霧合，西舍秋風起。", "更過三十年，還成苷蔗滓。"]'),
('7cc74af5-81a0-4061-9548-a3966071e112','詩三百三首 十四','寒山','唐','唐诗','tang','','[]','城中娥眉女，珠珮珂珊珊。',48,'全唐诗/poet.tang.44000.json','["城中娥眉女，珠珮珂珊珊。", "鸚鵡花前弄，琵琶月下彈。", "長歌三月響，短舞萬人看。", "未必長如此，芙蓉不耐寒。"]'),
('a52de482-fc61-4f54-8d44-5f5e95ed6386','詩三百三首 十五','寒山','唐','唐诗','tang','','[]','父母續經多，田園不羨他。',48,'全唐诗/poet.tang.44000.json','["父母續經多，田園不羨他。", "婦搖機軋軋，兒弄口㗻㗻。", "拍手摧花舞，搘頤聽鳥歌。", "誰當來歎賞，樵客屢經過。"]'),
('9c8e1593-c9f7-46b6-8a15-32345bfc8ee3','詩三百三首 十六','寒山','唐','唐诗','tang','','[]','家住綠巖下，庭蕪更不芟。',48,'全唐诗/poet.tang.44000.json','["家住綠巖下，庭蕪更不芟。", "新藤垂繚繞，古石豎巉巖。", "山果獼猴摘，池魚白鷺銜。", "仙書一兩卷，樹下讀喃喃。"]'),
('2cc43289-e575-4ef8-ad61-90e2871f0823','詩三百三首 十七','寒山','唐','唐诗','tang','','[]','四時無止息，年去又年來。',48,'全唐诗/poet.tang.44000.json','["四時無止息，年去又年來。", "萬物有代謝，九天無朽摧。", "東明又西暗，花落復花開。", "唯有黃泉客，冥冥去不迴。"]'),
('cb3a2f92-1667-4015-8568-3f8963d8cf43','詩三百三首 十八','寒山','唐','唐诗','tang','','[]','歲去換愁年，春來物色鮮。',48,'全唐诗/poet.tang.44000.json','["歲去換愁年，春來物色鮮。", "山花笑淥水，巖岫舞青煙。", "蜂蝶自云樂，禽魚更可憐。", "朋遊情未已，徹曉不能眠。"]'),
('26937dab-720c-412f-9a0d-337e5d96f938','詩三百三首 十九','寒山','唐','唐诗','tang','','[]','手筆太縱橫，身材極環瑋。',48,'全唐诗/poet.tang.44000.json','["手筆太縱橫，身材極環瑋。", "生爲有限身，死作無名鬼。", "自古如此多，君今爭奈何。", "可來白雲裏，教爾紫芝歌。"]'),
('6c091e30-b7df-4833-a1e9-003310a193c8','詩三百三首 二十','寒山','唐','唐诗','tang','','[]','欲得安身處，寒山可長保。',48,'全唐诗/poet.tang.44000.json','["欲得安身處，寒山可長保。", "微風吹幽松，近聽聲逾好。", "下有斑白人，喃喃讀黃老。", "十年歸不得，忘却來時道。"]'),
('8530482c-c1a0-4ac4-848f-8b239f359f73','詩三百三首 二十一','寒山','唐','唐诗','tang','','[]','俊傑馬上郎，揮鞭指綠楊。',48,'全唐诗/poet.tang.44000.json','["俊傑馬上郎，揮鞭指綠楊。", "謂言無死日，終不作梯航。", "四運花自好，一朝成萎黃。", "醍醐與石蜜，至死不能嘗。"]'),
('c8440e54-b940-4053-a82d-e8fb1aca9d6a','詩三百三首 二十二','寒山','唐','唐诗','tang','','[]','有一餐霞子，其居諱俗遊。',48,'全唐诗/poet.tang.44000.json','["有一餐霞子，其居諱俗遊。", "論時實蕭爽，在夏亦如秋。", "幽澗常瀝瀝，高松風颼颼。", "其中半日坐，忘却百年愁。"]'),
('9f8e2020-0585-439d-b29d-d9e101fc7084','詩三百三首 二十三','寒山','唐','唐诗','tang','','[]','妾在邯鄲住，歌聲亦抑揚。',48,'全唐诗/poet.tang.44000.json','["妾在邯鄲住，歌聲亦抑揚。", "賴我安居處，此曲舊來長。", "既醉莫言歸，留連日未央。", "兒家寢宿處，繡被滿銀牀。"]'),
('b76d24ac-6a7d-4c79-8b36-ec4c6ccb2416','詩三百三首 二十四','寒山','唐','唐诗','tang','','[]','快搒三翼舟，善乘千里馬。',48,'全唐诗/poet.tang.44000.json','["快搒三翼舟，善乘千里馬。", "莫能造我家，謂言最幽野。", "巖岫深嶂中，雲雷竟日下。", "自非孔丘公，無能相救者。"]'),
('1d1ed63a-b2e4-495c-aa3c-484d3a98e0b5','詩三百三首 二十五','寒山','唐','唐诗','tang','','[]','智者君拋我，愚者我拋君。',48,'全唐诗/poet.tang.44000.json','["智者君拋我，愚者我拋君。", "非愚亦非智，從此斷相聞。", "入夜歌明月，侵晨舞白雲。", "焉能拱口手，端坐鬢紛紛。"]'),
('7c2b9ad6-1c7b-4909-bd79-3515a1d2f069','詩三百三首 二十六','寒山','唐','唐诗','tang','','[]','有鳥五色彣，棲桐食竹實。',48,'全唐诗/poet.tang.44000.json','["有鳥五色彣，棲桐食竹實。", "徐動合禮儀，和鳴中音律。", "昨來何以至，爲吾暫時出。", "儻聞弦歌聲，作舞欣今日。"]'),
('3c339144-18fc-4968-89ea-5e70bde8683d','詩三百三首 二十七','寒山','唐','唐诗','tang','','[]','茅棟野人居，門前車馬疎。',48,'全唐诗/poet.tang.44000.json','["茅棟野人居，門前車馬疎。", "林幽偏聚鳥，谿闊本藏魚。", "山果攜兒摘，臯田共婦鋤。", "家中何所有，唯有一牀書。"]'),
('a15b83f7-2778-4c71-a401-0ea17d124324','詩三百三首 二十八','寒山','唐','唐诗','tang','','[]','登陟寒山道，寒山路不窮。',48,'全唐诗/poet.tang.44000.json','["登陟寒山道，寒山路不窮。", "谿長石磊磊，澗闊草濛濛。", "苔滑非關雨，松鳴不假風。", "誰能超世累，共坐白雲中。"]'),
('1becc41d-d700-4c4a-ad00-8aeb5d660dee','詩三百三首 二十九','寒山','唐','唐诗','tang','','[]','六極常嬰困，九維徒自論。',48,'全唐诗/poet.tang.44000.json','["六極常嬰困，九維徒自論。", "有才遺草澤，無藝閉蓬門。", "日上巖猶暗，煙消谷尚昏。", "其中長者子，箇箇總無裩。"]'),
('f323b758-894e-47fb-9b87-ef5d475f9f69','詩三百三首 三十','寒山','唐','唐诗','tang','','[]','白雲高嵯峨，淥水蕩潭波。',48,'全唐诗/poet.tang.44000.json','["白雲高嵯峨，淥水蕩潭波。", "此處聞漁父，時時鼓棹歌。", "聲聲不可聽，令我愁思多。", "誰謂雀無角，其如穿屋何。"]'),
('33ea7df7-8496-4e59-b329-8233b14ffe10','詩三百三首 三十一','寒山','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','杳杳寒山道，落落冷澗濱。',48,'全唐诗/poet.tang.44000.json','["杳杳寒山道，落落冷澗濱。", "啾啾常有鳥，寂寂更無人。", "磧磧風吹面，紛紛雪積身。", "朝朝不見日，歲歲不知春。"]'),
('99791624-33ea-4f82-a470-3d22dae35b67','詩三百三首 三十二','寒山','唐','唐诗','tang','','[]','少年何所愁，愁見鬢毛白。',48,'全唐诗/poet.tang.44000.json','["少年何所愁，愁見鬢毛白。", "白更何所愁，愁見日逼迫。", "移向東岱居，配守北邙宅。", "何忍出此言，此言傷老客。"]'),
('346ad958-32e4-491c-a5c5-b6dc6780d4fc','詩三百三首 三十三','寒山','唐','唐诗','tang','','[]','聞道愁難遣，斯言謂不真。',48,'全唐诗/poet.tang.44000.json','["聞道愁難遣，斯言謂不真。", "昨朝曾趂却，今日又纏身。", "月盡愁難盡，年新愁更新。", "誰知席帽下，元是昔愁人。"]'),
('fadc8e0f-0947-4c9b-87f9-fecbb174dd14','詩三百三首 三十四','寒山','唐','唐诗','tang','','[]','兩龜乘犢車，驀出路頭戲。',48,'全唐诗/poet.tang.44000.json','["兩龜乘犢車，驀出路頭戲。", "一蠱從傍來，苦死欲求寄。", "不載爽人情，始載被沈累。", "彈指不可論，行恩却遭刺。"]'),
('6c1990b6-bec4-4e87-9114-198902767c4a','詩三百三首 三十五','寒山','唐','唐诗','tang','','[]','三月蠶猶小，女人來采花。',48,'全唐诗/poet.tang.44000.json','["三月蠶猶小，女人來采花。", "隈牆弄蝴蝶，臨水擲蝦𢋙。", "羅袖盛梅子，金鎞挑筍芽。", "鬬論多物色，此地勝余家。"]'),
('611202c6-173d-4fc9-8cb9-43b4c07106ae','詩三百三首 三十六','寒山','唐','唐诗','tang','','[]','東家一老婆，富來三五年。',48,'全唐诗/poet.tang.44000.json','["東家一老婆，富來三五年。", "昔日貧於我，今笑我無錢。", "渠笑我在後，我笑渠在前。", "相笑儻不止，東邊復西邊。"]'),
('bc022418-23fc-43e2-b2a3-a8dcf69ba456','詩三百三首 三十七','寒山','唐','唐诗','tang','','[]','富兒多鞅掌，觸事難祇承。',48,'全唐诗/poet.tang.44000.json','["富兒多鞅掌，觸事難祇承。", "倉米已赫赤，不貸人斗升。", "轉懷鉤距意，買絹先揀綾。", "若至臨終日，弔客有蒼蠅。"]'),
('7d192e30-8ec8-46eb-b369-f21f2d08e66b','詩三百三首 三十八','寒山','唐','唐诗','tang','','[]','余曾昔覩聰明士，博達英靈無比倫。',64,'全唐诗/poet.tang.44000.json','["余曾昔覩聰明士，博達英靈無比倫。", "一選嘉名喧宇宙，五言詩句越諸人。", "爲官治化超先輩，直爲無能繼後塵。", "忍然富貴貪財色，瓦解冰消不可陳。"]'),
('b928c814-6966-467f-907c-fc068517ded0','詩三百三首 三十九','寒山','唐','唐诗','tang','','[]','白鶴銜苦桃，千里作一息。',48,'全唐诗/poet.tang.44000.json','["白鶴銜苦桃，千里作一息。", "欲往蓬萊山，將此充糧食。", "未達毛摧落，離羣心慘惻。", "却歸舊來巢，妻子不相識。"]'),
('0811670e-25fe-49dc-8cbf-14dcc10819eb','詩三百三首 四十','寒山','唐','唐诗','tang','','[]','慣居幽隱處，乍向國清中。',48,'全唐诗/poet.tang.44000.json','["慣居幽隱處，乍向國清中。", "時訪豐干道，仍來看拾公。", "獨迴上寒巖，無人話合同。", "尋究無源水，源窮水不窮。"]'),
('1119583b-6e60-43d0-8f55-fccc615259a2','詩三百三首 四十一','寒山','唐','唐诗','tang','','[]','生前大愚癡，不爲今日悟。',48,'全唐诗/poet.tang.44000.json','["生前大愚癡，不爲今日悟。", "今日如許貧，總是前生作。", "今生又不修，來生還如故。", "兩岸各無船，渺渺難濟渡。"]'),
('2068371c-8a2b-4f28-a381-995055d72398','詩三百三首 四十二','寒山','唐','唐诗','tang','','[]','璨璨盧家女，舊來名莫愁。',48,'全唐诗/poet.tang.44000.json','["璨璨盧家女，舊來名莫愁。", "貪乘摘花馬，樂搒采蓮舟。", "膝坐綠熊席，身披青鳳裘。", "哀傷百年內，不免歸山丘。"]'),
('6476e4a1-e339-46d4-bdf1-c2ae99e76ea8','詩三百三首 四十三','寒山','唐','唐诗','tang','','[]','低眼鄒公妻，邯鄲杜生母。',48,'全唐诗/poet.tang.44000.json','["低眼鄒公妻，邯鄲杜生母。", "二人同老少，一種好面首。", "昨日會客場，惡衣排在後。", "只爲著破裙，喫他殘䴺𪍣。"]'),
('d15bbf81-c8f8-46e1-9ee6-900eef8d0bb5','詩三百三首 四十四','寒山','唐','唐诗','tang','','[]','獨臥重巖下，蒸雲晝不消。',48,'全唐诗/poet.tang.44000.json','["獨臥重巖下，蒸雲晝不消。", "室中雖暡靉，心裏絕喧囂。", "夢去遊金闕，魂歸度石橋。", "拋除鬧我者，歷歷樹間瓢。"]'),
('be5b633a-2355-48a8-9e83-87bf5603f84b','詩三百三首 四十五','寒山','唐','唐诗','tang','','[]','夫物有所用，用之各有宜。',48,'全唐诗/poet.tang.44000.json','["夫物有所用，用之各有宜。", "用之若失所，一缺復一虧。", "圓鑿而方枘，悲哉空爾爲。", "驊騮將捕鼠，不及跛猫兒。"]'),
('8f7bd356-374d-4d86-a6c0-1c20301cf47f','詩三百三首 四十六','寒山','唐','唐诗','tang','','[]','誰家長不死，死事舊來均。',48,'全唐诗/poet.tang.44000.json','["誰家長不死，死事舊來均。", "始憶八尺漢，俄成一聚塵。", "黃泉無曉日，青草有時春。", "行到傷心處，松風愁殺人。"]'),
('911905d1-9c98-45e9-86eb-1180c9631d18','詩三百三首 四十七','寒山','唐','唐诗','tang','','[]','騮馬珊瑚鞭，驅馳洛陽道。',48,'全唐诗/poet.tang.44000.json','["騮馬珊瑚鞭，驅馳洛陽道。", "自矜美少年，不信有衰老。", "白髮會應生，紅顏豈長保。", "但看北邙山，箇是蓬萊島。"]'),
('6ee68a5a-e3b9-4310-952e-6958eaa56396','詩三百三首 四十八','寒山','唐','唐诗','tang','','[]','竟日常如醉，流年不暫停。',48,'全唐诗/poet.tang.44000.json','["竟日常如醉，流年不暫停。", "埋著蓬蒿下，曉月何冥冥。", "骨肉消散盡，魂魄幾凋零。", "遮莫齩鐵口，無因讀老經。"]'),
('ca158369-c545-4091-b92a-d8d059ae0a7b','詩三百三首 四十九','寒山','唐','唐诗','tang','','[]','一向寒山坐，淹留三十年。',48,'全唐诗/poet.tang.44000.json','["一向寒山坐，淹留三十年。", "昨來訪親友，太半入黃泉。", "漸減如殘燭，長流似逝川。", "今朝對孤影，不覺淚雙懸。"]'),
('33aad07b-e13a-4eb2-87bb-55061a2aadcb','詩三百三首 五十','寒山','唐','唐诗','tang','','[]','相喚採芙蓉，可憐清江裏。',48,'全唐诗/poet.tang.44000.json','["相喚採芙蓉，可憐清江裏。", "遊戲不覺暮，屢見狂風起。", "浪捧鴛鴦兒，波搖鸂鶒子。", "此時居舟楫，浩蕩情無已。"]'),
('fe76e29c-c7c5-495a-aecc-a66924a41046','詩三百三首 五十一','寒山','唐','唐诗','tang','','[]','吾心似秋月，碧潭清皎潔。',24,'全唐诗/poet.tang.44000.json','["吾心似秋月，碧潭清皎潔。", "無物堪比倫，教我如何說。"]'),
('eccb61bc-15b6-4ef8-b45f-f9eb302668c7','詩三百三首 五十二','寒山','唐','唐诗','tang','','[]','垂柳暗如煙，飛花飄似霰。',48,'全唐诗/poet.tang.44000.json','["垂柳暗如煙，飛花飄似霰。", "夫居離婦州，婦住思夫縣。", "各在天一涯，何時得相見？", "寄語明月樓，莫貯雙飛燕。"]'),
('f9072441-da51-4774-a06f-3466a3157dca','詩三百三首 五十三','寒山','唐','唐诗','tang','','[]','有酒相招飲，有肉相呼喫。',48,'全唐诗/poet.tang.44000.json','["有酒相招飲，有肉相呼喫。", "黃泉前後人，少壯須努力。", "玉帶暫時華，金釵非久飾。", "張翁與鄭婆，一去無消息。"]'),
('f4555ed9-13b5-4fc0-a67c-9a1fac88bd62','詩三百三首 五十四','寒山','唐','唐诗','tang','','[]','可憐好丈夫，身體極稜稜。',48,'全唐诗/poet.tang.44000.json','["可憐好丈夫，身體極稜稜。", "春秋未三十，才藝百般能。", "金羈逐俠客，玉饌集良朋。", "唯有一般惡，不傳無盡燈。"]'),
('c8e96122-7e34-4273-bba3-ff560edd5a2d','詩三百三首 五十五','寒山','唐','唐诗','tang','','[]','桃花欲經夏，風月催不待。',48,'全唐诗/poet.tang.44000.json','["桃花欲經夏，風月催不待。", "訪覓漢時人，能無一箇在。", "朝朝花遷落，歲歲人移改。", "今日揚塵處，昔時爲大海。"]'),
('124d6329-4473-413c-ba33-2f66f6d09add','詩三百三首 五十六','寒山','唐','唐诗','tang','','[]','我見東家女，年可有十八。',48,'全唐诗/poet.tang.44000.json','["我見東家女，年可有十八。", "西舍競來問，願姻夫妻活。", "烹羊煮衆命，聚頭作婬殺。", "含笑樂呵呵，啼哭受殃抉。"]'),
('ac5d248b-7395-4410-8ee5-2fca45f776ab','詩三百三首 五十七','寒山','唐','唐诗','tang','','[]','田舍多桑園，牛犢滿廐轍。',48,'全唐诗/poet.tang.44000.json','["田舍多桑園，牛犢滿廐轍。", "肯信有因果，頑皮早晚裂。", "眼看消磨盡，當頭各自活。", "紙袴瓦作裩，到頭凍餓殺。"]'),
('a0de3690-b77e-454e-b01f-cd9ca228ec40','詩三百三首 五十八','寒山','唐','唐诗','tang','','[]','我見百十狗，箇箇毛鬇鬡。',48,'全唐诗/poet.tang.44000.json','["我見百十狗，箇箇毛鬇鬡。", "臥者渠自臥，行者渠自行。", "投之一塊骨，相與啀喍爭。", "良由爲骨少，狗多分不平。"]'),
('f025ed30-0459-45aa-b3c4-7f35d27387e8','詩三百三首 五十九','寒山','唐','唐诗','tang','','[]','極目兮長望，白雲四茫茫。',48,'全唐诗/poet.tang.44000.json','["極目兮長望，白雲四茫茫。", "鴟鵶飽腲腇，鸞鳳飢徬徨。", "駿馬放石磧，蹇驢能至堂。", "天高不可問，鷦鵊在滄浪。"]'),
('8f835f5a-9a57-4a54-90ce-428f1e0c3c32','詩三百三首 六十','寒山','唐','唐诗','tang','','[]','洛陽多女兒，春日逞華麗。',48,'全唐诗/poet.tang.44000.json','["洛陽多女兒，春日逞華麗。", "共折路邊花，各持插高髻。", "髻高花匼匝，人見皆睥睨。", "別求醦醦憐，將歸見夫壻。"]'),
('3fe62d4b-19b4-425f-a292-9cebc02d47c8','詩三百三首 六十一','寒山','唐','唐诗','tang','','[]','春女衒容儀，相將南陌陲。',48,'全唐诗/poet.tang.44000.json','["春女衒容儀，相將南陌陲。", "看花愁日晚，隱樹怕風吹。", "年少徒傍來，白馬黃金羈。", "何須久相弄，兒家夫壻知。"]'),
('8062c758-e477-47b0-961e-1c5630c30f18','詩三百三首 六十二','寒山','唐','唐诗','tang','','[]','羣女戲夕陽，風來滿路香。',48,'全唐诗/poet.tang.44000.json','["羣女戲夕陽，風來滿路香。", "綴裙金蛺蝶，插髻玉鴛鴦。", "角婢紅羅縝，閹奴紫錦裳。", "爲觀失道者，鬢白心惶惶。"]'),
('461bb2e5-bcac-4e3f-a1da-dee1f6775068','詩三百三首 六十三','寒山','唐','唐诗','tang','','[]','若人逢鬼魅，第一莫驚懅。',48,'全唐诗/poet.tang.44000.json','["若人逢鬼魅，第一莫驚懅。", "捺硬莫采渠，呼名自當去。", "燒香請佛力，禮拜求僧助。", "蚊子叮鐵牛，無渠下觜處。"]'),
('bb9ddbfd-e61f-4889-9cb2-bdeddd099649','詩三百三首 六十四','寒山','唐','唐诗','tang','','["\u9ec4\u6cb3"]','浩浩黃河水，東流長不息。',48,'全唐诗/poet.tang.44000.json','["浩浩黃河水，東流長不息。", "悠悠不見清，人人壽有極。", "苟欲乘白雲，曷由生羽翼。", "唯當鬒髮時，行住須努力。"]'),
('f63665af-0020-4407-b158-3bdc5d708499','詩三百三首 六十五','寒山','唐','唐诗','tang','','[]','乘茲朽木船，采彼紝婆子。',48,'全唐诗/poet.tang.44000.json','["乘茲朽木船，采彼紝婆子。", "行至大海中，波濤復不止。", "唯賫一宿糧，去岸三千里。", "煩惱從何生，愁哉緣苦起。"]'),
('aad9d882-fa41-4c5a-90f3-802545790d7c','詩三百三首 六十六','寒山','唐','唐诗','tang','','[]','默默永無言，後生何所述。',48,'全唐诗/poet.tang.44000.json','["默默永無言，後生何所述。", "隱居在林藪，智日何由出。", "枯槁非堅衛，風霜成夭疾。", "土牛耕石田，未有得稻日。"]'),
('81800dd9-2f0e-474c-8bcf-0c218cd3425b','詩三百三首 六十七','寒山','唐','唐诗','tang','','[]','山中何太冷，自古非今年。',48,'全唐诗/poet.tang.44000.json','["山中何太冷，自古非今年。", "沓嶂恆凝雪，幽林每吐煙。", "草生芒種後，葉落立秋前。", "此有沈迷客，窺窺不見天。"]'),
('4ed8b61f-bf4e-4946-8c44-60d5eb92a2a8','詩三百三首 六十八','寒山','唐','唐诗','tang','','[]','山客心悄悄，常嗟歲序遷。',48,'全唐诗/poet.tang.44000.json','["山客心悄悄，常嗟歲序遷。", "辛勤采芝朮，搜斥詎成仙。", "庭廓雲初卷，林明月正圓。", "不歸何所爲，桂樹相留連。"]'),
('1c555bc5-5bca-45a2-8071-98e1c4ea5b06','詩三百三首 六十九','寒山','唐','唐诗','tang','','[]','有人兮山楹，雲卷兮霞纓。',50,'全唐诗/poet.tang.44000.json','["有人兮山楹，雲卷兮霞纓。", "秉芳兮欲寄，路漫漫兮難征。", "心惆悵兮狐疑，年老已無成。", "衆喔咿斯，蹇獨立兮忠貞。"]'),
('fbc2c9f1-d0a5-4cde-a839-7234b71ea3e8','詩三百三首 七十','寒山','唐','唐诗','tang','','[]','豬喫死人肉，人喫死豬腸。',48,'全唐诗/poet.tang.44000.json','["豬喫死人肉，人喫死豬腸。", "豬不嫌人臭，人反道豬香。", "豬死拋水內，人死掘土藏。", "彼此莫相噉，蓮花生沸湯。"]'),
('d0b1b932-68ed-4c6d-9db5-33830065ab2c','詩三百三首 七十一','寒山','唐','唐诗','tang','','[]','快哉混沌身，不飯復不尿。',48,'全唐诗/poet.tang.44000.json','["快哉混沌身，不飯復不尿。", "遭得誰鑽鑿，因茲立九竅。", "朝朝爲衣食，歲歲愁租調。", "千箇爭一錢，聚頭亡命叫。"]'),
('b6f50052-e0dd-4da2-8d79-33598a367926','詩三百三首 七十二','寒山','唐','唐诗','tang','','[]','啼哭緣何事，淚如珠子顆。',48,'全唐诗/poet.tang.44000.json','["啼哭緣何事，淚如珠子顆。", "應當有別離，復是遭喪禍。", "所爲在貧窮，未能了因果。", "塚間瞻死屍，六道不干我。"]'),
('b0e2bf38-95f1-4867-8a0e-a962214c8462','詩三百三首 七十三','寒山','唐','唐诗','tang','','[]','婦女慵經織，男夫嬾耨田。',48,'全唐诗/poet.tang.44000.json','["婦女慵經織，男夫嬾耨田。", "輕浮耽挾彈，跕躧拈抹弦。", "凍骨衣應急，充腸食在先。", "今誰念於汝，苦痛哭蒼天。"]'),
('8e90372e-5d11-461a-a561-63e93b2857d5','詩三百三首 七十四','寒山','唐','唐诗','tang','','[]','不行真正道，隨邪號行婆。',48,'全唐诗/poet.tang.44000.json','["不行真正道，隨邪號行婆。", "口慙神佛少，心懷嫉妒多。", "背後噇魚肉，人前念佛陀。", "如此修身處，難應避奈何。"]'),
('2ec62262-c89c-48a8-89fc-d80eb1201cfb','詩三百三首 七十五','寒山','唐','唐诗','tang','','[]','世有一等愚，茫茫恰似驢。',48,'全唐诗/poet.tang.44000.json','["世有一等愚，茫茫恰似驢。", "還解人言語，貪婬狀若豬。", "險巇難可測，實語却成虛。", "誰能共伊語，令教莫此居。"]'),
('953805e5-ac10-49c1-8cc4-c02acea44c8c','詩三百三首 七十六','寒山','唐','唐诗','tang','','[]','有漢姓慠慢，名貪字不廉。',48,'全唐诗/poet.tang.44000.json','["有漢姓慠慢，名貪字不廉。", "一身無所解，百事被他嫌。", "死惡黃連苦，生憐白蜜甜。", "喫魚猶未止，食肉更無厭。"]'),
('54a61bc9-334e-48d9-8fc4-cb5535b59b8a','詩三百三首 七十七','寒山','唐','唐诗','tang','','[]','縱你居犀角，饒君帶虎睛。',48,'全唐诗/poet.tang.44000.json','["縱你居犀角，饒君帶虎睛。", "桃枝將辟穢，蒜殼取爲瓔。", "暖腹茱萸酒，空心枸杞羹。", "終歸不免死，浪自覓長生。"]'),
('87c43e3e-c499-4609-a4ac-c9f50786b8e3','詩三百三首 七十八','寒山','唐','唐诗','tang','','[]','卜擇幽居地，天台更莫言。',48,'全唐诗/poet.tang.44000.json','["卜擇幽居地，天台更莫言。", "猨啼谿霧冷，嶽色草門連。", "折葉覆松室，開池引澗泉。", "已甘休萬事，采蕨度殘年。"]'),
('baa17c9c-3f75-4b49-ba89-42e539ab99b5','詩三百三首 七十九','寒山','唐','唐诗','tang','','[]','益者益其精，可名爲有益。',48,'全唐诗/poet.tang.44000.json','["益者益其精，可名爲有益。", "易者易其形，是名之有易。", "能益復能易，當得上仙籍。", "無益復無易，終不免死厄。"]'),
('071e5afc-3077-4df4-b25b-b70d3e1777ad','詩三百三首 八十','寒山','唐','唐诗','tang','','[]','徒勞說三史，浪自看五經。',48,'全唐诗/poet.tang.44000.json','["徒勞說三史，浪自看五經。", "洎老檢黃籍，依前住白丁。", "筮遭連蹇卦，生主虛危星。", "不及河邊樹，年年一度青。"]'),
('6e44958a-2ace-4527-ac61-549b52731954','詩三百三首 八十一','寒山','唐','唐诗','tang','','[]','碧澗泉水清，寒山月華白。',24,'全唐诗/poet.tang.44000.json','["碧澗泉水清，寒山月華白。", "默知神自明，觀空境逾寂。"]'),
('fc2a482e-10a8-4766-8c14-bd1d6904b9a0','詩三百三首 八十二','寒山','唐','唐诗','tang','','[]','我今有一襦，非羅復非綺。',48,'全唐诗/poet.tang.44000.json','["我今有一襦，非羅復非綺。", "借問作何色，不紅亦不紫。", "夏天將作衫，冬天將作被。", "冬夏遞互用，長年只這是。"]'),
('4e952e6a-279c-4758-8356-61762ce838e2','詩三百三首 八十三','寒山','唐','唐诗','tang','','[]','白拂栴檀柄，馨香竟日聞。',48,'全唐诗/poet.tang.44000.json','["白拂栴檀柄，馨香竟日聞。", "柔和如卷霧，搖拽似行雲。", "禮奉宜當暑，高提復去塵。", "時時方丈內，將用指迷人。"]'),
('99a951cb-90ab-4e2a-bb82-90c18fbce596','詩三百三首 八十四','寒山','唐','唐诗','tang','','[]','貪愛有人求快活，不知禍在百年身。',64,'全唐诗/poet.tang.44000.json','["貪愛有人求快活，不知禍在百年身。", "但看陽燄浮漚水，便覺無常敗壞人。", "丈夫志氣直如鐵，無曲心中道自真。", "行密節高霜下竹，方知不枉用心神。"]'),
('5cfaaca2-d493-45f9-9af5-4e783140ab42','詩三百三首 八十五','寒山','唐','唐诗','tang','','[]','多少般數人，百計求名利。',84,'全唐诗/poet.tang.44000.json','["多少般數人，百計求名利。", "心貪覓榮華，經營圖富貴。", "心未片時歇，奔突如煙氣。", "家眷實團圓，一呼百諾至。", "不過七十年，冰消瓦解置。", "死了萬事休，誰人承後嗣。", "水浸泥彈丸，方知無意智。"]'),
('26dd6f17-3b2a-4301-b84a-d98c0e23e352','詩三百三首 八十六','寒山','唐','唐诗','tang','','[]','貪人好聚財，恰如梟愛子。',48,'全唐诗/poet.tang.44000.json','["貪人好聚財，恰如梟愛子。", "子大而食母，財多還害己。", "散之即福生，聚之即禍起。", "無財亦無禍，鼓翼青雲裏。"]'),
('de7f75a9-7d2d-45d9-a3c1-4b23af2324ff','詩三百三首 八十七','寒山','唐','唐诗','tang','','[]','去家一萬里，提劒擊匈奴。',48,'全唐诗/poet.tang.44000.json','["去家一萬里，提劒擊匈奴。", "得利渠即死，失利汝即殂。", "渠命既不惜，汝命亦何辜。", "教汝百勝術，不貪爲上謨。"]'),
('35661fb2-59ad-482c-b524-ea712e68da74','詩三百三首 八十八','寒山','唐','唐诗','tang','','[]','瞋是心中火，能燒功德林。',24,'全唐诗/poet.tang.44000.json','["瞋是心中火，能燒功德林。", "欲行菩薩道，忍辱護真心。"]'),
('204bdb0f-6fa1-4a8d-b13d-5b811369f26f','詩三百三首 八十九','寒山','唐','唐诗','tang','','[]','汝爲埋頭癡兀兀，愛向無明羅剎窟。',64,'全唐诗/poet.tang.44000.json','["汝爲埋頭癡兀兀，愛向無明羅剎窟。", "再三勸你早修行，是你頑癡心恍惚。", "不肯信受寒山語，轉轉倍加業汩汩。", "直待斬首作兩段，方知自身奴賊物。"]'),
('d671d9a6-0b1a-4282-85a4-a394c1305b8e','詩三百三首 九十','寒山','唐','唐诗','tang','','[]','惡趣甚茫茫，冥冥無日光。',48,'全唐诗/poet.tang.44000.json','["惡趣甚茫茫，冥冥無日光。", "人間八百歲，未抵半宵長。", "此等諸癡子，論情甚可傷。", "勸君求出離，認取法中王。"]'),
('74148e53-bd8c-48f7-aaa2-165d1a7640e5','詩三百三首 九十一','寒山','唐','唐诗','tang','','[]','世有多解人，愚癡徒苦辛。',48,'全唐诗/poet.tang.44000.json','["世有多解人，愚癡徒苦辛。", "不求當來善，唯知造惡因。", "五逆十惡輩，三毒以爲親。", "一死入地獄，長如鎮庫銀。"]'),
('4ec4c6f3-eb9b-4fd1-a473-dc6e4407ab3a','詩三百三首 九十二','寒山','唐','唐诗','tang','','[]','天高高不窮，地厚厚無極。',48,'全唐诗/poet.tang.44000.json','["天高高不窮，地厚厚無極。", "動物在其中，憑茲造化力。", "爭頭覓飽暖，作計相噉食。", "因果都未詳，盲兒問乳色。"]'),
('3db8e3e2-039e-428b-9417-34cd45d96a42','詩三百三首 九十三','寒山','唐','唐诗','tang','','[]','天下幾種人，論時色數有。',48,'全唐诗/poet.tang.44000.json','["天下幾種人，論時色數有。", "賈婆如許夫，黃老元無婦。", "衛氏兒可憐，鐘家女極醜。", "渠若向西行，我便東邊走。"]'),
('d012133b-b43e-4473-b23d-46f8652debe3','詩三百三首 九十四','寒山','唐','唐诗','tang','','[]','賢士不貪婪，癡人好鑪冶。',48,'全唐诗/poet.tang.44000.json','["賢士不貪婪，癡人好鑪冶。", "麥地占他家，竹園皆我者。", "努膊覓錢財，切齒驅奴馬。", "須看郭門外，壘壘松栢下。"]'),
('5452e44b-7125-4121-954f-8302c8873699','詩三百三首 九十五','寒山','唐','唐诗','tang','','[]','嗊嗊買魚肉，擔歸餧妻子。',48,'全唐诗/poet.tang.44000.json','["嗊嗊買魚肉，擔歸餧妻子。", "何須殺他命，將來活汝己。", "此非天堂緣，純是地獄滓。", "徐六語破堆，始知沒道理。"]'),
('171d9b97-1a69-4f75-8e7c-113deb24ae9a','詩三百三首 九十六','寒山','唐','唐诗','tang','','[]','有人把椿樹，喚作白栴檀。',48,'全唐诗/poet.tang.44000.json','["有人把椿樹，喚作白栴檀。", "學道多沙數，幾箇得泥丸。", "棄金却擔草，謾他亦自謾。", "似聚砂一處，成團也大難。"]'),
('1e42feac-3dc3-49ab-9445-654067aa13f5','詩三百三首 九十七','寒山','唐','唐诗','tang','','[]','蒸砂擬作飯，臨渴始掘井。',48,'全唐诗/poet.tang.44000.json','["蒸砂擬作飯，臨渴始掘井。", "用力磨碌磚，那堪將作鏡。", "佛說元平等，總有真如性。", "但自審思量，不用閑爭競。"]'),
('83c8d652-c3f4-4a76-82a1-2ee73a3ee74d','詩三百三首 九十八','寒山','唐','唐诗','tang','','[]','推尋世間事，子細總皆知。',60,'全唐诗/poet.tang.44000.json','["推尋世間事，子細總皆知。", "凡事莫容易，盡愛討便宜。", "護即弊成好，毀即是成非。", "故知雜濫口，背面總由伊。", "冷暖我自量，不信奴脣皮。"]'),
('4782f46c-1167-4482-af9a-80286f502c8f','詩三百三首 九十九','寒山','唐','唐诗','tang','','[]','蹭蹬諸貧士，飢寒成至極。',51,'全唐诗/poet.tang.44000.json','["蹭蹬諸貧士，飢寒成至極。", "閑居好作詩，札札用心力。", "賤他言孰采，勸君休歎息。", "題安餬{麥幷}上，乞狗也不喫。"]'),
('00945457-4606-427a-be1b-6af889d83d8e','詩三百三首 一百','寒山','唐','唐诗','tang','','[]','欲識生死譬，且將冰水比。',48,'全唐诗/poet.tang.44000.json','["欲識生死譬，且將冰水比。", "水結即成冰，冰消返成水。", "已死必應生，出生還復死。", "冰水不相傷，生死還雙美。"]'),
('b3c24f3d-03eb-47e8-8e47-3864bedc91e8','詩三百三首 一百一','寒山','唐','唐诗','tang','','[]','尋思少年日，遊獵向平陵。',48,'全唐诗/poet.tang.44000.json','["尋思少年日，遊獵向平陵。", "國使職非願，神仙未足稱。", "聯翩騎白馬，喝兔放蒼鷹。", "不覺大流落，皤皤誰見矜。"]'),
('efc4e43c-c637-48db-a4db-9dc26c19b034','詩三百三首 一百二','寒山','唐','唐诗','tang','','[]','偃息深林下，從生是農夫。',48,'全唐诗/poet.tang.44000.json','["偃息深林下，從生是農夫。", "立身既質直，出語無諂諛。", "保我不鑒璧，信君方得珠。", "焉能同泛灩，極目波上鳧。"]'),
('5ac596b0-b5db-4878-9f41-97e2f5dd3578','詩三百三首 一百三','寒山','唐','唐诗','tang','','[]','不須攻人惡，何用伐己善。',48,'全唐诗/poet.tang.44000.json','["不須攻人惡，何用伐己善。", "行之則可行，卷之則可卷。", "祿厚憂積大，言深慮交淺。", "聞茲若念茲，小子當自見。"]'),
('41b509a7-fe4b-4a81-bf07-ff306f9f1662','詩三百三首 一百四','寒山','唐','唐诗','tang','','[]','富兒會高堂，華燈何煒煌。',48,'全唐诗/poet.tang.44000.json','["富兒會高堂，華燈何煒煌。", "此時無燭者，心願處其傍。", "不意遭排遣，還歸暗處藏。", "益人明詎損，頓訝惜餘光。"]'),
('1618dcd5-7c50-4e45-8c0c-9cb8ecbf5ccc','詩三百三首 一百五','寒山','唐','唐诗','tang','','[]','世有聰明士，勤苦探幽文。',48,'全唐诗/poet.tang.44000.json','["世有聰明士，勤苦探幽文。", "三端自孤立，六藝越諸君。", "神氣卓然異，精彩超衆羣。", "不識箇中意，逐境亂紛紛。"]'),
('683e5b2a-d809-4750-bb94-cd54365fabcd','詩三百三首 一百六','寒山','唐','唐诗','tang','','[]','層層山水秀，煙霞鎖翠微。',48,'全唐诗/poet.tang.44000.json','["層層山水秀，煙霞鎖翠微。", "嵐拂紗巾濕，露霑蓑草衣。", "足躡遊方履，手執古藤枝。", "更觀塵世外，夢境復何爲。"]'),
('b422b60d-ae38-4681-a4fe-ce22ac693110','詩三百三首 一百七','寒山','唐','唐诗','tang','','[]','滿卷才子詩，溢壺聖人酒。',48,'全唐诗/poet.tang.44000.json','["滿卷才子詩，溢壺聖人酒。", "行愛觀牛犢，坐不離左右。", "霜露入茅簷，月華明甕牖。", "此時吸兩甌，吟詩五百首。"]'),
('b280be78-5308-4a31-9cac-b798126a93f4','詩三百三首 一百八','寒山','唐','唐诗','tang','','[]','施家有兩兒，以藝干齊楚。',48,'全唐诗/poet.tang.44000.json','["施家有兩兒，以藝干齊楚。", "文武各自備，託身爲得所。", "孟公問其術，我子親教汝。", "秦衛兩不成，失時成齟齬。"]'),
('ed48ec3f-0814-400f-8e06-3dbebe5d664b','詩三百三首 一百九','寒山','唐','唐诗','tang','','[]','止宿鴛鴦鳥，一雄兼一雌。',48,'全唐诗/poet.tang.44000.json','["止宿鴛鴦鳥，一雄兼一雌。", "銜花相共食，刷羽每相隨。", "戲入煙霄裏，宿歸沙岸湄。", "自憐生處樂，不奪鳳皇池。"]'),
('3dd94cd6-1c36-4324-b38b-f370e6d4e66c','詩三百三首 一百一十','寒山','唐','唐诗','tang','','[]','或有衒行人，才藝過周孔。',48,'全唐诗/poet.tang.44000.json','["或有衒行人，才藝過周孔。", "見罷頭兀兀，看時身侗侗。", "繩牽未肯行，錐刺猶不動。", "恰似羊公鶴，可憐生氃氋。"]'),
('1a98770e-adf5-4781-9ce9-c9df33df17f4','詩三百三首 一一一','寒山','唐','唐诗','tang','','[]','少小帶經鋤，本將兄共居。',48,'全唐诗/poet.tang.44000.json','["少小帶經鋤，本將兄共居。", "緣遭他輩責，剩被自妻疎。", "拋絕紅塵境，常遊好閱書。", "誰能借斗水，活取轍中魚。"]'),
('f4ecc2ab-e112-4e8d-8ebf-0ec00804ff82','詩三百三首 一一二','寒山','唐','唐诗','tang','','[]','變化計無窮，生死竟不止。',48,'全唐诗/poet.tang.44000.json','["變化計無窮，生死竟不止。", "三途鳥雀身，五嶽龍魚已。", "世濁作𦎔羺，時清爲騄駬。", "前迴是富兒，今度成貧士。"]'),
('3f9e03ac-af78-4f4c-86bd-20daa0e1f4b8','詩三百三首 一一三','寒山','唐','唐诗','tang','','[]','書判全非弱，嫌身不得官。',48,'全唐诗/poet.tang.44000.json','["書判全非弱，嫌身不得官。", "銓曹被拗折，洗垢覓瘡瘢。", "必也關天命，今冬更試看。", "盲兒射雀目，偶中亦非難。"]'),
('ba1e5f33-0a08-4737-b426-c3ce6650904e','詩三百三首 一一四','寒山','唐','唐诗','tang','','[]','貧驢欠一尺，富狗剩三寸。',48,'全唐诗/poet.tang.44000.json','["貧驢欠一尺，富狗剩三寸。", "若分貧不平，中半富與困。", "始取驢飽足，却令狗飢頓。", "爲汝熟思量，令我也愁悶。"]'),
('148737bd-4a03-450a-b3af-1b9af9e59ff3','詩三百三首 一一五','寒山','唐','唐诗','tang','','[]','柳郎八十二，藍嫂一十八。',48,'全唐诗/poet.tang.44000.json','["柳郎八十二，藍嫂一十八。", "夫妻共百年，相憐情狡猾。", "弄璋字烏䖘，擲瓦名婠妠。", "屢見枯楊荑，常遭青女殺。"]'),
('daf4d957-05e0-433d-ba92-6350586ed4d4','詩三百三首 一一六','寒山','唐','唐诗','tang','','[]','大有飢寒客，生將獸魚殊。',48,'全唐诗/poet.tang.44000.json','["大有飢寒客，生將獸魚殊。", "長存磨石下，時哭路邊隅。", "累日空思飯，經冬不識襦。", "唯齎一束草，幷帶五升麩。"]'),
('cd13e9e2-eb50-404c-bf49-25895121e679','詩三百三首 一一七','寒山','唐','唐诗','tang','','[]','赫赫誰𤮧肆，其酒甚濃厚。',48,'全唐诗/poet.tang.44000.json','["赫赫誰𤮧肆，其酒甚濃厚。", "可憐高幡幟，極目平升斗。", "何意訝不售，其家多猛狗。", "童子欲來沽，狗齩便是走。"]'),
('c874d0f0-2433-4e20-b670-cfc49297cdc3','詩三百三首 一一八','寒山','唐','唐诗','tang','','[]','吁嗟濁濫處，羅剎共賢人。',48,'全唐诗/poet.tang.44000.json','["吁嗟濁濫處，羅剎共賢人。", "謂是等流類，焉知道不親。", "狐假師子勢，詐妄却稱珍。", "鉛礦入鑪冶，方知金不知。"]'),
('b0f81363-833c-48ab-b133-af9f0181fef4','詩三百三首 一一九','寒山','唐','唐诗','tang','','[]','田家避暑月，斗酒共誰歡。',48,'全唐诗/poet.tang.44000.json','["田家避暑月，斗酒共誰歡。", "雜雜排山果，疎疎圍酒罇。", "蘆莦將代席，蕉葉且充盤。", "醉後搘頤坐，須彌小彈丸。"]'),
('8cc20706-80b9-4bef-8b73-9634fc9fd972','詩三百三首 一百二十','寒山','唐','唐诗','tang','','[]','箇是何措大，時來省南院。',48,'全唐诗/poet.tang.44000.json','["箇是何措大，時來省南院。", "年可三十餘，曾經四五選。", "囊裏無青蚨，篋中有黃絹。", "行到食店前，不敢暫迴面。"]'),
('1b69daf4-dead-43a1-8140-636540117a46','詩三百三首 一二一','寒山','唐','唐诗','tang','','[]','爲人常喫用，愛意須慳惜。',48,'全唐诗/poet.tang.44000.json','["爲人常喫用，愛意須慳惜。", "老去不自由，漸被他推斥。", "送向荒山頭，一生願虛擲。", "亡羊罷補牢，失意終無極。"]'),
('1fcf8e29-1fad-4710-a667-d6e1563181a2','詩三百三首 一二二','寒山','唐','唐诗','tang','','[]','浪造凌霄閣，虛登百尺樓。',48,'全唐诗/poet.tang.44000.json','["浪造凌霄閣，虛登百尺樓。", "養生仍夭命，誘讀詎封侯。", "不用從黃口，何須厭白頭。", "未能端似箭，且莫曲如鉤。"]'),
('bc703a21-bba8-4e98-ba0a-ba884de37a81','詩三百三首 一二三','寒山','唐','唐诗','tang','','[]','雲山疊疊連天碧，路僻林深無客遊。',64,'全唐诗/poet.tang.44000.json','["雲山疊疊連天碧，路僻林深無客遊。", "遠望孤蟾明皎皎，近聞羣鳥語啾啾。", "老夫獨坐棲青嶂，少室閑居任白頭。", "可歎往年與今日，無心還似水東流。"]'),
('80cff0ac-7cbf-40ec-b67e-9b230b3d635e','詩三百三首 一二四','寒山','唐','唐诗','tang','','[]','富貴疎親聚，只爲多錢米。',48,'全唐诗/poet.tang.44000.json','["富貴疎親聚，只爲多錢米。", "貧賤骨肉離，非關少兄弟。", "急須歸去來，招賢閣未啓。", "浪行朱雀街，踏破皮鞋底。"]'),
('3cec929d-88f7-4907-93b3-2dcfa3c0ba79','詩三百三首 一二五','寒山','唐','唐诗','tang','','[]','我見一癡漢，仍居三兩婦。',48,'全唐诗/poet.tang.44000.json','["我見一癡漢，仍居三兩婦。", "養得八九兒，總是隨宜手。", "丁防是新差，資財非舊有。", "黃蘖作驢鞦，始知苦在後。"]'),
('d4cae778-cfce-4787-ab73-1a7323db4860','詩三百三首 一二六','寒山','唐','唐诗','tang','','[]','新穀尚未熟，舊穀今已無。',48,'全唐诗/poet.tang.44000.json','["新穀尚未熟，舊穀今已無。", "就貸一斗許，門外立踟躕。", "夫出教問婦，婦出遣問夫。", "慳惜不救乏，財多爲累愚。"]'),
('cb478b39-8ba7-4732-8182-af3f122ba32f','詩三百三首 一二七','寒山','唐','唐诗','tang','','[]','大有好笑事，畧陳三五箇。',48,'全唐诗/poet.tang.44000.json','["大有好笑事，畧陳三五箇。", "張公富奢華，孟子貧轗軻。", "只取侏儒飽，不憐方朔餓。", "巴歌唱者多，白雪無人和。"]'),
('1f324252-fade-4634-abc1-e0dbb7a507e3','詩三百三首 一二八','寒山','唐','唐诗','tang','','[]','老翁娶少婦，髮白婦不耐。',48,'全唐诗/poet.tang.44000.json','["老翁娶少婦，髮白婦不耐。", "老婆嫁少夫，面黃夫不愛。", "老翁娶老婆，一一無棄背。", "少婦嫁少夫，兩兩相憐態。"]'),
('357ba0cf-312b-475c-bfe5-ba8ee9539360','詩三百三首 一二九','寒山','唐','唐诗','tang','','[]','雍容美少年，博覽諸經史。',48,'全唐诗/poet.tang.44000.json','["雍容美少年，博覽諸經史。", "盡號曰先生，皆稱爲學士。", "未能得官職，不解秉耒耜。", "冬披破布衫，蓋是書誤己。"]'),
('37c44716-7e92-423a-94c8-58ceaa7b30e2','詩三百三首 一三○','寒山','唐','唐诗','tang','','[]','鳥語情不堪，其時臥草菴。',48,'全唐诗/poet.tang.44000.json','["鳥語情不堪，其時臥草菴。", "櫻桃紅爍爍，楊柳正毿毿。", "旭日銜青嶂，晴雲洗淥潭。", "誰知出塵俗，馭上寒山南。"]'),
('bf91ed12-db3d-40fe-bc9d-ec264dd0d097','詩三百三首 一三一','寒山','唐','唐诗','tang','','[]','昨日何悠悠，場中可憐許。',48,'全唐诗/poet.tang.44000.json','["昨日何悠悠，場中可憐許。", "上爲桃李徑，下作蘭蓀渚。", "復有綺羅人，舍中翠毛羽。", "相逢欲相喚，脈脈不能語。"]'),
('01240f01-978c-409d-aec0-572e34a6e872','詩三百三首 一三二','寒山','唐','唐诗','tang','','[]','丈夫莫守困，無錢須經紀。',48,'全唐诗/poet.tang.44000.json','["丈夫莫守困，無錢須經紀。", "養得一牸牛，生得五犢子。", "犢子又生兒，積數無窮已。", "寄語陶朱公，富與君相似。"]'),
('1a3e45c4-f886-4c3c-a08c-8fbdaeda917b','詩三百三首 一三三','寒山','唐','唐诗','tang','','[]','之字何惶惶，卜居須自審。',48,'全唐诗/poet.tang.44000.json','["之字何惶惶，卜居須自審。", "南方瘴癘多，北地風霜甚。", "荒陬不可居，毒川難可飲。", "魂兮歸去來，食我家園葚。"]'),
('92194ad5-b8b3-45d5-a569-4305ba687d63','詩三百三首 一三四','寒山','唐','唐诗','tang','','[]','昨夜夢還家，見婦機中織。',48,'全唐诗/poet.tang.44000.json','["昨夜夢還家，見婦機中織。", "駐梭如有思，擎梭似無力。", "呼之迴面視，況復不相識。", "應是別多年，鬢毛非舊色。"]'),
('e4a10879-0640-4c60-b606-95d31af1118a','詩三百三首 一三五','寒山','唐','唐诗','tang','','[]','人生不滿百，常懷千載憂。',48,'全唐诗/poet.tang.44000.json','["人生不滿百，常懷千載憂。", "自身病始可，又爲子孫愁。", "下視禾根土，上看桑樹頭。", "秤鎚落東海，到底始知休。"]'),
('e163fb15-195d-4e80-a07e-d7d189897df0','詩三百三首 一三六','寒山','唐','唐诗','tang','','[]','世有一等流，悠悠似木頭。',48,'全唐诗/poet.tang.44000.json','["世有一等流，悠悠似木頭。", "出語無知解，云我百不憂。", "問道道不會，問佛佛不求。", "子細推尋著，茫然一場愁。"]'),
('cb43ee21-be42-4afe-961c-ebe440f945e0','詩三百三首 一三七','寒山','唐','唐诗','tang','','[]','董郎年少時，出入帝京裏。',48,'全唐诗/poet.tang.44000.json','["董郎年少時，出入帝京裏。", "衫作嫩鵝黃，容儀畫相似。", "常騎踏雪馬，拂拂紅塵起。", "觀者滿路傍，箇是誰家子。"]'),
('4cef1bfd-82d7-441f-b55f-d81b50034ff3','詩三百三首 一三八','寒山','唐','唐诗','tang','','[]','箇是誰家子，爲人大被憎。',48,'全唐诗/poet.tang.44000.json','["箇是誰家子，爲人大被憎。", "癡心常憤憤，肉眼醉瞢瞢。", "見佛不禮佛，逢僧不施僧。", "唯知打大臠，除此百無能。"]'),
('65cc1249-2fa1-459a-b2c9-38813b108df5','詩三百三首 一三九','寒山','唐','唐诗','tang','','[]','人以身爲本，本以心爲柄。',48,'全唐诗/poet.tang.44000.json','["人以身爲本，本以心爲柄。", "本在心莫邪，心邪喪本命。", "未能免此殃，何言嬾照鏡。", "不念金剛經，却令菩薩病。"]'),
('f1df98c2-11ec-4cee-9bba-ca11a587e4f7','詩三百三首 一百四十','寒山','唐','唐诗','tang','','[]','城北仲家翁，渠家多酒肉。',48,'全唐诗/poet.tang.44000.json','["城北仲家翁，渠家多酒肉。", "仲翁婦死時，弔客滿堂屋。", "仲翁自身亡，能無一人哭。", "喫他桮臠者，何太冷心腹。"]'),
('14717c81-6fef-48fa-9068-9a47b0bcb527','詩三百三首 一四一','寒山','唐','唐诗','tang','','[]','下愚讀我詩，不解却嗤誚。',48,'全唐诗/poet.tang.44000.json','["下愚讀我詩，不解却嗤誚。", "中庸讀我詩，思量云甚要。", "上賢讀我詩，把著滿面笑。", "楊修見幼婦，一覽便知妙。"]'),
('a630e407-55e6-4abd-857d-1e285cf3a5c9','詩三百三首 一四二','寒山','唐','唐诗','tang','','[]','自有慳惜人，我非慳惜輩。',48,'全唐诗/poet.tang.44000.json','["自有慳惜人，我非慳惜輩。", "衣單爲舞穿，酒盡緣歌啐。", "當取一腹飽，莫令兩脚儽。", "蓬蒿鑽髑髏，此日君應悔。"]'),
('e175af1f-d771-4a9a-8f4e-35c1aee728b8','詩三百三首 一四三','寒山','唐','唐诗','tang','','[]','我行經古墳，淚盡嗟存沒。',48,'全唐诗/poet.tang.44000.json','["我行經古墳，淚盡嗟存沒。", "塚破壓黃腸，棺穿露白骨。", "欹斜有甕缾，掁撥無簪笏。", "風至攬其中，灰塵亂𡋯𡋯。"]'),
('a28b3106-f605-4056-b7e6-e89468372bc6','詩三百三首 一四四','寒山','唐','唐诗','tang','','[]','夕陽赫西山，草木光曄曄。',48,'全唐诗/poet.tang.44000.json','["夕陽赫西山，草木光曄曄。", "復有朦朧處，松蘿相連接。", "此中多伏虎，見我奮迅鬣。", "手中無寸刃，爭不懼懾懾。"]'),
('d43d57e1-94bb-4b47-ae48-7bd031101b76','詩三百三首 一四五','寒山','唐','唐诗','tang','','[]','出身既擾擾，世事非一狀。',48,'全唐诗/poet.tang.44000.json','["出身既擾擾，世事非一狀。", "未能捨流俗，所以相追訪。", "昨弔徐五死，今送劉三葬。", "終日不得閑，爲此心悽愴。"]'),
('7430ff3a-1443-4f87-bc9c-cebedb2fa366','詩三百三首 一四六','寒山','唐','唐诗','tang','','[]','有樂且須樂，時哉不可失。',48,'全唐诗/poet.tang.44000.json','["有樂且須樂，時哉不可失。", "雖云一百年，豈滿三萬日。", "寄世是須臾，論錢莫啾唧。", "孝經末後章，委曲陳情畢。"]'),
('941162d2-9d37-48ee-a9e9-93c7baa907ac','詩三百三首 一四七','寒山','唐','唐诗','tang','','[]','獨坐常忽忽，情懷何悠悠。',48,'全唐诗/poet.tang.44000.json','["獨坐常忽忽，情懷何悠悠。", "山腰雲縵縵，谷口風颼颼。", "猨來樹嫋嫋，鳥入林啾啾。", "時催鬢颯颯，歲盡老惆惆。"]'),
('d7cdaef4-bdae-48aa-8daf-3f67393d64cc','詩三百三首 一四八','寒山','唐','唐诗','tang','','[]','一人好頭肚，六藝盡皆通。',48,'全唐诗/poet.tang.44000.json','["一人好頭肚，六藝盡皆通。", "南見驅歸北，西風趂向東。", "長漂如泛萍，不息似飛蓬。", "問是何等色，姓貧名曰窮。"]'),
('6b2a9006-11ee-4c8f-9155-ef81ea9fd6b5','詩三百三首 一四九','寒山','唐','唐诗','tang','','[]','他賢君即受，不賢君莫與。',48,'全唐诗/poet.tang.44000.json','["他賢君即受，不賢君莫與。", "君賢他見容，不賢他亦拒。", "嘉善矜不能，仁徒方得所。", "勸逐子張言，拋却卜商語。"]'),
('069308be-e25a-473e-91d4-c346a0c71bbe','詩三百三首 一百五十','寒山','唐','唐诗','tang','','[]','俗薄真成薄，人心箇不同。',48,'全唐诗/poet.tang.44000.json','["俗薄真成薄，人心箇不同。", "殷翁笑柳老，柳老笑殷翁。", "何故兩相笑，俱行譣詖中。", "裝車競嵽嵲，翻載各瀧涷。"]'),
('35723ded-7d9f-407a-882e-120dd9c6ba88','詩三百三首 一五一','寒山','唐','唐诗','tang','','[]','是我有錢日，恆爲汝貸將。',48,'全唐诗/poet.tang.44000.json','["是我有錢日，恆爲汝貸將。", "汝今既飽暖，見我不分張。", "須憶汝欲得，似我今承望。", "有無更代事，勸汝熟思量。"]'),
('d2ab37b7-5de6-440b-afa5-fa176d243127','詩三百三首 一五二','寒山','唐','唐诗','tang','','[]','人生一百年，佛說十二部。',48,'全唐诗/poet.tang.44000.json','["人生一百年，佛說十二部。", "慈悲如野鹿，瞋忿似家狗。", "家狗趂不去，野鹿常好走。", "欲伏獼猴心，須聽獅子吼。"]'),
('f8410522-1d55-434d-aa98-9fcc1987f7b1','詩三百三首 一五三','寒山','唐','唐诗','tang','','[]','教汝數般事，思量知我賢。',48,'全唐诗/poet.tang.44000.json','["教汝數般事，思量知我賢。", "極貧忍賣屋，纔富須買田。", "空腹不得走，枕頭須莫眠。", "此言期衆見，挂在日東邊。"]'),
('355d794f-e5cb-4631-b9ba-d72add045355','詩三百三首 一五四','寒山','唐','唐诗','tang','','[]','寒山多幽奇，登者皆恒懾。',48,'全唐诗/poet.tang.44000.json','["寒山多幽奇，登者皆恒懾。", "月照水澄澄，風吹草獵獵。", "凋梅雪作花，杌木雲充葉。", "觸雨轉鮮靈，非晴不可涉。"]'),
('28c02203-ae21-40b5-b836-3a4fd23c82fc','詩三百三首 一五五','寒山','唐','唐诗','tang','','[]','有樹先林生，計年逾一倍。',48,'全唐诗/poet.tang.44000.json','["有樹先林生，計年逾一倍。", "根遭陵谷變，葉被風霜改。", "咸笑外凋零，不憐內文采。", "皮膚脫落盡，唯有貞實在。"]'),
('7296b47a-6353-421a-9516-934a0da02198','詩三百三首 一五六','寒山','唐','唐诗','tang','','[]','寒山有躶蟲，身白而頭黑。',48,'全唐诗/poet.tang.44000.json','["寒山有躶蟲，身白而頭黑。", "手把兩卷書，一道將一德。", "住不安釜竈，行不齎衣裓。", "常持智慧劒，擬破煩惱賊。"]'),
('da1293b5-cc71-4f47-9e18-c46dc3857cb1','詩三百三首 一五七','寒山','唐','唐诗','tang','','[]','有人畏白首，不肯捨朱紱。',48,'全唐诗/poet.tang.44000.json','["有人畏白首，不肯捨朱紱。", "采藥空求仙，根苗亂挑掘。", "數年無效驗，癡意瞋怫鬱。", "獵師披袈裟，元非汝使物。"]'),
('481695e0-5fa5-4c84-a28d-fa5cd0eaeddc','詩三百三首 一五八','寒山','唐','唐诗','tang','','[]','昔時可可貧，今朝最貧凍。',48,'全唐诗/poet.tang.44000.json','["昔時可可貧，今朝最貧凍。", "作事不諧和，觸途成倥傯。", "行泥屢脚屈，坐社頻腹痛。", "失却斑猫兒，老鼠圍飯甕。"]'),
('ae720546-eca1-47b7-ac4b-742e54b9a805','詩三百三首 一五九','寒山','唐','唐诗','tang','','[]','我見世間人，堂堂好儀相。',264,'全唐诗/poet.tang.44000.json','["我見世間人，堂堂好儀相。", "不報父母恩，方寸底模樣。", "欠負他人錢，蹄穿始惆悵。", "箇箇惜妻兒，爺孃不供養。", "兄弟似冤家，心中長悵怏。", "憶昔少年時，求神願成長。", "今爲不孝子，世間多此樣。", "買肉自家噇，抹觜道我暢。", "自逞說嘍囉，聰明無益當。", "牛頭努目瞋，出去始時曏。", "擇佛燒好香，揀僧歸供養。", "羅漢門前乞，趂却閑和尚。", "不悟無爲人，從來無相狀。", "封疏請名僧，䞋錢兩三樣。", "雲光好法師，安角在頭上。", "汝無平等心，聖賢俱不降。", "凡聖皆混然，勸君休取相。", "我法妙難思，天龍盡迴向。", "我今稽首禮，無上法中王。", "慈悲大喜捨，名稱滿十方。", "衆生作依怙，智慧身金剛。", "頂禮無所著，我師大法王。"]'),
('151b7e3c-9ce0-4fab-aa77-738fde64ba1f','詩三百三首 一百六十','寒山','唐','唐诗','tang','','[]','可貴天然物，獨一無伴侶。',48,'全唐诗/poet.tang.44000.json','["可貴天然物，獨一無伴侶。", "覓他不可見，出入無門戶。", "促之在方寸，延之一切處。", "你若不信愛，相逢不相遇。"]'),
('df5c6dab-0d5e-451d-b60b-e5038af7f2d7','詩三百三首 一六一','寒山','唐','唐诗','tang','','[]','余家有一窟，窟中無一物。',48,'全唐诗/poet.tang.44000.json','["余家有一窟，窟中無一物。", "淨潔空堂堂，光華明日日。", "䔫食養微軀，布裘遮幻質。", "任你千聖現，我有天真佛。"]'),
('41452555-b341-4871-8bb1-04bd0ebf6f97','詩三百三首 一六二','寒山','唐','唐诗','tang','','[]','男兒大丈夫，作事莫莽鹵。',48,'全唐诗/poet.tang.44000.json','["男兒大丈夫，作事莫莽鹵。", "勁挺鐵石心，直取菩提路。", "邪路不用行，行之枉辛苦。", "不要求佛果，識取心王主。"]'),
('793d041b-e71b-4766-b5d2-0c88d83e7d79','詩三百三首 一六三','寒山','唐','唐诗','tang','','[]','粵自居寒山，曾經幾萬載。',60,'全唐诗/poet.tang.44000.json','["粵自居寒山，曾經幾萬載。", "任運遯林泉，棲遲觀自在。", "寒巖人不到，白雲常靉靆。", "細草作臥褥，青天爲被蓋。", "快活枕石頭，天地任變改。"]'),
('07a854fa-70e1-4f19-881f-6527886dc163','詩三百三首 一六四','寒山','唐','唐诗','tang','','[]','可重是寒山，白雲常自閑。',48,'全唐诗/poet.tang.44000.json','["可重是寒山，白雲常自閑。", "猨啼暢道內，虎嘯出人間。", "獨步石可履，孤吟藤好攀。", "松風清颯颯，鳥語聲𠴨𠴨。"]'),
('93f00f1b-fa25-457b-b8bc-efb675347daa','詩三百三首 一六五','寒山','唐','唐诗','tang','','[]','閑自訪高僧，煙山萬萬層。',24,'全唐诗/poet.tang.44000.json','["閑自訪高僧，煙山萬萬層。", "師親指歸路，月挂一輪燈。"]'),
('db4b0d22-3550-46e1-bb26-410025207ff4','詩三百三首 一六六','寒山','唐','唐诗','tang','','[]','閑遊華頂上，日朗晝光輝。',24,'全唐诗/poet.tang.44000.json','["閑遊華頂上，日朗晝光輝。", "四顧晴空裏，白雲同鶴飛。"]'),
('5442868b-5e64-4c02-bd4f-0ebc692b490b','詩三百三首 一六七','寒山','唐','唐诗','tang','','[]','世有多事人，廣學諸知見。',48,'全唐诗/poet.tang.44000.json','["世有多事人，廣學諸知見。", "不識本真性，與道轉懸遠。", "若能明實相，豈用陳虛願。", "一念了自心，開佛之知見。"]'),
('bc16a49b-04dc-46ae-9540-723733c27238','詩三百三首 一六八','寒山','唐','唐诗','tang','','[]','寒山有一宅，宅中無闌隔。',96,'全唐诗/poet.tang.44000.json','["寒山有一宅，宅中無闌隔。", "六門左右通，堂中見天碧。", "房房虛索索，東壁打西壁。", "其中一物無，免被人來惜。", "寒到燒輭火，飢來煮菜喫。", "不學田舍翁，廣置牛莊宅。", "盡作地獄業，一入何曾極。", "好好善思量，思量知軌則。"]'),
('4e3737a1-bf9d-462f-82c8-a619df2df424','詩三百三首 一六九','寒山','唐','唐诗','tang','','[]','儂家暫下山，入到城隍裏。',132,'全唐诗/poet.tang.44000.json','["儂家暫下山，入到城隍裏。", "逢見一羣女，端正容貌美。", "頭帶蜀樣花，燕脂塗粉膩。", "金釧鏤銀朵，羅衣緋紅紫。", "朱顏類神仙，香帶氛氳氣。", "時人皆顧盼，癡愛染心意。", "謂言世無雙，魂影隨他去。", "狗齩枯骨頭，虛自舐脣齒。", "不解返思量，與畜何曾異。", "今成白髮婆，老陋若精魅。", "無始由狗心，不超解脫地。"]'),
('7b700323-b9c3-449c-91c8-d017310b6926','詩三百三首 一百七十','寒山','唐','唐诗','tang','','[]','一自遯寒山，養命餐山果。',48,'全唐诗/poet.tang.44000.json','["一自遯寒山，養命餐山果。", "平生何所憂，此世隨緣過。", "日月如逝川，光陰石中火。", "任你天地移，我暢巖中坐。"]'),
('2ed9dc17-96df-48a3-873e-fdbe89d74596','詩三百三首 一七一','寒山','唐','唐诗','tang','','[]','我見世間人，茫茫走路塵。',48,'全唐诗/poet.tang.44000.json','["我見世間人，茫茫走路塵。", "不知此中事，將何爲去津。", "榮華能幾日，眷屬片時親。", "縱有千斤金，不如林下貧。"]'),
('08565735-813e-44e8-b349-dbf0e06fcf54','詩三百三首 一七二','寒山','唐','唐诗','tang','','[]','自聞梁朝日，四依諸賢士。',96,'全唐诗/poet.tang.44000.json','["自聞梁朝日，四依諸賢士。", "寶志萬迴師，四仙傅大士。", "顯揚一代教，作時如來使。", "造建僧伽藍，信心歸佛理。", "雖乃得如斯，有爲多患累。", "與道殊懸遠，折西補東爾。", "不達無爲功，損多益少利。", "有聲而無形，至今何處去。"]'),
('f50c3082-df12-4fa6-a476-ce552d52a145','詩三百三首 一七三','寒山','唐','唐诗','tang','','[]','吁嗟貧復病，爲人絕友親。',48,'全唐诗/poet.tang.44000.json','["吁嗟貧復病，爲人絕友親。", "甕裏長無飯，甑中屢生塵。", "蓬菴不免雨，漏榻劣容身。", "莫怪今憔悴，多愁定損人。"]'),
('95a12f6b-7936-488d-95ac-d4ab081fdc5b','詩三百三首 一七四','寒山','唐','唐诗','tang','','[]','養女畏太多，已生須訓誘。',48,'全唐诗/poet.tang.44000.json','["養女畏太多，已生須訓誘。", "捺頭遣小心，鞭背令緘口。", "未解乘機杼，那堪事箕箒。", "張婆語驢駒，汝大不如母。"]'),
('b5336bfc-41de-41ca-ba75-cd9079bf6595','詩三百三首 一七五','寒山','唐','唐诗','tang','','[]','秉志不可卷，須知我匪席。',48,'全唐诗/poet.tang.44000.json','["秉志不可卷，須知我匪席。", "浪造山林中，獨臥盤陀石。", "辯士來勸余，速令受金璧。", "鑿牆植蓬蒿，若此非有益。"]'),
('d13446a4-9f68-4376-807a-6f565e5b3fe7','詩三百三首 一七六','寒山','唐','唐诗','tang','','[]','以我棲遲處，幽深難可論。',48,'全唐诗/poet.tang.44000.json','["以我棲遲處，幽深難可論。", "無風蘿自動，不霧竹長昏。", "澗水緣誰咽，山雲忽自屯。", "午時菴內坐，始覺日頭暾。"]'),
('fcd5ec13-45fd-495a-bcf8-ff214aba9f20','詩三百三首 一七七','寒山','唐','唐诗','tang','','[]','憶昔遇逢處，人間逐勝遊。',48,'全唐诗/poet.tang.44000.json','["憶昔遇逢處，人間逐勝遊。", "樂山登萬仞，愛水泛千舟。", "送客琵琶谷，攜琴鸚鵡洲。", "焉知松樹下，抱膝冷颼颼。"]'),
('3dd03234-4a5c-48fb-97ae-ca691787e827','詩三百三首 一七八','寒山','唐','唐诗','tang','','[]','報汝修道者，進求虛勞神。',48,'全唐诗/poet.tang.44000.json','["報汝修道者，進求虛勞神。", "人有精靈物，無字復無文。", "呼時歷歷應，隱處不居存。", "叮嚀善保護，勿令有點痕。"]'),
('f68ac4ad-7adc-4f45-8b5a-ab6d53fda1fc','詩三百三首 一七九','寒山','唐','唐诗','tang','','[]','去年春鳥鳴，此時思弟兄。',48,'全唐诗/poet.tang.44000.json','["去年春鳥鳴，此時思弟兄。", "今年秋菊爛，此時思發生。", "綠水千腸咽，黃雲四面平。", "哀哉百年內，腸斷憶咸京。"]'),
('c40a6c1e-0234-436d-93f7-0a18846663f6','詩三百三首 一百八十','寒山','唐','唐诗','tang','','[]','多少天台人，不識寒山子。',24,'全唐诗/poet.tang.44000.json','["多少天台人，不識寒山子。", "莫知真意度，喚作閑言語。"]'),
('e9c1c3da-391e-4148-8b65-ea82f7c014b9','詩三百三首 一八一','寒山','唐','唐诗','tang','','[]','一住寒山萬事休，更無雜念挂心頭。',32,'全唐诗/poet.tang.44000.json','["一住寒山萬事休，更無雜念挂心頭。", "閑於石壁題詩句，任運還同不繫舟。"]'),
('fbd7bfcd-a71c-4d9a-b3d2-92dc7e1b3f69','詩三百三首 一八二','寒山','唐','唐诗','tang','','[]','可惜百年屋，左倒右復傾。',48,'全唐诗/poet.tang.44000.json','["可惜百年屋，左倒右復傾。", "牆壁分散盡，木植亂差橫。", "甎瓦片片落，朽爛不堪停。", "狂風吹驀榻，再豎卒難成。"]'),
('501d9d6d-d256-4c01-a216-232f7615a491','詩三百三首 一八三','寒山','唐','唐诗','tang','','[]','精神殊爽爽，形貌極堂堂。',48,'全唐诗/poet.tang.44000.json','["精神殊爽爽，形貌極堂堂。", "能射穿七札，讀書覽五行。", "經眠虎頭枕，昔坐象牙牀。", "若無一堵物，不啻冷如霜。"]'),
('099d19f5-6d46-4b49-9b75-5dafaacdc2a8','詩三百三首 一八四','寒山','唐','唐诗','tang','','[]','笑我田舍兒，頭頰底縶澀。',48,'全唐诗/poet.tang.44000.json','["笑我田舍兒，頭頰底縶澀。", "巾子未曾高，腰帶長時急。", "非是不及時，無錢趂不及。", "一日有錢財，浮圖頂上立。"]'),
('311e8565-cae9-4113-8bd6-1aa8996b10a5','詩三百三首 一八五','寒山','唐','唐诗','tang','','[]','買肉血{氵目舌}{氵目舌}，買魚跳鱍鱍。',56,'全唐诗/poet.tang.44000.json','["買肉血{氵目舌}{氵目舌}，買魚跳鱍鱍。", "君身招罪累，妻子成快活。", "纔死渠便嫁，他人誰敢遏。", "一朝如破牀，兩箇當頭脫。"]'),
('0fda6302-82e6-492f-a9a0-197de20fd8dc','詩三百三首 一八六','寒山','唐','唐诗','tang','','[]','客難寒山子，君詩無道理。',48,'全唐诗/poet.tang.44000.json','["客難寒山子，君詩無道理。", "吾觀乎古人，貧賤不爲恥。", "應之笑此言，談何疎闊矣。", "願君似今日，錢是急事爾。"]'),
('e9768b77-4ea3-46e7-b814-860dd70b60e3','詩三百三首 一八七','寒山','唐','唐诗','tang','','[]','從生不往來，至死無仁義。',48,'全唐诗/poet.tang.44000.json','["從生不往來，至死無仁義。", "言既有枝葉，心懷便險詖。", "若其開小道，緣此生大僞。", "詐說造雲梯，削之成棘刺。"]'),
('a3b08999-a44c-410d-bfed-1121d9847d8d','詩三百三首 一八八','寒山','唐','唐诗','tang','','[]','一缾鑄金成，一缾埏泥出。',48,'全唐诗/poet.tang.44000.json','["一缾鑄金成，一缾埏泥出。", "二缾任君看，那箇缾牢實。", "欲知缾有二，須知業非一。", "將此驗生因，修行在今日。"]'),
('4b230d68-0f52-4b51-8564-77c1c977ac70','詩三百三首 一八九','寒山','唐','唐诗','tang','','[]','攜殘荒草廬，其中煙火蔚。',48,'全唐诗/poet.tang.44000.json','["攜殘荒草廬，其中煙火蔚。", "借問羣小兒，生來凡幾日。", "門外有三車，迎之不肯出。", "飽食腹膨脝，箇是癡頑物。"]'),
('21b18344-0ca4-42ff-a49d-2616e5f970c5','詩三百三首 一百九十','寒山','唐','唐诗','tang','','[]','有身與無身，是我復非我。',48,'全唐诗/poet.tang.44000.json','["有身與無身，是我復非我。", "如此審思量，遷延倚巖坐。", "足間青草生，頂上紅塵墮。", "已見俗中人，靈牀施酒果。"]'),
('fa0f80e1-cbb9-4252-931f-5d2b042f9f40','詩三百三首 一九一','寒山','唐','唐诗','tang','','[]','昨見河邊樹，摧殘不可論。',48,'全唐诗/poet.tang.44000.json','["昨見河邊樹，摧殘不可論。", "二三餘幹在，千萬斧刀痕。", "霜凋萎疎葉，波衝枯朽根。", "生處當如此，何用怨乾坤。"]'),
('2cb7a4cb-e732-412e-80f3-c5c5e035bfeb','詩三百三首 一九二','寒山','唐','唐诗','tang','','[]','余見僧繇性希奇，巧妙間生梁朝時。',64,'全唐诗/poet.tang.44000.json','["余見僧繇性希奇，巧妙間生梁朝時。", "道子飄然爲殊特，二公善繪手毫揮。", "逞畫圖真意氣異，龍行鬼走神巍巍。", "饒邈虛空寫塵跡，無因畫得誌公師。"]'),
('34ff3dd3-b8f6-4c5b-b0fc-943ed02f1593','詩三百三首 一九三','寒山','唐','唐诗','tang','','[]','久住寒山凡幾秋，獨吟歌曲絕無憂。',64,'全唐诗/poet.tang.44000.json','["久住寒山凡幾秋，獨吟歌曲絕無憂。", "蓬扉不掩常幽寂，泉涌甘漿長自流。", "石室地鑪砂鼎沸，松黃柏茗乳香甌。", "飢餐一粒伽陀藥，心地調和倚石頭。"]'),
('7a54c07c-1dff-4532-8936-a8c60481ce4a','詩三百三首 一九四','寒山','唐','唐诗','tang','','[]','丹丘迥聳與雲齊，空裏五峰遙望低。',64,'全唐诗/poet.tang.44000.json','["丹丘迥聳與雲齊，空裏五峰遙望低。", "鴈塔高排出青嶂，禪林古殿入虹蜺。", "風搖松葉赤城秀，霧吐中巖仙路迷。", "碧落千山萬仞現，藤蘿相接次連谿。"]'),
('b8147a4a-5251-4312-b4fb-a4c7790d6cda','詩三百三首 一九五','寒山','唐','唐诗','tang','','[]','千生萬死凡幾生，生死來去轉迷情。',32,'全唐诗/poet.tang.44000.json','["千生萬死凡幾生，生死來去轉迷情。", "不識心中無價寶，猶似盲驢信脚行。"]'),
('08df7232-10b7-4c43-952a-bcb8a82973a2','詩三百三首 一九六','寒山','唐','唐诗','tang','','[]','老病殘年百有餘，面黃頭白好山居。',64,'全唐诗/poet.tang.44000.json','["老病殘年百有餘，面黃頭白好山居。", "布裘擁質隨緣過，豈羨人間巧樣模。", "心神用盡爲名利，百種貪婪進己軀。", "浮生幻化如燈燼，塚內埋身是有無。"]'),
('6ea8c051-beed-4b47-aafd-38f0c2792357','詩三百三首 一九七','寒山','唐','唐诗','tang','','[]','世間何事最堪嗟，盡是三途造罪楂。',64,'全唐诗/poet.tang.44000.json','["世間何事最堪嗟，盡是三途造罪楂。", "不學白雲巖下客，一條寒衲是生涯。", "秋到任他林落葉，春來從你樹開花。", "三界橫眠閑無事，明月清風是我家。"]'),
('7c1077fe-38b0-4a80-ac62-7a6a3e638e7b','詩三百三首 一九八','寒山','唐','唐诗','tang','','[]','昔年曾到大海遊，爲采摩尼誓懇求。',64,'全唐诗/poet.tang.44000.json','["昔年曾到大海遊，爲采摩尼誓懇求。", "直到龍宮深密處，金關鎖斷主神愁。", "龍王守護安耳裏，劒客星揮無處搜。", "賈客却歸門內去，明珠元在我心頭。"]'),
('deeb538f-2fec-43ff-af47-c78a9376836e','詩三百三首 一九九','寒山','唐','唐诗','tang','','["\u591c\u665a", "\u6708\u4eae", "\u5199\u666f", "\u6292\u60c5"]','衆星羅列夜明深，巖點孤燈月未沈。',32,'全唐诗/poet.tang.44000.json','["衆星羅列夜明深，巖點孤燈月未沈。", "圓滿光華不磨瑩，挂在青天是我心。"]'),
('c02a7f72-f997-4e1d-bd89-65e2f199df57','詩三百三首 二百','寒山','唐','唐诗','tang','','[]','千年石上古人蹤，萬丈巖前一點空。',32,'全唐诗/poet.tang.44000.json','["千年石上古人蹤，萬丈巖前一點空。", "明月照時常皎潔，不勞尋討問西東。"]'),
('3ec0ee3f-9402-4e7b-b692-57b38fa2621a','詩三百三首 二百一','寒山','唐','唐诗','tang','','[]','寒山頂上月輪孤，照見晴空一物無。',32,'全唐诗/poet.tang.44000.json','["寒山頂上月輪孤，照見晴空一物無。", "可貴天然無價寶，埋在五陰溺身軀。"]'),
('a557665d-5c9d-45d7-822f-e75e725cc1df','詩三百三首 二百二','寒山','唐','唐诗','tang','','[]','我向前谿照碧流，或向巖邊坐磐石。',32,'全唐诗/poet.tang.44000.json','["我向前谿照碧流，或向巖邊坐磐石。", "心似孤雲無所依，悠悠世事何須覓。"]'),
('706700a2-1cf3-445d-8b86-98e15150e338','詩三百三首 二百三','寒山','唐','唐诗','tang','','[]','我家本住在寒山，石巖棲息離煩緣。',64,'全唐诗/poet.tang.44000.json','["我家本住在寒山，石巖棲息離煩緣。", "泯時萬象無痕跡，舒處周流徧大千。", "光影騰輝照心地，無有一法當現前。", "方知摩尼一顆珠，解用無方處處圓。"]'),
('fa7707ba-5634-4dce-8307-683cb3345457','詩三百三首 二百四','寒山','唐','唐诗','tang','','[]','世人何事可吁嗟，苦樂交煎勿底涯。',64,'全唐诗/poet.tang.44000.json','["世人何事可吁嗟，苦樂交煎勿底涯。", "生死往來多少劫，東西南北是誰家。", "張王李趙權時姓，六道三途事似麻。", "只爲主人不了絕，遂招遷謝逐迷邪。"]'),
('4a7de0e8-31fe-41f4-a8de-cc41a423a5e4','詩三百三首 二百五','寒山','唐','唐诗','tang','','[]','余家本住在天台，雲路煙深絕客來。',64,'全唐诗/poet.tang.44000.json','["余家本住在天台，雲路煙深絕客來。", "千仞巖巒深可遯，萬重谿澗石樓臺。", "樺巾木屐沿流步，布裘藜杖繞山迴。", "自覺浮生幻化事，逍遙快樂實善哉。"]'),
('9b2d9de4-b5a2-4901-84fe-65ce5b390ddc','詩三百三首 二百六','寒山','唐','唐诗','tang','','[]','憐底衆生病，餐嘗畧不厭。',48,'全唐诗/poet.tang.44000.json','["憐底衆生病，餐嘗畧不厭。", "蒸豚揾蒜醬，炙鴨點椒鹽。", "去骨鮮魚膾，兼皮熟肉臉。", "不知他命苦，只取自家甜。"]'),
('f4b581d2-0a07-4b7c-ad25-cfbc7ec71726','詩三百三首 二百七','寒山','唐','唐诗','tang','','[]','讀書豈免死，讀書豈免貧。',48,'全唐诗/poet.tang.44000.json','["讀書豈免死，讀書豈免貧。", "何以好識字，識字勝他人。", "丈夫不識字，無處可安身。", "黃連揾蒜醬，忘計是苦辛。"]'),
('81c46f0a-28e2-44be-809a-0820f11611a0','詩三百三首 二百八','寒山','唐','唐诗','tang','','[]','我見瞞人漢，如籃盛水走。',48,'全唐诗/poet.tang.44000.json','["我見瞞人漢，如籃盛水走。", "一氣將歸家，籃裏何曾有。", "我見被人瞞，一似園中韭。", "日日被刀傷，天生還自有。"]'),
('c16d82a0-d05f-4d85-bb4c-656364165734','詩三百三首 二百九','寒山','唐','唐诗','tang','','[]','不見朝垂露，日爍自消除。',48,'全唐诗/poet.tang.44000.json','["不見朝垂露，日爍自消除。", "人身亦如此，閻浮是寄居。", "切莫因循過，且令三毒袪。", "菩提即煩惱，盡令無有餘。"]'),
('a45dd1f6-6e06-4abd-b7e8-5dfa4184f102','詩三百三首 二百一十','寒山','唐','唐诗','tang','','[]','水清澄澄瑩，徹底自然見。',48,'全唐诗/poet.tang.44000.json','["水清澄澄瑩，徹底自然見。", "心中無一事，水清衆獸現。", "心若不妄起，永劫無改變。", "若能如是知，是知無背面。"]'),
('5f810eb3-632d-4cff-a039-c29e93e49295','詩三百三首 二一一','寒山','唐','唐诗','tang','','[]','自從到此天台境，經今早度幾冬春。',32,'全唐诗/poet.tang.44000.json','["自從到此天台境，經今早度幾冬春。", "山水不移人自老，見却多少後生人。"]'),
('34c53120-4e70-4f64-96ea-d8b16fb707e7','詩三百三首 二一二','寒山','唐','唐诗','tang','','[]','說食終不飽，說衣不免寒。',48,'全唐诗/poet.tang.44000.json','["說食終不飽，說衣不免寒。", "飽喫須是飯，著衣方免寒。", "不解審思量，只道求佛難。", "迴心即是佛，莫向外頭看。"]'),
('c83aaa31-e1a1-46b7-b745-ccff1b60785c','詩三百三首 二一三','寒山','唐','唐诗','tang','','[]','可畏輪迴苦，往復似翻塵。',48,'全唐诗/poet.tang.44000.json','["可畏輪迴苦，往復似翻塵。", "蟻巡環未息，六道亂紛紛。", "改頭換面孔，不離舊時人。", "速了黑暗獄，無令心性昏。"]'),
('b4427f46-2853-423c-b600-77e3795697b9','詩三百三首 二一四','寒山','唐','唐诗','tang','','[]','可畏三界輪，念念未曾息。',48,'全唐诗/poet.tang.44000.json','["可畏三界輪，念念未曾息。", "纔始似出頭，又却遭沈溺。", "假使非非想，蓋緣多福力。", "爭似識真源，一得即永得。"]'),
('bb8065f3-8542-4e6f-b314-222af19574ef','詩三百三首 二一五','寒山','唐','唐诗','tang','','[]','昨日遊峰頂，下窺千尺崖。',48,'全唐诗/poet.tang.44000.json','["昨日遊峰頂，下窺千尺崖。", "臨危一株樹，風擺兩枝開。", "雨漂即零落，日曬作塵埃。", "嗟見此茂秀，今爲一聚灰。"]'),
('22e890da-53fd-4cb3-ac92-10eb66330522','詩三百三首 二一六','寒山','唐','唐诗','tang','','[]','自古多少聖，叮嚀教自信。',48,'全唐诗/poet.tang.44000.json','["自古多少聖，叮嚀教自信。", "人根性不等，高下有利鈍。", "真佛不肯認，置功枉受困。", "不知清淨心，便是法王印。"]'),
('228ecb1f-1d2f-4677-b7a8-0ae031638199','詩三百三首 二一七','寒山','唐','唐诗','tang','','[]','我聞天台山，山中有琪樹。',48,'全唐诗/poet.tang.44000.json','["我聞天台山，山中有琪樹。", "永言欲攀之，莫曉石橋路。", "緣此生悲歎，幸居將已慕。", "今日觀鏡中，颯颯鬢垂素。"]'),
('e9fb3d44-d48a-4783-b083-1c3d5106164a','詩三百三首 二一八','寒山','唐','唐诗','tang','','[]','養子不經師，不及都亭鼠。',48,'全唐诗/poet.tang.44000.json','["養子不經師，不及都亭鼠。", "何曾見好人，豈聞長者語。", "爲染在薰蕕，應須擇朋侶。", "五月販鮮魚，莫教人笑汝。"]'),
('f6c0921d-9ecb-4332-a8ef-4c6134097a8e','詩三百三首 二一九','寒山','唐','唐诗','tang','','[]','徒閉蓬門坐，頻經石火遷。',48,'全唐诗/poet.tang.44000.json','["徒閉蓬門坐，頻經石火遷。", "唯聞人作鬼，不見鶴成仙。", "念此那堪說，隨緣須自憐。", "迴瞻郊郭外，古墓犂爲田。"]'),
('57dd1e4c-4267-46c5-aa64-d0cfafdd13e7','詩三百三首 二百二十','寒山','唐','唐诗','tang','','[]','時人見寒山，各謂是風顛。',48,'全唐诗/poet.tang.44000.json','["時人見寒山，各謂是風顛。", "貌不起人目，身唯布裘纏。", "我語他不會，他語我不言。", "爲報往來者，可來向寒山。"]'),
('bdd48842-bf95-424b-b0d9-e690c7d6f95b','詩三百三首 二二一','寒山','唐','唐诗','tang','','[]','自在白雲閑，從來非買山。',48,'全唐诗/poet.tang.44000.json','["自在白雲閑，從來非買山。", "下危須策杖，上險捉藤攀。", "澗底松常翠，谿邊石自斑。", "友朋雖阻絕，春至鳥𠴨𠴨。"]'),
('320757b4-0d72-4d05-bf58-e6060bbcf6ab','詩三百三首 二二二','寒山','唐','唐诗','tang','','[]','我在村中住，衆推無比方。',48,'全唐诗/poet.tang.44000.json','["我在村中住，衆推無比方。", "昨日到城下，却被狗形相。", "或嫌袴太窄，或說衫少長。", "攣却鷂子眼，雀兒舞堂堂。"]'),
('d341282a-c5a0-4625-90ae-28f19d575380','詩三百三首 二二三','寒山','唐','唐诗','tang','','[]','生死元有命，富貴本由天。',48,'全唐诗/poet.tang.44000.json','["生死元有命，富貴本由天。", "此是古人語，吾今非謬傳。", "聰明好短命，癡騃却長年。", "鈍物豐財寶，醒醒漢無錢。"]'),
('658fc0f9-5ed6-4a69-bb81-4533687da31b','詩三百三首 二二四','寒山','唐','唐诗','tang','','[]','國以人爲本，猶如樹因地。',48,'全唐诗/poet.tang.44000.json','["國以人爲本，猶如樹因地。", "地厚樹扶疎，地薄樹憔悴。", "不得露其根，枝枯子先墜。", "決陂以取魚，是取一期利。"]'),
('5b35d877-2f45-4331-ae41-824e554c9311','詩三百三首 二二五','寒山','唐','唐诗','tang','','[]','衆生不可說，何意許顛邪。',48,'全唐诗/poet.tang.44000.json','["衆生不可說，何意許顛邪。", "面上兩惡鳥，心中三毒虵。", "是渠作障礙，使你事煩拏。", "舉手高彈指，南無佛陀耶。"]'),
('93ab6f05-a0ad-4645-ad6e-5f54d24836bc','詩三百三首 二二六','寒山','唐','唐诗','tang','','[]','自樂平生道，煙蘿石洞間。',48,'全唐诗/poet.tang.44000.json','["自樂平生道，煙蘿石洞間。", "野情多放曠，長伴白雲閑。", "有路不通世，無心孰可攀。", "石牀孤夜坐，圓月上寒山。"]'),
('2f482216-fa3f-433a-add1-9789ee93416a','詩三百三首 二二七','寒山','唐','唐诗','tang','','[]','大海水無邊，魚龍萬萬千。',48,'全唐诗/poet.tang.44000.json','["大海水無邊，魚龍萬萬千。", "遞互相食噉，冗冗癡肉團。", "爲心不了絕，妄想起如煙。", "性月澄澄朗，廓爾照無邊。"]'),
('0ce5b1fe-896d-4725-b184-6d5c4b02fc1d','詩三百三首 二二八','寒山','唐','唐诗','tang','','[]','自見天台頂，孤高出衆羣。',48,'全唐诗/poet.tang.44000.json','["自見天台頂，孤高出衆羣。", "風搖松竹韻，月現海潮頻。", "下望青山際，談玄有白雲。", "野情便山水，本志慕道倫。"]'),
('88042b8b-cb78-4cc6-8939-fa445387bea2','詩三百三首 二二九','寒山','唐','唐诗','tang','','[]','三五癡後生，作事不真實。',48,'全唐诗/poet.tang.44000.json','["三五癡後生，作事不真實。", "未讀十卷書，強把雌黃筆。", "將他儒行篇，喚作賊盜律。", "脫體似蟫蟲，齩破他書帙。"]'),
('d3aeb762-f963-46cb-95c4-b40cd0f7ac4d','詩三百三首 二百三十','寒山','唐','唐诗','tang','','[]','心高如山嶽，人我不伏人。',84,'全唐诗/poet.tang.44000.json','["心高如山嶽，人我不伏人。", "解講圍陀典，能談三教文。", "心中無慚媿，破戒違律文。", "自言上人法，稱爲第一人。", "愚者皆讚歎，智者撫掌笑。", "陽燄虛空花，豈得免生老。", "不如百不解，靜坐絕憂惱。"]'),
('ccf09eef-faa8-4f02-84c6-b2527488bd62','詩三百三首 二三一','寒山','唐','唐诗','tang','','[]','如許多寶貝，海中乘壞舸。',48,'全唐诗/poet.tang.44000.json','["如許多寶貝，海中乘壞舸。", "前頭失却桅，後頭又無柁。", "宛轉任風吹，高低隨浪簸。", "如何得到岸，努力莫端坐。"]'),
('ffde9fa3-46b2-4d02-b725-02b57c6070eb','詩三百三首 二三二','寒山','唐','唐诗','tang','','[]','我見凡愚人，多畜資財穀。',120,'全唐诗/poet.tang.44000.json','["我見凡愚人，多畜資財穀。", "飲酒食生命，謂言我富足。", "莫知地獄深，唯求上天福。", "罪業如毘富，豈得免災毒。", "財主忽然死，爭共當頭哭。", "供僧讀文疏，空是鬼神祿。", "福田一箇無，虛設一羣禿。", "不如早覺悟，莫作黑暗獄。", "狂風不動樹，心真無罪福。", "寄語冗冗人，叮嚀再三讀。"]'),
('f7d50bd8-2b23-46d7-950e-da663b3151fb','詩三百三首 二三三','寒山','唐','唐诗','tang','','[]','勸你三界子，莫作勿道理。',72,'全唐诗/poet.tang.44000.json','["勸你三界子，莫作勿道理。", "理短被他欺，理長不奈你。", "世間濁濫人，恰似黍黏子。", "不見無事人，獨脫無能比。", "早須返本源，三界任緣起。", "清淨入如流，莫飲無明水。"]'),
('5f1e89ed-57ca-4c94-8989-161d94afe229','詩三百三首 二三四','寒山','唐','唐诗','tang','','[]','三界人蠢蠢，六道人茫茫。',96,'全唐诗/poet.tang.44000.json','["三界人蠢蠢，六道人茫茫。", "貪財愛婬欲，心惡若豺狼。", "地獄如箭射，極苦若爲當。", "兀兀過朝夕，都不別賢良。", "好惡總不識，猶如豬及羊。", "共語如木石，嫉妒似顛狂。", "不自見己過，如豬在圈臥。", "不知自償債，却笑牛牽磨。"]'),
('15147644-a707-48b7-b4fa-775c678708c3','詩三百三首 二三五','寒山','唐','唐诗','tang','','[]','人生在塵蒙，恰似盆中蟲。',48,'全唐诗/poet.tang.44000.json','["人生在塵蒙，恰似盆中蟲。", "終日行遶遶，不離其盆中。", "神仙不可得，煩惱計無窮。", "歲月如流水，須臾作老翁。"]'),
('20fd37a4-c0ba-46c8-a793-520538fdab55','詩三百三首 二三六','寒山','唐','唐诗','tang','','[]','寒山出此語，復似顛狂漢。',60,'全唐诗/poet.tang.44000.json','["寒山出此語，復似顛狂漢。", "有事對面說，所以足人怨。", "心真出語直，直心無背面。", "臨死度奈河，誰是嘍囉漢。", "冥冥泉臺路，被業相拘絆。"]'),
('b5407ed4-4ac0-4f9b-a24f-04252b38fbfa','詩三百三首 二三七','寒山','唐','唐诗','tang','','[]','我見多知漢，終日用心神。',48,'全唐诗/poet.tang.44000.json','["我見多知漢，終日用心神。", "岐路逞嘍囉，欺謾一切人。", "唯作地獄滓，不修正直因。", "忽然無常至，定知亂紛紛。"]'),
('d3393c51-2615-402c-8cd0-328128f8b878','詩三百三首 二三八','寒山','唐','唐诗','tang','','[]','寄語諸仁者，復以何爲懷。',48,'全唐诗/poet.tang.44000.json','["寄語諸仁者，復以何爲懷。", "達道見自性，自性即如來。", "天真元具足，修證轉差迴。", "棄本却逐末，只守一場獃。"]'),
('06692d14-200c-4e87-a4c4-9eeaf09a551f','詩三百三首 二三九','寒山','唐','唐诗','tang','','[]','世有一般人，不惡又不善。',48,'全唐诗/poet.tang.44000.json','["世有一般人，不惡又不善。", "不識主人公，隨客處處轉。", "因循過時光，渾是癡肉臠。", "雖有一靈臺，如同客作漢。"]'),
('0b32d044-0a85-4b9a-bded-d809abdfe3c0','詩三百三首 二百四十','寒山','唐','唐诗','tang','','[]','常聞釋迦佛，先受然燈記。',48,'全唐诗/poet.tang.44000.json','["常聞釋迦佛，先受然燈記。", "然燈與釋迦，只論前後智。", "前後體非殊，異中無有異。", "一佛一切佛，心是如來地。"]'),
('d6bbaead-6ce1-440f-8dcd-e67b837fee8d','詩三百三首 二四一','寒山','唐','唐诗','tang','','[]','常聞國大臣，朱紫簪纓祿。',96,'全唐诗/poet.tang.44000.json','["常聞國大臣，朱紫簪纓祿。", "富貴百千般，貪榮不知辱。", "奴馬滿宅舍，金銀盈帑屋。", "癡福暫時扶，埋頭作地獄。", "忽死萬事休，男女當頭哭。", "不知有禍殃，前路何疾速。", "家破冷颼颼，食無一粒粟。", "凍餓苦悽悽，良由不覺觸。"]'),
('24f293ef-8d04-464b-8b76-888cce196aa7','詩三百三首 二四二','寒山','唐','唐诗','tang','','[]','上人心猛利，一聞便知妙。',96,'全唐诗/poet.tang.44000.json','["上人心猛利，一聞便知妙。", "中流心清淨，審思云甚要。", "下士鈍暗癡，頑皮最難裂。", "直待血淋頭，始知自摧滅。", "看取開眼賊，鬧市集人決。", "死屍棄如塵，此時向誰說。", "男兒大丈夫，一刀兩段截。", "人面禽獸心，造作何時歇。"]'),
('280b4f7a-961a-4dd6-822b-9019b34a6b9c','詩三百三首 二四三','寒山','唐','唐诗','tang','','[]','我有六兄弟，就中一箇惡。',156,'全唐诗/poet.tang.44000.json','["我有六兄弟，就中一箇惡。", "打伊又不得，駡伊又不著。", "處處無奈何，耽財好淫殺。", "見好埋頭愛，貪心過羅剎。", "阿爺惡見伊，阿孃嫌不悅。", "昨被我捉得，惡駡恣情掣。", "趂向無人處，一一向伊說。", "汝今須改行，覆車須改轍。", "若也不信受，共汝惡合殺。", "汝受我調伏，我共汝覓活。", "從此盡和同，如今過菩薩。", "學業攻鑪冶，鍊盡三山鐵。", "至今靜恬恬，衆人皆讚說。"]'),
('5d49a1c0-cd02-4fe8-909d-69bec2e03b92','詩三百三首 二四四','寒山','唐','唐诗','tang','','[]','昔日極貧苦，夜夜數他寶。',60,'全唐诗/poet.tang.44000.json','["昔日極貧苦，夜夜數他寶。", "今日審思量，自家須營造。", "掘得一寶藏，純是水精珠。", "大有碧眼胡，密擬買將去。", "余即報渠言，此珠無價數。"]'),
('ec25c0f9-b2ab-4894-968e-e8b2c8c486c7','詩三百三首 二四五','寒山','唐','唐诗','tang','','[]','一生慵嬾作，憎重只便輕。',48,'全唐诗/poet.tang.44000.json','["一生慵嬾作，憎重只便輕。", "他家學事業，余持一卷經。", "無心裝褾軸，來去省人擎。", "應病則說藥，方便度衆生。"]'),
('69f56e1e-e39b-46fa-8fc1-dadbbfb9e787','詩三百三首 二四六','寒山','唐','唐诗','tang','','[]','我見出家人，不入出家學。',60,'全唐诗/poet.tang.44000.json','["我見出家人，不入出家學。", "欲知真出家，心淨無繩索。", "澄澄孤玄妙，如如無倚託。", "三界任縱橫，四生不可泊。", "無爲無事人，逍遙實快樂。"]'),
('55c3e225-3e53-42bd-876d-f4b935084988','詩三百三首 二四七','寒山','唐','唐诗','tang','','[]','昨到雲霞觀，忽見仙尊士。',132,'全唐诗/poet.tang.44000.json','["昨到雲霞觀，忽見仙尊士。", "星冠月帔橫，盡云居山水。", "餘問神仙術，云道若爲比。", "謂言靈無上，妙藥心神祕。", "守死待鶴來，皆道乘魚去。", "余乃返窮之，推尋勿道理。", "但看箭射空，須臾還墜地。", "饒你得仙人，恰似守屍鬼。", "心月自精明，萬象何能比。", "欲知仙丹術，身內元神是。", "莫學黃巾公，握愚自守擬。"]'),
('9351af6b-84bf-48ff-acf4-fc25db758e7f','詩三百三首 二四八','寒山','唐','唐诗','tang','','[]','余家有一宅，其宅無正主。',48,'全唐诗/poet.tang.44000.json','["余家有一宅，其宅無正主。", "地生一寸草，水垂一滴露。", "火燒六箇賊，風吹黑雲雨。", "子細尋本人，布裹真珠爾。"]'),
('7e537342-de76-47c3-b495-69e6f7b0fab3','詩三百三首 二四九','寒山','唐','唐诗','tang','','[]','傳語諸公子，聽說石齊奴。',48,'全唐诗/poet.tang.44000.json','["傳語諸公子，聽說石齊奴。", "僮僕八百人，水碓三十區。", "舍下養魚鳥，樓上吹笙竽。", "伸頭臨白刃，癡心爲綠珠。"]'),
('bddb9528-e5b3-4078-bb3a-30977081c917','詩三百三首 二百五十','寒山','唐','唐诗','tang','','[]','何以長惆悵，人生似朝菌。',48,'全唐诗/poet.tang.44000.json','["何以長惆悵，人生似朝菌。", "那堪數十年，親舊凋落盡。", "以此思自哀，哀情不可忍。", "奈何當奈何，託體歸山隱。"]'),
('20f96259-9cf9-422e-8a29-8644238a206c','詩三百三首 二五一','寒山','唐','唐诗','tang','','[]','繿縷關前業，莫訶今日身。',48,'全唐诗/poet.tang.44000.json','["繿縷關前業，莫訶今日身。", "若言由冢墓，箇是極癡人。", "到頭君作鬼，豈令男女貧。", "皎然易解事，作麽無精神。"]'),
('138e5c00-5aa7-4b9a-b7db-21adb705d0db','詩三百三首 二五二','寒山','唐','唐诗','tang','','["\u9ec4\u6cb3"]','我見黃河水，凡經幾度清。',48,'全唐诗/poet.tang.44000.json','["我見黃河水，凡經幾度清。", "水流如急箭，人世若浮萍。", "癡屬根本業，無明煩惱阬。", "輪迴幾許劫，只爲造迷盲。"]'),
('317f1dd3-3dd3-4f21-ba8e-506d3255f521','詩三百三首 二五三','寒山','唐','唐诗','tang','','[]','二儀既開闢，人乃居其中。',48,'全唐诗/poet.tang.44000.json','["二儀既開闢，人乃居其中。", "迷汝即吐霧，醒汝即吹風。", "惜汝即富貴，奪汝即貧窮。", "碌碌羣漢子，萬事由天公。"]'),
('5224de87-2ab2-4dda-93e2-21e8ad163f52','詩三百三首 二五四','寒山','唐','唐诗','tang','','[]','余勸諸稚子，急離火宅中。',60,'全唐诗/poet.tang.44000.json','["余勸諸稚子，急離火宅中。", "三車在門外，載你免飄蓬。", "露地四衢坐，當天萬事空。", "十方無上下，來去任西東。", "若得箇中意，縱橫處處通。"]'),
('319edec3-7ad7-4fca-a017-2db75c3489d1','詩三百三首 二五五','寒山','唐','唐诗','tang','','[]','可歎浮生人，悠悠何日了。',48,'全唐诗/poet.tang.44000.json','["可歎浮生人，悠悠何日了。", "朝朝無閑時，年年不覺老。", "總爲求衣食，令心生煩惱。", "擾擾百千年，去來三惡道。"]'),
('0759f649-5498-4bb2-bdb6-dd8a6897d475','詩三百三首 二五六','寒山','唐','唐诗','tang','','[]','時人尋雲路，雲路杳無蹤。',48,'全唐诗/poet.tang.44000.json','["時人尋雲路，雲路杳無蹤。", "山高多險峻，澗闊少玲瓏。", "碧嶂前兼後，白雲西復東。", "欲知雲路處，雲路在虛空。"]'),
('991596c4-0098-4123-afa2-d6b30f2bb3d3','詩三百三首 二五七','寒山','唐','唐诗','tang','','[]','寒山棲隱處，絕得雜人過。',48,'全唐诗/poet.tang.44000.json','["寒山棲隱處，絕得雜人過。", "時逢林內鳥，相共唱山歌。", "瑞草聯谿谷，老松枕嵯峨。", "可觀無事客，憩歇在巖阿。"]'),
('a2efa29f-f61e-4da9-a1a1-2838b6d2fe07','詩三百三首 二五八','寒山','唐','唐诗','tang','','[]','五嶽俱成粉，須彌一寸山。',48,'全唐诗/poet.tang.44000.json','["五嶽俱成粉，須彌一寸山。", "大海一滴水，吸入在心田。", "生長菩提子，徧蓋天中天。", "語汝慕道者，慎莫繞十纏。"]'),
('c918c83a-c2fd-4e62-b71a-c49c16676164','詩三百三首 二五九','寒山','唐','唐诗','tang','','[]','無衣自訪覓，莫共狐謀裘。',48,'全唐诗/poet.tang.44000.json','["無衣自訪覓，莫共狐謀裘。", "無食自采取，莫共羊謀羞。", "借皮兼借肉，懷歎復懷愁。", "皆緣義失所，衣食常不周。"]'),
('e01bc4c0-533e-4936-a052-11b278f954d6','詩三百三首 二百六十','寒山','唐','唐诗','tang','','[]','自羨山間樂，逍遙無倚託。',60,'全唐诗/poet.tang.44000.json','["自羨山間樂，逍遙無倚託。", "逐日食殘軀，閑思無所作。", "時披古佛書，往往登石閣。", "下窺千尺崖，上有雲盤泊。", "寒月冷颼颼，身似孤飛鶴。"]'),
('622fcd46-08c6-4e5b-866d-ff0ce32c4018','詩三百三首 二六一','寒山','唐','唐诗','tang','','[]','我見轉輪王，千子常圍繞。',96,'全唐诗/poet.tang.44000.json','["我見轉輪王，千子常圍繞。", "十善化四天，莊嚴多七寶。", "七寶鎮隨身，莊嚴甚妙好。", "一朝福報盡，猶若棲蘆鳥。", "還作牛領蟲，六趣受業道。", "況復諸凡夫，無常豈長保。", "生死如旋火，輪迴似麻稻。", "不解早覺悟，爲人枉虛老。"]'),
('2497d4be-cebc-4f59-b7e5-6adc96bf591d','詩三百三首 二六二','寒山','唐','唐诗','tang','','[]','平野水寬闊，丹丘連四明。',48,'全唐诗/poet.tang.44000.json','["平野水寬闊，丹丘連四明。", "仙都最高秀，羣峰聳翠屏。", "遠遠望何極，矹矹勢相迎。", "獨標海隅外，處處播嘉名。"]'),
('dfa1d04f-e432-484b-830a-9e57737dd0ea','詩三百三首 二六三','寒山','唐','唐诗','tang','','[]','可貴一名山，七寶何能比。',48,'全唐诗/poet.tang.44000.json','["可貴一名山，七寶何能比。", "松月颼颼冷，雲霞片片起。", "匼匝幾重山，迴還多少里。", "谿澗靜澄澄，快活無窮已。"]'),
('89c04fe6-7c9e-42c3-abf0-376a077f845a','詩三百三首 二六四','寒山','唐','唐诗','tang','','[]','我見世間人，生而還復死。',48,'全唐诗/poet.tang.44000.json','["我見世間人，生而還復死。", "昨朝猶二八，壯氣胸襟士。", "如今七十過，力困形憔悴。", "恰似春日花，朝開夜落爾。"]'),
('50be911e-f92a-477e-9bcd-d7547bf723fb','詩三百三首 二六五','寒山','唐','唐诗','tang','','[]','迴聳霄漢外，雲裏路岧嶢。',48,'全唐诗/poet.tang.44000.json','["迴聳霄漢外，雲裏路岧嶢。", "瀑布千丈流，如鋪練一條。", "下有棲心窟，橫安定命橋。", "雄雄鎮世界，天台名獨超。"]'),
('cd5e00ba-d16b-42d8-a33a-5392ca583720','詩三百三首 二六六','寒山','唐','唐诗','tang','','[]','盤陀石上坐，谿澗冷淒淒。',48,'全唐诗/poet.tang.44000.json','["盤陀石上坐，谿澗冷淒淒。", "靜翫偏嘉麗，虛巖蒙霧迷。", "怡然憩歇處，日斜樹影低。", "我自觀心地，蓮花出淤泥。"]'),
('d90dd753-4752-49e0-9cc6-4b15d861d5a1','詩三百三首 二六七','寒山','唐','唐诗','tang','','[]','隱士遁人間，多向山中眠。',48,'全唐诗/poet.tang.44000.json','["隱士遁人間，多向山中眠。", "青蘿疎麓麓，碧澗響聯聯。", "騰騰且安樂，悠悠自清閑。", "免有染世事，心靜如白蓮。"]'),
('e0003917-cdba-4e06-9457-f3f463153dd5','詩三百三首 二六八','寒山','唐','唐诗','tang','','[]','寄語食肉漢，食時無逗遛。',48,'全唐诗/poet.tang.44000.json','["寄語食肉漢，食時無逗遛。", "今生過去種，未來今日修。", "只取今日美，不畏來生憂。", "老鼠入飯甕，雖飽難出頭。"]'),
('3b20d872-eca7-42f9-9480-511efba0c9ba','詩三百三首 二六九','寒山','唐','唐诗','tang','','[]','自從出家後，漸得養生趣。',48,'全唐诗/poet.tang.44000.json','["自從出家後，漸得養生趣。", "伸縮四肢全，勤聽六根具。", "褐衣隨春冬，糲食供朝暮。", "今日懇懇修，願與佛相遇。"]'),
('7b4a1ad1-b238-4057-a9fc-be7f04134f15','詩三百三首 二百七十','寒山','唐','唐诗','tang','','[]','五言五百篇，七字七十九。',48,'全唐诗/poet.tang.44000.json','["五言五百篇，七字七十九。", "三字二十一，都來六百首。", "一例書巖石，自誇云好手。", "若能會我詩，真是如來母。"]'),
('0ced3b7a-133f-4201-84e8-1b90f50ca9cc','詩三百三首 二七一','寒山','唐','唐诗','tang','','[]','世事繞悠悠，貪生早晚休。',48,'全唐诗/poet.tang.44000.json','["世事繞悠悠，貪生早晚休。", "研盡大地石，何時得歇頭。", "四時周變易，八節急如流。", "爲報火宅主，露地騎白牛。"]'),
('bfd3c4a9-901f-4e5a-b16e-b033ee011783','詩三百三首 二七二','寒山','唐','唐诗','tang','','[]','可笑五陰窟，四虵共同居。',48,'全唐诗/poet.tang.44000.json','["可笑五陰窟，四虵共同居。", "黑暗無明燭，三毒遞相驅。", "伴黨六箇賊，劫掠法財珠。", "斬却魔軍輩，安泰湛如蘇。"]'),
('df5916a1-8ebe-4324-bd0f-712c592e51a7','詩三百三首 二七三','寒山','唐','唐诗','tang','','[]','常聞漢武帝，爰及秦始皇。',48,'全唐诗/poet.tang.44000.json','["常聞漢武帝，爰及秦始皇。", "俱好神仙術，延年竟不長。", "金臺既摧折，沙丘遂滅亡。", "茂陵與驪嶽，今日草茫茫。"]'),
('c90b74ec-9b0b-4b39-a824-8e2529fa7228','詩三百三首 二七四','寒山','唐','唐诗','tang','','[]','憶得二十年，徐步國清歸。',84,'全唐诗/poet.tang.44000.json','["憶得二十年，徐步國清歸。", "國清寺中人，盡道寒山癡。", "癡人何用疑，疑不解尋思。", "我尚自不識，是伊爭得知。", "低頭不用問，問得復何爲。", "有人來駡我，分明了了知。", "雖然不應對，却是得便宜。"]'),
('91f07eff-a48c-4faa-99c2-d92324f2a27c','詩三百三首 二七五','寒山','唐','唐诗','tang','','[]','語你出家輩，何名爲出家。',264,'全唐诗/poet.tang.44000.json','["語你出家輩，何名爲出家。", "奢華求養活，繼綴族姓家。", "美舌甜脣觜，諂曲心鉤加。", "終日禮道場，持經置功課。", "鑪燒神佛香，打鐘高聲和。", "六時學客舂，晝夜不得臥。", "只爲愛錢財，心中不脫灑。", "見他高道人，却嫌誹謗駡。", "驢屎比麝香，苦哉佛陀耶。", "又見出家兒，有力及無力。", "上上高節者，鬼神欽道德。", "君王分輦坐，諸侯拜迎逆。", "堪爲世福田，世人須保惜。", "下下低愚者，詐現多求覓。", "濁濫即可知，愚癡愛財色。", "著却福田衣，種田討衣食。", "作債稅牛犂，爲事不忠直。", "朝朝行弊惡，往往痛臀脊。", "不解善思量，地獄苦無極。", "一朝著病纏，三年臥牀席。", "亦有真佛性，翻作無明賊。", "南無佛陀耶，遠遠求彌勒。"]'),
('538b6b5c-cfff-4e2a-8eb6-7d0c66c94758','詩三百三首 二七六','寒山','唐','唐诗','tang','','[]','寒巖深更好，無人行此道。',48,'全唐诗/poet.tang.44000.json','["寒巖深更好，無人行此道。", "白雲高岫閑，青嶂孤猨嘯。", "我更何所親，暢志自宜老。", "形容寒暑遷，心珠甚可保。"]'),
('10dc504b-7c32-40bd-8b66-9b6facbf28cb','詩三百三首 二七七','寒山','唐','唐诗','tang','','[]','巖前獨靜坐，圓月當天耀。',48,'全唐诗/poet.tang.44000.json','["巖前獨靜坐，圓月當天耀。", "萬象影現中，一輪本無照。", "廓然神自清，含虛洞玄妙。", "因指見其月，月是心樞要。"]'),
('77e8660e-f7c3-4627-9ce6-0f1fd0674b42','詩三百三首 二七八','寒山','唐','唐诗','tang','','[]','本志慕道倫，道倫常獲親。',48,'全唐诗/poet.tang.44000.json','["本志慕道倫，道倫常獲親。", "時逢杜源客，每接話禪賓。", "談玄月明夜，探理日臨晨。", "萬機俱泯迹，方識本來人。"]'),
('1173eb0f-19cd-48e1-af97-d35dbd836a5a','詩三百三首 二七九','寒山','唐','唐诗','tang','','[]','元非隱逸士，自號山林人。',48,'全唐诗/poet.tang.44000.json','["元非隱逸士，自號山林人。", "仕魯蒙幘帛，且愛裹疎巾。", "道有巢許操，恥爲堯舜臣。", "獼猴罩帽子，學人避風塵。"]'),
('1143abb6-7d2a-43bb-9667-2850fc256546','詩三百三首 二百八十','寒山','唐','唐诗','tang','','[]','自古諸哲人，不見有長存。',48,'全唐诗/poet.tang.44000.json','["自古諸哲人，不見有長存。", "生而還復死，盡變作灰塵。", "積骨如毘富，別淚成海津。", "唯有空名在，豈免生死輪。"]'),
('0af27f99-afc3-4e02-9897-6bb2b13f1ab4','詩三百三首 二八一','寒山','唐','唐诗','tang','','[]','今日巖前坐，坐久煙雲收。',48,'全唐诗/poet.tang.44000.json','["今日巖前坐，坐久煙雲收。", "一道清谿冷，千尋碧嶂頭。", "白雲朝影靜，明月夜光浮。", "身上無塵垢，心中那更憂。"]'),
('d3ba7932-0f66-463a-ac6b-0860a7800656','詩三百三首 二八二','寒山','唐','唐诗','tang','','[]','千雲萬水間，中有一閑士。',48,'全唐诗/poet.tang.44000.json','["千雲萬水間，中有一閑士。", "白日遊青山，夜歸巖下睡。", "倐爾過春秋，寂然無塵累。", "快哉何所依，靜若秋江水。"]'),
('6562fdf2-2b7b-496d-9289-eb39abe1689e','詩三百三首 二八三','寒山','唐','唐诗','tang','','[]','勸你休去來，莫惱他閻老。',48,'全唐诗/poet.tang.44000.json','["勸你休去來，莫惱他閻老。", "失脚入三途，粉骨遭千擣。", "長爲地獄人，永隔今生道。", "勉你信余言，識取衣中寶。"]'),
('1207a8ad-eacc-4211-9a45-1a75498a1ab3','詩三百三首 二八四','寒山','唐','唐诗','tang','','[]','世間一等流，誠堪與人笑。',48,'全唐诗/poet.tang.44000.json','["世間一等流，誠堪與人笑。", "出家弊己身，誑俗將爲道。", "雖著離塵衣，衣中多養蚤。", "不如歸去來，識取心王好。"]'),
('fb2d1e01-96e7-4fdd-b063-448e59f1f812','詩三百三首 二八五','寒山','唐','唐诗','tang','','[]','高高峰頂上，四顧極無邊。',48,'全唐诗/poet.tang.44000.json','["高高峰頂上，四顧極無邊。", "獨坐無人知，孤月照寒泉。", "泉中且無月，月自在青天。", "吟此一曲歌，歌終不是禪。"]'),
('f39bfe8b-aca3-4314-bf98-906050cad29b','詩三百三首 二八六','寒山','唐','唐诗','tang','','[]','有箇王秀才，笑我詩多失。',48,'全唐诗/poet.tang.44000.json','["有箇王秀才，笑我詩多失。", "云不識蜂腰，仍不會鶴膝。", "平側不解壓，凡言取次出。", "我笑你作詩，如盲徒詠日。"]'),
('9b4fbdb3-3752-4218-80b1-3ccad0773062','詩三百三首 二八七','寒山','唐','唐诗','tang','','[]','我住在村鄉，無爺亦無娘。',48,'全唐诗/poet.tang.44000.json','["我住在村鄉，無爺亦無娘。", "無名無姓第，人喚作張王。", "並無人教我，貧賤也尋常。", "自憐心的實，堅固等金剛。"]'),
('0b4d7f69-137f-4cba-9f64-11bf035b7d97','詩三百三首 二八八','寒山','唐','唐诗','tang','','[]','寒山出此語，此語無人信。',48,'全唐诗/poet.tang.44000.json','["寒山出此語，此語無人信。", "蜜甜足人嘗，黃蘖苦難近。", "順情生喜悅，逆意多瞋恨。", "但看木傀儡，弄了一場困。"]'),
('017f4e49-0d22-46df-b78b-3b3c24da8479','詩三百三首 二八九','寒山','唐','唐诗','tang','','[]','我見人轉經，依他言語會。',60,'全唐诗/poet.tang.44000.json','["我見人轉經，依他言語會。", "口轉心不轉，心口相違背。", "心真無委曲，不作諸纏蓋。", "但且自省躬，莫覓他替代。", "可中作得主，是知無內外。"]'),
('ba5b163e-3410-462d-8b09-d6786f14afe4','詩三百三首 二百九十','寒山','唐','唐诗','tang','','[]','寒山唯白雲，寂寂絕埃塵。',48,'全唐诗/poet.tang.44000.json','["寒山唯白雲，寂寂絕埃塵。", "草座山家有，孤燈明月輪。", "石牀臨碧沼，虎鹿每爲鄰。", "自羨幽居樂，長爲象外人。"]'),
('89e33d58-330e-4ef9-8ee0-140fa2e7fdde','詩三百三首 二九一','寒山','唐','唐诗','tang','','[]','鹿生深林中，飲水而食草。',48,'全唐诗/poet.tang.44000.json','["鹿生深林中，飲水而食草。", "伸脚樹下眠，可憐無煩惱。", "繫之在華堂，餚饍極肥好。", "終日不肯嘗，形容轉枯槁。"]'),
('7560f136-682a-4587-b784-ef14ea6da691','詩三百三首 二九二','寒山','唐','唐诗','tang','','[]','花上黃鶯子，𠴨𠴨聲可憐。',48,'全唐诗/poet.tang.44000.json','["花上黃鶯子，𠴨𠴨聲可憐。", "美人顏似玉，對此弄鳴弦。", "翫之能不足，眷戀在齠年。", "花飛鳥亦散，灑淚秋風前。"]'),
('a1a884a3-a38d-4a20-a6c6-a429787b7b96','詩三百三首 二九三','寒山','唐','唐诗','tang','','[]','棲遲寒巖下，偏訝最幽奇。',60,'全唐诗/poet.tang.44000.json','["棲遲寒巖下，偏訝最幽奇。", "攜籃采山茹，挈籠摘果歸。", "䔫齋敷茅坐，啜啄食紫芝。", "清沼濯瓢鉢，雜和煮稠稀。", "當陽擁裘坐，閑讀古人詩。"]'),
('40f40f5a-de46-4638-a01b-87baaf42eac1','詩三百三首 二九四','寒山','唐','唐诗','tang','','[]','昔日經行處，今復七十年。',48,'全唐诗/poet.tang.44000.json','["昔日經行處，今復七十年。", "故人無來往，埋在古冢間。", "余今頭已白，猶守片雲山。", "爲報後來子，何不讀古言。"]'),
('159deba0-65ce-4469-b8c3-dc229d511fe4','詩三百三首 二九五','寒山','唐','唐诗','tang','','[]','欲向東巖去，于今無量年。',48,'全唐诗/poet.tang.44000.json','["欲向東巖去，于今無量年。", "昨來攀葛上，半路困風煙。", "徑窄衣難進，苔黏履不全。", "住茲丹桂下，且枕白雲眠。"]'),
('4a06b50e-f53a-4611-9e2a-ea91d3845032','詩三百三首 二九六','寒山','唐','唐诗','tang','','[]','我見利智人，觀者便知意。',48,'全唐诗/poet.tang.44000.json','["我見利智人，觀者便知意。", "不假尋文字，直入如來地。", "心不逐諸緣，意根不妄起。", "心意不生時，內外無餘事。"]'),
('12a5d604-f4e5-4df8-bb81-94f9bdedb60e','詩三百三首 二九七','寒山','唐','唐诗','tang','','[]','身著空花衣，足躡龜毛履。',24,'全唐诗/poet.tang.44000.json','["身著空花衣，足躡龜毛履。", "手把兔角弓，擬射無明鬼。"]'),
('f81690db-a5e7-4c6b-b648-9138aea108e4','詩三百三首 二九八','寒山','唐','唐诗','tang','','[]','君看葉裏花，能得幾時好。',48,'全唐诗/poet.tang.44000.json','["君看葉裏花，能得幾時好。", "今日畏人攀，明朝待誰埽。", "可憐嬌豔情，年多轉成老。", "將世比於花，紅顏豈長保。"]'),
('659ae405-233a-424d-9741-389c871f5a55','詩三百三首 二九九','寒山','唐','唐诗','tang','','[]','畫棟非吾宅，松林是我家。',48,'全唐诗/poet.tang.44000.json','["畫棟非吾宅，松林是我家。", "一生俄爾過，萬事莫言賒。", "濟渡不造筏，漂淪爲采花。", "善根今未種，何日見生芽。"]'),
('1870cbee-d3f0-4cae-a93f-7d323eaa8cb3','詩三百三首 三百','寒山','唐','唐诗','tang','','[]','出生三十年，當遊千萬里。',48,'全唐诗/poet.tang.44000.json','["出生三十年，當遊千萬里。", "行江青草合，入塞紅塵起。", "鍊藥空求仙，讀書兼詠史。", "今日歸寒山，枕流兼洗耳。"]'),
('55254dda-b67a-4fd7-ad18-7ef3770d0ad7','詩三百三首 三百一','寒山','唐','唐诗','tang','','[]','寒山無漏巖，其巖甚濟要。',84,'全唐诗/poet.tang.44000.json','["寒山無漏巖，其巖甚濟要。", "八風吹不動，萬古人傳妙。", "寂寂好安居，空空離譏誚。", "孤月夜長明，圓日常來照。", "虎丘兼虎谿，不用相呼召。", "世間有王傅，莫把同周邵。", "我自遯寒巖，快活長歌笑。"]'),
('f20a6c1c-2231-4176-8942-345adbcb87d7','詩三百三首 三百二','寒山','唐','唐诗','tang','','[]','沙門不持戒，道士不服藥。',24,'全唐诗/poet.tang.44000.json','["沙門不持戒，道士不服藥。", "自古多少賢，盡在青山脚。"]'),
('99ac6989-56ed-471d-a852-18587221d33d','詩三百三首 三百三','寒山','唐','唐诗','tang','','[]','有人笑我詩，我詩合典雅。',60,'全唐诗/poet.tang.44000.json','["有人笑我詩，我詩合典雅。", "不煩鄭氏箋，豈用毛公解。", "不恨會人稀，只爲知音寡。", "若遣趁宮商，余病莫能罷。", "忽遇明眼人，即自流天下。"]'),
('184470e1-61f8-4207-88c2-842a0f1eda68','三字詩六首 一','寒山','唐','唐诗','tang','','[]','寒山道，無人到。',56,'全唐诗/poet.tang.44000.json','["寒山道，無人到。", "若能行，稱十號。", "有蟬鳴，無鴉噪。", "黃葉落，白雲掃。", "石磊磊，山隩隩。", "我獨居，名善導。", "子細看，何相好。"]'),
('c6de9a95-a9d4-4f8e-a0a2-00f7956aca73','三字詩六首 二','寒山','唐','唐诗','tang','','[]','寒山寒，冰鎖石。',32,'全唐诗/poet.tang.44000.json','["寒山寒，冰鎖石。", "藏山青，現雪白。", "日出照，一時釋。", "從茲暖，養老客。"]'),
('47ce7bc3-15c4-4047-89b5-1cf084bfbdc2','三字詩六首 三','寒山','唐','唐诗','tang','','[]','我居山，勿人識。',16,'全唐诗/poet.tang.44000.json','["我居山，勿人識。", "白雲中，常寂寂。"]'),
('005dc730-afdf-4827-9c1b-af507d164bdd','三字詩六首 四','寒山','唐','唐诗','tang','','[]','寒山深，稱我心。',32,'全唐诗/poet.tang.44000.json','["寒山深，稱我心。", "純白石，勿黃金。", "泉聲響，撫伯琴。", "有子期，辨此音。"]'),
('9d8d4672-ae46-4a04-a0d1-caa2c1d94d89','三字詩六首 五','寒山','唐','唐诗','tang','','[]','重巖中，足清風。',32,'全唐诗/poet.tang.44000.json','["重巖中，足清風。", "扇不搖，涼冷通。", "明月照，白雲籠。", "獨自坐，一老翁。"]'),
('9db32987-bc33-4d8a-9571-b822940a56dd','三字詩六首 六','寒山','唐','唐诗','tang','','[]','寒山子，長如是。',16,'全唐诗/poet.tang.44000.json','["寒山子，長如是。", "獨自居，不生死。"]'),
('3ddd47e2-07ed-4874-8226-35e67daa6222','拾遺二首新添 一','寒山','唐','唐诗','tang','','[]','我見世間人，箇箇爭意氣。',48,'全唐诗/poet.tang.44000.json','["我見世間人，箇箇爭意氣。", "一朝忽然死，只得一片地。", "闊四尺，長丈二。", "汝若會出來爭意氣，我與汝立碑記。"]'),
('09342d24-38a0-4a9d-b857-e9b0c56e30f7','拾遺二首新添 二','寒山','唐','唐诗','tang','','[]','家有寒山詩，勝汝看經卷。',24,'全唐诗/poet.tang.44000.json','["家有寒山詩，勝汝看經卷。", "書放屏風上，時時看一徧。"]'),
('aac347ef-a941-4d60-a4dc-653708ba6d3f','詩 一','拾得','唐','唐诗','tang','','[]','諸佛留藏經，只爲人難化。',48,'全唐诗/poet.tang.44000.json','["諸佛留藏經，只爲人難化。", "不唯賢與愚，箇箇心搆架。", "造業大如山，豈解懷憂怕。", "那肯細尋思，日夜懷姦詐。"]'),
('48d8112f-856e-43f7-8a0c-d7a9f4a169be','詩 二','拾得','唐','唐诗','tang','','[]','嗟見世間人，箇箇愛喫肉。',96,'全唐诗/poet.tang.44000.json','["嗟見世間人，箇箇愛喫肉。", "椀楪不曾乾，長時道不足。", "昨日設箇齋，今朝宰六畜。", "都緣業使牽，非干情所欲。", "一度造天堂，百度造地獄。", "閻羅使來追，合家盡啼哭。", "鑪子邊向火，鑊子裏澡浴。", "更得出頭時，換却汝衣服。"]'),
('26e830ef-d5ae-48fe-9f41-401d7d504aff','詩 三','拾得','唐','唐诗','tang','','[]','出家要清閑，清閑即爲貴。',72,'全唐诗/poet.tang.44000.json','["出家要清閑，清閑即爲貴。", "如何塵外人，却入塵埃裏。", "一向迷本心，終朝役名利。", "名利得到身，形容已顦顇。", "況復不遂者，虛用平生志。", "可憐無事人，未能笑得爾。"]'),
('8abf04eb-d610-41d1-aeb9-31880fef84a4','詩 四','拾得','唐','唐诗','tang','','[]','養兒與娶妻，養女求媒娉。',48,'全唐诗/poet.tang.44000.json','["養兒與娶妻，養女求媒娉。", "重重皆是業，更殺衆生命。", "聚集會親情，總來看盤飣。", "目下雖稱心，罪簿先注定。"]'),
('974100ce-dfec-4ca0-a07c-2ca96d504855','詩 五','拾得','唐','唐诗','tang','','[]','得此分叚身，可笑好形質。',48,'全唐诗/poet.tang.44000.json','["得此分叚身，可笑好形質。", "面貌似銀盤，心中黑如漆。", "烹豬又宰羊，誇道甜如蜜。", "死後受波吒，更莫稱冤屈。"]'),
('1352915a-1e91-4610-9e46-33321b4da70e','詩 六','拾得','唐','唐诗','tang','','[]','佛哀三界子，總是親男女。',48,'全唐诗/poet.tang.44000.json','["佛哀三界子，總是親男女。", "恐沈黑暗阬，示儀垂化度。", "盡登無上道，俱證菩提路。", "教汝癡衆生，慧心勤覺悟。"]'),
('85baf4c4-d265-41bf-9ec2-30f72cae1c6c','詩 七','拾得','唐','唐诗','tang','','[]','佛拾尊榮樂，爲愍諸癡子。',48,'全唐诗/poet.tang.44000.json','["佛拾尊榮樂，爲愍諸癡子。", "早願悟無生，辦集無上事。", "後來出家者，多緣無業次。", "不能得衣食，頭鑽入於寺。"]'),
('4af6305e-3d2f-4b6e-847f-ed8358ab4cd7','詩 八','拾得','唐','唐诗','tang','','[]','嗟見世間人，永劫在迷津。',24,'全唐诗/poet.tang.44000.json','["嗟見世間人，永劫在迷津。", "不省這箇意，修行徒苦辛。"]'),
('26727de8-2e48-4266-929e-523e4d4b376f','詩 九','拾得','唐','唐诗','tang','','[]','我詩也是詩，有人喚作偈。',48,'全唐诗/poet.tang.44000.json','["我詩也是詩，有人喚作偈。", "詩偈總一般，讀時須子細。", "緩緩細披尋，不得生容易。", "依此學修行，大有可笑事。"]'),
('e43b50da-c190-467b-8e83-e74ee259088f','詩 十','拾得','唐','唐诗','tang','','[]','有偈有千萬，卒急述應難。',48,'全唐诗/poet.tang.44000.json','["有偈有千萬，卒急述應難。", "若要相知者，但入天台山。", "巖中深處坐，說理及談玄。", "共我不相見，對面似千山。"]'),
('3013fc18-8df3-47de-9f1a-f4589a058aa2','詩 十一','拾得','唐','唐诗','tang','','[]','世間億萬人，面孔不相似。',48,'全唐诗/poet.tang.44000.json','["世間億萬人，面孔不相似。", "借問何因緣，致令遣如此。", "各執一般見，互說非兼是。", "但自修己身，不要言他已。"]'),
('e9c31969-18b8-4b3b-9474-53fe5556babb','詩 十二','拾得','唐','唐诗','tang','','[]','男女爲婚嫁，俗務是常儀。',48,'全唐诗/poet.tang.44000.json','["男女爲婚嫁，俗務是常儀。", "自量其事力，何用廣張施。", "取債誇人我，論情入骨癡。", "殺他雞犬命，身死墮阿鼻。"]'),
('56077cce-5478-41a7-8738-9b11e683c7ab','詩 十三','拾得','唐','唐诗','tang','','[]','世上一種人，出性常多事。',48,'全唐诗/poet.tang.44000.json','["世上一種人，出性常多事。", "終日傍街衢，不離諸酒肆。", "爲他作保見，替他說道理。", "一朝有乖張，過咎全歸你。"]'),
('d9002e68-7b4c-4c5a-afb9-46228f2889ff','詩 十四','拾得','唐','唐诗','tang','','[]','我勸出家輩，須知教法深。',48,'全唐诗/poet.tang.44000.json','["我勸出家輩，須知教法深。", "專心求出離，輒莫染貪淫。", "大有俗中士，知非不愛金。", "故知君子志，任運聽浮沈。"]'),
('7bc81ce2-0e1b-4043-83fc-fdeb4312f369','詩 十五','拾得','唐','唐诗','tang','','[]','寒山住寒山，拾得自拾得。',48,'全唐诗/poet.tang.44000.json','["寒山住寒山，拾得自拾得。", "凡愚豈見知，豐干却相識。", "見時不可見，覓時何處覓。", "借問有何緣，却道無爲力。"]'),
('c9d855d9-d87f-45af-974e-cb6c86c75bda','詩 十六','拾得','唐','唐诗','tang','','["\u9ec4\u6cb3"]','從來是拾得，不是偶然稱。',48,'全唐诗/poet.tang.44000.json','["從來是拾得，不是偶然稱。", "別無親眷屬，寒山是我兄。", "兩人心相似，誰能徇俗情。", "若問年多少，黃河幾度清。"]'),
('2ddc907a-c1b3-4669-b4ed-18690160b8e2','詩 十七','拾得','唐','唐诗','tang','','[]','若解捉老鼠，不在五白猫。',48,'全唐诗/poet.tang.44000.json','["若解捉老鼠，不在五白猫。", "若能悟理性，那由錦繡包。", "真珠入席袋，佛性止蓬茅。", "一羣取相漢，用意總無交。"]'),
('3956c666-98cd-499d-9301-b972d231e3b1','詩 十八','拾得','唐','唐诗','tang','','[]','運心常寬廣，此則名爲布。',48,'全唐诗/poet.tang.44000.json','["運心常寬廣，此則名爲布。", "輟己惠於人，方可名爲施。", "後來人不知，焉能會此義。", "未設一庸僧，早擬望富貴。"]'),
('53f2dc02-4b4b-48e3-b593-7e52befc7a68','詩 十九','拾得','唐','唐诗','tang','','[]','獼猴尚教得，人何不憤發。',48,'全唐诗/poet.tang.44000.json','["獼猴尚教得，人何不憤發。", "前車即落阬，後車須改轍。", "若也不知此，恐君惡合殺。", "此來是夜叉，變即成菩薩。"]'),
('b52f4213-2e90-43b3-86fc-f1d5a928e3b0','詩 二十','拾得','唐','唐诗','tang','','[]','自從到此天台寺，經今早已幾冬春。',32,'全唐诗/poet.tang.44000.json','["自從到此天台寺，經今早已幾冬春。", "山水不移人自老，見却多少後生人。"]'),
('b6f92f3d-a91e-4c75-a133-54ea28d96d31','詩 二十一','拾得','唐','唐诗','tang','','[]','君不見三界之中紛擾擾，只爲無明不了絕。',35,'全唐诗/poet.tang.44000.json','["君不見三界之中紛擾擾，只爲無明不了絕。", "一念不生心澄然，無去無來不生滅。"]'),
('72822367-bfd2-42b7-b3cb-9adf6ddc1356','詩 二十二','拾得','唐','唐诗','tang','','[]','故林又斬新，剡源谿上人。',48,'全唐诗/poet.tang.44000.json','["故林又斬新，剡源谿上人。", "天姥峽關嶺，通同次海津。", "灣深曲島間，淼淼水雲雲。", "借問松禪客，日輪何處暾。"]'),
('e02aeec7-88d3-4ff0-8520-6bce8a01895a','詩 二十三','拾得','唐','唐诗','tang','','[]','自笑老夫筋力敗，偏戀松巖愛獨遊。',32,'全唐诗/poet.tang.44000.json','["自笑老夫筋力敗，偏戀松巖愛獨遊。", "可歎往年至今日，任運還同不繫舟。"]'),
('56ecf12c-72e9-46d8-a372-33ecb101c9a0','詩 二十四','拾得','唐','唐诗','tang','','[]','一入雙谿不計春，鍊暴黃精幾許斤。',64,'全唐诗/poet.tang.44000.json','["一入雙谿不計春，鍊暴黃精幾許斤。", "鑪竈石鍋頻煮沸，土甑久烝氣味珍。", "誰來幽谷餐仙食，獨向雲泉更勿人。", "延齡壽盡招手石，此棲終不出山門。"]'),
('beef07d9-a266-494a-bbda-b99d7aa4544a','詩 二十五','拾得','唐','唐诗','tang','','[]','躑躅一羣羊，沿山又入谷。',48,'全唐诗/poet.tang.44000.json','["躑躅一羣羊，沿山又入谷。", "看人貪竹塞，且遭豺狼逐。", "元不出孳生，便將充口腹。", "從頭喫至尾，𩚛𩚛無餘肉。"]'),
('9c7863b2-4f3c-4f51-8a99-4d1ead6f4618','詩 二十六','拾得','唐','唐诗','tang','','[]','銀星釘稱衡，綠絲作稱紐。',48,'全唐诗/poet.tang.44000.json','["銀星釘稱衡，綠絲作稱紐。", "買人推向前，賣人推向後。", "不顧他心怨，唯言我好手。", "死去見閻王，背後插掃箒。"]'),
('b2e5087d-abf9-4653-8e07-74cff95dcf01','詩 二十七','拾得','唐','唐诗','tang','','[]','閉門私造罪，準擬免災殃。',48,'全唐诗/poet.tang.44000.json','["閉門私造罪，準擬免災殃。", "被他惡部童，抄得報閻王。", "縱不入鑊湯，亦須臥鐵牀。", "不許雇人替，自作自身當。"]'),
('b3be1672-0ade-4d31-9126-c782aa300564','詩 二十八','拾得','唐','唐诗','tang','','[]','悠悠塵裏人，常道塵中樂。',36,'全唐诗/poet.tang.44000.json','["悠悠塵裏人，常道塵中樂。", "我見塵中人，心生多慜顧。", "何哉慜此流，念彼塵中苦。"]'),
('e5ba6574-18be-4192-ab2f-7888f924db31','詩 二十九','拾得','唐','唐诗','tang','','[]','無去無來本湛然，不居內外及中間。',32,'全唐诗/poet.tang.44000.json','["無去無來本湛然，不居內外及中間。", "一顆水精絕瑕翳，光明透滿出人天。"]'),
('27779fe9-3492-4af0-a98f-51c106f4f2e8','詩 三十','拾得','唐','唐诗','tang','','[]','少年學書劒，叱馭到荆州。',48,'全唐诗/poet.tang.44000.json','["少年學書劒，叱馭到荆州。", "聞伐匈奴盡，婆娑無處遊。", "歸來翠巖下，席草翫清流。", "壯士志未騁，獼猴騎土牛。"]'),
('94af3e39-cd84-4d8a-9db4-fb3201ea6b9c','詩 三十一','拾得','唐','唐诗','tang','','[]','三界如轉輪，浮生若流水。',36,'全唐诗/poet.tang.44000.json','["三界如轉輪，浮生若流水。", "蠢蠢諸品類，貪生不覺死。", "汝看朝垂露，能得幾時子。"]'),
('25e4460e-33bd-4fda-8590-7e1d5829dc4d','詩 三十二','拾得','唐','唐诗','tang','','[]','閑入天台洞，訪人人不知。',48,'全唐诗/poet.tang.44000.json','["閑入天台洞，訪人人不知。", "寒山爲伴侶，松下噉靈芝。", "每談今古事，嗟見世愚癡。", "箇箇入地獄，早晚出頭時。"]'),
('3ef4ff31-d4c4-4651-89ed-c80b17dfd906','詩 三十三','拾得','唐','唐诗','tang','','[]','古佛路淒淒，愚人到却迷。',48,'全唐诗/poet.tang.44000.json','["古佛路淒淒，愚人到却迷。", "只緣前業重，所以不能知。", "欲識無爲理，心中不挂絲。", "生生勤苦學，必定覩天師。"]'),
('82b8f42d-f230-4199-8df0-8c70eacee5c8','詩 三十四','拾得','唐','唐诗','tang','','[]','各有天真佛，號之爲寶王。',48,'全唐诗/poet.tang.44000.json','["各有天真佛，號之爲寶王。", "珠光日夜照，玄妙卒難量。", "盲人常兀兀，那肯怕災殃。", "唯貪淫泆業，此輩實堪傷。"]'),
('28f4edea-260a-4ab3-aa5f-dd35b4619900','詩 三十五','拾得','唐','唐诗','tang','','[]','出家求出離，哀念苦衆生。',48,'全唐诗/poet.tang.44000.json','["出家求出離，哀念苦衆生。", "助佛爲揚化，令教選路行。", "何曾解救苦，恣意亂縱橫。", "一時同受溺，俱落大深阬。"]'),
('476e4733-9bc0-423e-8d77-9e4733a943cb','詩 三十六','拾得','唐','唐诗','tang','','[]','常飲三毒酒，昏昏都不知。',48,'全唐诗/poet.tang.44000.json','["常飲三毒酒，昏昏都不知。", "將錢作夢事，夢事成鐵圍。", "以苦欲捨苦，捨苦無出期。", "應須早覺悟，覺悟自歸依。"]'),
('5a00d070-3f27-44a0-95dd-b157b1f79da7','詩 三十七','拾得','唐','唐诗','tang','','[]','雲山疊疊幾千重，幽谷路深絕人蹤。',32,'全唐诗/poet.tang.44000.json','["雲山疊疊幾千重，幽谷路深絕人蹤。", "碧澗清流多勝境，時來鳥語合人心。"]'),
('4cbd9de0-47ba-4c95-8575-d9ae3a1d51c4','詩 三十八','拾得','唐','唐诗','tang','','[]','後來出家子，論情入骨癡。',48,'全唐诗/poet.tang.44000.json','["後來出家子，論情入骨癡。", "本來求解脫，却見受驅馳。", "終朝遊俗舍，禮念作威儀。", "博錢沽酒喫，翻成客作兒。"]'),
('f222d508-d85d-4ec8-b76a-25c762d67b68','詩 三十九','拾得','唐','唐诗','tang','','[]','若論常快活，唯有隱居人。',48,'全唐诗/poet.tang.44000.json','["若論常快活，唯有隱居人。", "林花長似錦，四季色常新。", "或向巖間坐，旋瞻見桂輪。", "雖然身暢逸，却念世間人。"]'),
('68dd6a7e-cab2-4a46-b198-273d5f443603','詩 四十','拾得','唐','唐诗','tang','','[]','我見出家人，總愛喫酒肉。',48,'全唐诗/poet.tang.44000.json','["我見出家人，總愛喫酒肉。", "此合上天堂，却沈歸地獄。", "念得兩卷經，欺他道鄽俗。", "豈知鄽俗士，大有根性熟。"]'),
('19d4d542-43b7-40b5-a5d4-40326cb6643e','詩 四十一','拾得','唐','唐诗','tang','','[]','我見頑鈍人，燈心柱須彌。',48,'全唐诗/poet.tang.44000.json','["我見頑鈍人，燈心柱須彌。", "蟻子齧大樹，焉知氣力微。", "學咬兩莖菜，言與祖師齊。", "火急求懺悔，從今輒莫迷。"]'),
('d3534362-2ba7-44a5-99a2-2fa00d15abcd','詩 四十二','拾得','唐','唐诗','tang','','[]','若見月光明，照燭四天下。',48,'全唐诗/poet.tang.44000.json','["若見月光明，照燭四天下。", "圓暉掛太虛，瑩淨能蕭灑。", "人道有虧盈，我見無衰謝。", "狀似摩尼珠，光明無晝夜。"]'),
('be5875f5-41bc-4a80-8f59-5d1dc64e0f54','詩 四十三','拾得','唐','唐诗','tang','','[]','余住無方所，盤泊無爲理。',48,'全唐诗/poet.tang.44000.json','["余住無方所，盤泊無爲理。", "時陟湼盤山，或翫香林寺。", "尋常只是閑，言不干名利。", "東海變桑田，我心誰管你。"]'),
('57dff727-acb6-4cef-9d36-2ac3c6f0a8c5','詩 四十四','拾得','唐','唐诗','tang','','[]','左手握驪珠，右手執慧劒。',48,'全唐诗/poet.tang.44000.json','["左手握驪珠，右手執慧劒。", "先破無明賊，神珠自吐燄。", "傷嗟愚癡人，貪愛那生厭。", "一墮三途間，始覺前程險。"]'),
('5bfab23f-e3d7-4fa6-86ed-637bf86009c0','詩 四十五','拾得','唐','唐诗','tang','','[]','般若酒泠泠，飲多人易醒。',48,'全唐诗/poet.tang.44000.json','["般若酒泠泠，飲多人易醒。", "余住天台山，凡愚那見形。", "常遊深谷洞，終不逐時情。", "無思亦無慮，無辱也無榮。"]'),
('f95d04b0-ca1f-4629-b14a-89c9bd872af3','詩 四十六','拾得','唐','唐诗','tang','','[]','平生何所憂，此世隨緣過。',36,'全唐诗/poet.tang.44000.json','["平生何所憂，此世隨緣過。", "日月如逝波，光陰石中火。", "任他天地移，我暢巖中坐。"]'),
('dc0be9dd-32f7-4f59-9abb-16a991a7f781','詩 四十七','拾得','唐','唐诗','tang','','[]','嗟見多知漢，終日枉用心。',48,'全唐诗/poet.tang.44000.json','["嗟見多知漢，終日枉用心。", "岐路逞嘍囉，欺謾一切人。", "唯作地獄滓，不修來世因。", "忽爾無常到，定知亂紛紛。"]'),
('56b3fd0c-6363-40e7-8924-6c6278df7e1d','詩 四十八','拾得','唐','唐诗','tang','','[]','迢迢山徑峻，萬仞險隘危。',48,'全唐诗/poet.tang.44000.json','["迢迢山徑峻，萬仞險隘危。", "石橋莓苔綠，時見白雲飛。", "瀑布懸如練，月影落潭暉。", "更登華頂上，猶待孤鶴期。"]'),
('4d1b9841-e1cd-43cf-8609-bd88633c6b5d','詩 四十九','拾得','唐','唐诗','tang','','[]','松月冷颼颼，片片雲霞起。',48,'全唐诗/poet.tang.44000.json','["松月冷颼颼，片片雲霞起。", "匼匝幾重山，縱目千萬里。", "谿潭水澄澄，徹底鏡相似。", "可貴靈臺物，七寶莫能比。"]'),
('059da24b-a5f3-40ec-ba62-97fd741f4b42','詩 五十','拾得','唐','唐诗','tang','','[]','世有多解人，愚癡學閑文。',60,'全唐诗/poet.tang.44000.json','["世有多解人，愚癡學閑文。", "不憂當來果，唯知造惡因。", "見佛不解禮，覩僧倍生瞋。", "五逆十惡輩，三毒以爲鄰。", "死去入地獄，未有出頭辰。"]'),
('6d7bc69f-dbfb-4b1c-baef-4b22d024942d','詩 五十一','拾得','唐','唐诗','tang','','[]','人生浮世中，箇箇願富貴。',48,'全唐诗/poet.tang.44000.json','["人生浮世中，箇箇願富貴。", "高堂車馬多，一呼百諾至。", "吞併田地宅，準擬承後嗣。", "未逾七十秋，冰消瓦解去。"]'),
('88316a3c-a123-47ae-9c7d-444057f9626d','詩 五十二','拾得','唐','唐诗','tang','','[]','水浸泥彈丸，思量無道理。',48,'全唐诗/poet.tang.44000.json','["水浸泥彈丸，思量無道理。", "浮漚夢幻身，百年能幾幾。", "不解細思惟，將言長不死。", "誅剝壘千金，留將與妻子。"]'),
('b2f2c688-0945-45f8-a110-5ba34a93a30d','詩 五十三','拾得','唐','唐诗','tang','','[]','雲林最幽棲，傍澗枕月谿。',44,'全唐诗/poet.tang.44000.json','["雲林最幽棲，傍澗枕月谿。", "松拂盤陀石，甘泉涌淒淒。", "靜坐偏佳麗，虛巖曚霧迷。", "怡然居憩地，日。"]'),
('064bae26-29b2-4b4b-b48f-93ad4e9d16e0','詩 五十四','拾得','唐','唐诗','tang','','[]','可笑是林泉，數里少人煙。',84,'全唐诗/poet.tang.44000.json','["可笑是林泉，數里少人煙。", "雲從巖嶂起，瀑布水潺潺。", "猨啼唱道曲，虎嘯出人間。", "松風清颯颯，鳥語聲關關。", "獨步繞石澗，孤陟上峰巒。", "時坐盤陀石，偃仰攀蘿沿。", "遙望城隍處，惟聞鬧喧喧。"]'),
('ff51f414-8c2e-4658-ba6a-7ffb65d37790','壁上詩二首 一','豐干','唐','唐诗','tang','','[]','余自來天台，凡經幾萬迴。',120,'全唐诗/poet.tang.44000.json','["余自來天台，凡經幾萬迴。", "一身如雲水，悠悠任去來。", "逍遙絕無鬧，忘機隆佛道。", "世途岐路心，衆生多煩惱。", "兀兀沈浪海，漂漂輪三界。", "可惜一靈物，無始被境埋。", "電光瞥然起，生死紛塵埃。", "寒山特相訪，拾得常往來。", "論心話明月，太虛廓無礙。", "法界即無邊，一法普徧該。"]'),
('24f48460-fe3a-417b-98ab-5ac1c2bbb611','壁上詩二首 二','豐干','唐','唐诗','tang','','[]','本來無一物，亦無塵可拂。',24,'全唐诗/poet.tang.44000.json','["本來無一物，亦無塵可拂。", "若能了達此，不用坐兀兀。"]'),
('399ca2c4-7687-4fc5-ae6a-567a0d23c58b','奉和竇使君同恭法師詠高僧二首 竺佛圖澄','慧宣','唐','唐诗','tang','','[]','大誓憫塗炭，乘機入生死。',60,'全唐诗/poet.tang.44000.json','["大誓憫塗炭，乘機入生死。", "中州法既弘，葛陂暴亦止。", "乳孔光一室，掌鏡徹千里。", "道盛咒蓮華，災生吟棘子。", "埋石緣雖謝，流沙化方始。"]'),
('7a0db264-19d2-48c6-8b61-ddc5523b82c2','奉和竇使君同恭法師詠高僧二首 釋僧肇','慧宣','唐','唐诗','tang','','[]','般若唯絕鑿，湼槃固無名。',60,'全唐诗/poet.tang.44000.json','["般若唯絕鑿，湼槃固無名。", "先賢未始覺，之子唱希聲。", "秦王嗟理詣，童壽揖詞清。", "徽音聞廬岳，精難動中京。", "適驗方袍裏，奇才復挺生。"]'),
('1d5ab856-44a2-431a-9aed-7ab42730d3c2','秋日遊東山寺尋殊曇二法師','慧宣','唐','唐诗','tang','','[]','木落樹蕭槮，水清流㵳寂。',148,'全唐诗/poet.tang.44000.json','["木落樹蕭槮，水清流㵳寂。", "屬此悲哉氣，復茲羈旅慼。", "奚用寫煩憂，山泉恣遊歷。", "萬丈窺深澗，千尋仰絕壁。", "傍嶺竹參差，緣崖藤冪{罓/歷}。", "行行極幽邃，去去逾空寂。", "果值息心侶，喬枝方挂錫。", "圍遶悉栴檀，純良豈沙礫。", "妙法誠無比，深經解怨敵。", "心歡即頂禮，道存仍目擊。", "慧刀幸已逢，疑網於焉析。", "豈直却煩惱，方期拯沈溺。"]'),
('a8c45d99-98d7-4b49-b296-5eb2f7d642eb','句','慧宣','唐','唐诗','tang','','[]','如蒙一被服，方堪稱福田。',12,'全唐诗/poet.tang.44000.json','["如蒙一被服，方堪稱福田。"]'),
('85441a30-562e-440f-8220-2ba2cf8e545c','愛妾換馬','法宣','唐','唐诗','tang','','[]','朱鬣飾金鑣，紅妝束素腰。',48,'全唐诗/poet.tang.44000.json','["朱鬣飾金鑣，紅妝束素腰。", "似雲來躞蹀，如雪去飄颻。", "桃花含淺汗，柳葉帶餘嬌。", "騁光將獨立，雙絕不俱標。"]'),
('87721262-872d-4e31-9e9e-f778b6066857','和趙王觀妓','法宣','唐','唐诗','tang','','[]','桂山留上客，蘭室命妖饒。',48,'全唐诗/poet.tang.44000.json','["桂山留上客，蘭室命妖饒。", "城中畫廣黛，宮裏束纖腰。", "舞袖風前舉，歌聲扇後嬌。", "周郎不須顧，今日管弦調。"]'),
('815938ea-8ede-48c7-b9de-0e72a80335b9','聽獨杵搗衣','慧偘','唐','唐诗','tang','','[]','非是無人助，意欲自鳴砧。',48,'全唐诗/poet.tang.44000.json','["非是無人助，意欲自鳴砧。", "向月憐孤影，承風送迥音。", "疑擣雙絲練，似奏一弦琴。", "令君聞獨杵，知妾有專心。"]'),
('d3f3de62-f789-4e6f-bac3-36b4534739ef','聞侯方兒來寇','慧偘','唐','唐诗','tang','','[]','羊皮贖去士，馬革歛還尸。',24,'全唐诗/poet.tang.44000.json','["羊皮贖去士，馬革歛還尸。", "天下方無事，孝廉非哭時。"]'),
('1e8f9421-bd0c-481d-953d-991eb81af2ec','和琳法師初春法集之作','慧淨','唐','唐诗','tang','','[]','鷲嶺光前選，祇園表昔恭。',108,'全唐诗/poet.tang.44000.json','["鷲嶺光前選，祇園表昔恭。", "哲人崇踵武，弘道會羣龍。", "高座登蓮葉，麈尾振霜松。", "塵飛揚雅梵，風度引疎鐘。", "靜言澄義海，發論上詞鋒。", "心虛道易合，跡廣席難重。", "和風動淑氣，麗日啓時雍。", "高才掞雅什，顧己濫朋從。", "因茲仰積善，靈華庶可逢。"]'),
('62955f72-a945-4ff8-84df-c93c73b4c803','與英才言聚賦得昇天行','慧淨','唐','唐诗','tang','','[]','馭風過閬苑，控鶴下瀛洲。',48,'全唐诗/poet.tang.44000.json','["馭風過閬苑，控鶴下瀛洲。", "欲採三芝秀，先從千仞遊。", "駕鳳吟虛管，乘槎泛淺流。", "頹齡一已駐，方驗大椿秋。"]'),
('3205a2f2-b86f-4f86-9003-dc338f8f839d','和盧贊府遊紀國道場','慧淨','唐','唐诗','tang','','[]','日光通漢室，星彩晦周朝。',72,'全唐诗/poet.tang.44000.json','["日光通漢室，星彩晦周朝。", "法城從此構，香閣本岧嶢。", "株盤仰承露，剎鳳俯摩霄。", "落照侵虛牖，長虹拖跨橋。", "高才暫騁目，雲藻隨飄颻。", "欲追千里驥，終是謝連鑣。"]'),
('b0b15cef-b06c-47a2-bf3a-99575ce1310c','冬日普光寺臥疾值雪簡諸舊遊','慧淨','唐','唐诗','tang','','[]','臥疴苦留滯，闢戶望遙天。',72,'全唐诗/poet.tang.44000.json','["臥疴苦留滯，闢戶望遙天。", "寒雲舒復卷，落雪斷還連。", "凝華照書閣，飛素涴琴弦。", "迴飄洛神賦，皎映齊紈篇。", "縈階如鶴舞，拂樹似花鮮。", "徒賞豐年瑞，沈憂終自憐。"]'),
('6ac5494d-4d47-47e0-bd5d-7ee0073040a3','雜言','慧淨','唐','唐诗','tang','','[]','觀化祇山頂，流睇古王城。',344,'全唐诗/poet.tang.44000.json','["觀化祇山頂，流睇古王城。", "萬載池猶潔，千年苑尚清。", "髣髴影堅路，摧殘廣脇楹。", "七寶仙臺亡舊迹，四彩天花絕雨聲。", "聲華日以遠，自恨生何晚。", "既傷火宅眩中門，還嗟寶渚迷長坂。", "步陟平郊望，心遊七海上。", "擾擾三界溺邪津，渾渾萬品忘真匠。", "唯有能仁獨圓悟，廓塵靜浪開玄路。", "創逢肌命棄身城，更爲求人崩意樹。", "持囊畢契戒珠淨，被甲要心忍衣固。", "三祇不倦陵二車，一足忘勞超九數。", "定瀲江清沐久結，智劍霜凝斬新霧。", "無邊大劫無不修，六時愍生遵六度。", "度有流光功德收，金河示滅歸常住。", "鶴林權唱演功周，聖德佳音傳餘響。", "龍宮秘典海中探，石室真言山處仰。", "流教在茲辰，傳芳代有人。", "沙河雪嶺迷朝徑，巨海鴻崖亂夜津。", "入萬死，求一生。", "投針偶穴非同喻，束馬懸車豈等程。", "不徇今身樂，無祈後代榮。", "誓舍危軀追勝義，咸希畢契傳燈情。", "勞歌勿復陳，延眺且周巡。"]'),
('4ccdc8ef-6a4c-4198-b119-8a1359612bfb','三不爲篇 一','海順','唐','唐诗','tang','','[]','我欲偃文修武，身死名存。',86,'全唐诗/poet.tang.44000.json','["我欲偃文修武，身死名存。", "斫石通道，祈井流泉。", "君肝在內，我身處邊。", "荆軻拔劍，毛遂捧盤。", "不爲則已，爲則不然。", "將恐兩虎共鬬，勢不俱全。", "永□今好，長絕來怨。", "是以返跡荒徑，息影柴門。"]'),
('cb6bdf47-c48d-46d1-aa15-c571908207eb','三不爲篇 二','海順','唐','唐诗','tang','','[]','我欲刺股錐刃，懸頭屋梁。',86,'全唐诗/poet.tang.44000.json','["我欲刺股錐刃，懸頭屋梁。", "書臨雪彩，牒映螢光。", "一朝鵬舉，萬里鸞翔。", "縱任才辯，遊說君王。", "高車反邑，衣錦還鄉。", "將恐鳥殘以羽，蘭折由芳。", "籠餐詎貴，鉤餌難嘗。", "是以高巢林藪，深穴池塘。"]'),
('43a5f281-b2df-4c0c-a889-1eea06884407','三不爲篇 三','海順','唐','唐诗','tang','','[]','我欲衒才鬻德，入市趨朝。',86,'全唐诗/poet.tang.44000.json','["我欲衒才鬻德，入市趨朝。", "四衆瞻仰，三槐附交。", "標形引勢，身達名超。", "箱盈綺服，廚富甘肴。", "諷揚弦管，詠美歌謠。", "將恐塵栖弱草，露宿危條。", "無過日旦，靡越風朝。", "是以還傷樂淺，非惟苦遙。"]'),
('fd712ed8-c1c9-4b03-96f5-15a8240ec9a0','出賜玄奘衲袈裟衣應制','道恭','唐','唐诗','tang','','[]','福田資象德，聖種理幽薰。',48,'全唐诗/poet.tang.44000.json','["福田資象德，聖種理幽薰。", "不持金作縷，還用綵成文。", "朱青自掩映，翠綺相氤氳。", "獨有離離葉，恒向稻畦分。"]'),
('ab142b51-8147-42f3-bb61-382dd0e765b4','設缸面酒欵蕭翼探得來字','辨才','唐','唐诗','tang','','[]','初醞一缸開，新知萬里來。',48,'全唐诗/poet.tang.44000.json','["初醞一缸開，新知萬里來。", "披雲同落寞，步月共裴回。", "夜久孤琴思，風長旅鴈哀。", "非君有秘術，誰照不然灰。"]'),
('88188de0-57ed-4879-aef1-08a6066d7a5f','書遺文後','僧鳳','唐','唐诗','tang','','[]','苦哉黑闇女，樂矣功德天。',48,'全唐诗/poet.tang.44000.json','["苦哉黑闇女，樂矣功德天。", "智者俱不受，愚夫納二邊。", "我奉能仁教，歸依彌勒前。", "願闡摩訶衍，成就那羅延。"]'),
('668f092a-f60d-429c-8f46-688c310869c5','譏韋玎吟以韋字爲韻','利涉','唐','唐诗','tang','','[]','我之佛法是無爲，何故今朝得有爲。',32,'全唐诗/poet.tang.44000.json','["我之佛法是無爲，何故今朝得有爲。", "無韋始得三數載，不知此復是何韋。"]'),
('859cf103-303f-4452-94d8-178d22c6fa44','別三輔諸僧','道會','唐','唐诗','tang','','[]','去住俱爲客，分悲損性情。',24,'全唐诗/poet.tang.44000.json','["去住俱爲客，分悲損性情。", "共作無期別，誰能訪死生。"]'),
('066d1bb6-9b8c-4a8b-9443-fcaab86af01b','贈王仙柯','中寤','唐','唐诗','tang','','[]','瞻思不及望仙兄，早晚昇霞入太清。',64,'全唐诗/poet.tang.44000.json','["瞻思不及望仙兄，早晚昇霞入太清。", "手種一株松未老，爐燒九轉藥新成。", "心中已得黃庭術，頭上應無白髮生。", "異日却歸華表語，待教凡俗普聞名。"]'),
('b2ccc56c-ce16-4308-8bc7-25f602fc4ea0','在西國懷王舍城','義淨','唐','唐诗','tang','','[]','遊，愁。',60,'全唐诗/poet.tang.44000.json','["遊，愁。", "赤縣遠，丹思抽。", "鷲嶺寒風駛，龍河激水流。", "既喜朝聞日復日，不覺頹年秋更秋。", "已畢耆山本願城難遇，終望持經振錫住神州。"]'),
('2acb6abe-c974-4d64-9742-b54d7fa2b25a','與無行禪師同遊鷲嶺瞻奉既訖遐眺鄉關無任殷憂聊述所懷爲雜言詩','義淨','唐','唐诗','tang','','[]','觀化祇山頂，流睇古王城。',344,'全唐诗/poet.tang.44000.json','["觀化祇山頂，流睇古王城。", "萬載池猶潔，千年苑尚清。", "髣髴影堅路，摧殘廣脇𡺡。", "七寶仙臺亡舊跡，四彩天花絕雨聲。", "聲華日以遠，自恨生何晚。", "既傷火宅眩中門，還嗟寶渚迷長坂。", "步陟平郊望，心遊七海上。", "擾擾三界溺邪津，渾渾萬品亡真匠。", "唯有能仁獨圓悟，廓塵靜浪開玄路。", "創逢肌命棄身城，更爲求人崩意樹。", "持囊畢契戒珠淨，被甲要心忍衣固。", "三祇不倦陵二車，一足忘勞超九數。", "定瀲江清沐久結，智劍霜凝斬新霧。", "無邊大劫無不脩，六時愍生遵六度。", "度有流光功德收，金河示滅歸常住。", "鶴林權唱演功周，聖徒往昔傳餘響。", "龍宮秘典海中探，石室真言山處仰。", "流教在茲辰，傳芳代有人。", "沙河雪嶺迷朝徑，巨海鴻崖亂夜津。", "入萬死，求一生。", "投針偶穴非同喻，束馬懸車豈等程。", "不徇今身樂，無祈後代榮。", "誓捨危軀追勝義，咸希畢契傳燈情。", "勞歌勿復陳，延眺且周巡。"]'),
('7c30ebf0-782f-4834-bae4-5d7ac875d3bf','玄逵律師言離廣府還望桂林去留愴然自述贈懷','義淨','唐','唐诗','tang','','[]','標心之梵宇，運想入仙洲。',48,'全唐诗/poet.tang.44000.json','["標心之梵宇，運想入仙洲。", "嬰痼乖同好，沈情阻若抽。", "葉落乍難聚，情離不可收。", "何日乘杯至，詳觀演法流。"]'),
('2da439ef-f602-417e-ac12-2139edb7a6d0','余以咸亨元年在西京尋聽于時與幷部處一法師萊州弘禕論師更有三二諸德同契鷲嶺標心覺樹然而一公屬母親之年老遂懷戀於幷州禕師遇玄瞻於江寧乃敘情於安養玄逵既到廣府復阻先期唯與晉州小僧善行同去神州故友索爾分飛印度新知冥焉未會此時躑躅難以爲懷戲擬四愁聊題兩絕 一','義淨','唐','唐诗','tang','','[]','我行之數萬，愁緒百重思。',24,'全唐诗/poet.tang.44000.json','["我行之數萬，愁緒百重思。", "那教六尺影，獨步五天陲。"]'),
('4278df7c-9e03-49ed-b222-ff79c952a6ec','余以咸亨元年在西京尋聽于時與幷部處一法師萊州弘禕論師更有三二諸德同契鷲嶺標心覺樹然而一公屬母親之年老遂懷戀於幷州禕師遇玄瞻於江寧乃敘情於安養玄逵既到廣府復阻先期唯與晉州小僧善行同去神州故友索爾分飛印度新知冥焉未會此時躑躅難以爲懷戲擬四愁聊題兩絕 二','義淨','唐','唐诗','tang','','[]','上將可陵師，匹士志難移。',24,'全唐诗/poet.tang.44000.json','["上將可陵師，匹士志難移。", "如論惜短命，何得滿長祇。"]'),
('f40ae313-b455-4baf-af9b-459dd7ebd019','西域寺','義淨','唐','唐诗','tang','','[]','衆美仍羅列，羣英已古今。',24,'全唐诗/poet.tang.44000.json','["衆美仍羅列，羣英已古今。", "也知生死分，那得不傷心。"]'),
('eaa8fe9b-4ec4-422d-ba0b-f6de9adbceb7','道希法師求法西域終於菴摩羅跋國後因巡禮希公住房傷其不幸聊題一絕','義淨','唐','唐诗','tang','','[]','百苦忘勞獨進影，四恩在念契流通。',32,'全唐诗/poet.tang.44000.json','["百苦忘勞獨進影，四恩在念契流通。", "如何未盡傳燈志，溘然于此遇途窮。"]'),
('de94891c-6ce5-4e0e-87a1-9b5b6c6fd005','行路難','寶月','唐','唐诗','tang','','[]','君不見孤鴈關外發，酸嘶度楊越。',103,'全唐诗/poet.tang.44000.json','["君不見孤鴈關外發，酸嘶度楊越。", "空城客子心腸斷，幽閨思婦氣欲絕。", "凝霜夜下拂羅衣，浮雲中斷開明月。", "夜夜遙遙徒相思，年年望望情不歇。", "取我匣中青銅鏡，情人爲我除白髮。", "行路難，行路難。", "夜聞南城漢使度，使我流淚憶長安。"]'),
('d2b70446-b236-4bf1-a586-7931f512f6cb','老僧','景雲','唐','唐诗','tang','','[]','日照西山雪，老僧門始開。',48,'全唐诗/poet.tang.44000.json','["日照西山雪，老僧門始開。", "凍瓶粘柱礎，宿火陷爐灰。", "童子病歸去，鹿麑寒入來。", "齋鐘知漸近，枝鳥下生臺。"]'),
('4b8f99cb-824b-491d-8720-ecf99d17879c','谿叟','景雲','唐','唐诗','tang','','[]','谿翁居處靜，谿鳥入門飛。',48,'全唐诗/poet.tang.44000.json','["谿翁居處靜，谿鳥入門飛。", "早起釣魚去，夜深乘月歸。", "露香菰米熟，煙煖荇絲肥。", "瀟灑塵埃外，扁舟一草衣。"]'),
('5ae3c3c7-7e29-4302-9d84-b7039f73fc9c','畫松','景雲','唐','唐诗','tang','','[]','畫松一似真松樹，且待尋思記得無。',32,'全唐诗/poet.tang.44000.json','["畫松一似真松樹，且待尋思記得無。", "曾在天台山上見，石橋南畔第三株。"]'),
('a254b5a9-0c34-42f8-99b0-92cf33bae131','送戴三徵君還谷口舊居','理瑩','唐','唐诗','tang','','[]','巖穴多遺秀，弓車屢遠招。',120,'全唐诗/poet.tang.44000.json','["巖穴多遺秀，弓車屢遠招。", "周王尊渭叟，潁客傲唐堯。", "出處天波洽，關河地勢遙。", "瞻星吳郡夜，作霧華山朝。", "清論虛重席，閑居挂一瓢。", "漁歌思坐酌，宸渥寵行軺。", "春爲荷裳煖，霜因葛履消。", "層崖懸瀑溜，萬壑振清飆。", "谷鳥猶遷木，場駒正食苗。", "謝安何日起，台鼎佇君調。"]'),
('07589265-3a3f-4820-9d77-ccbd10c013b4','送童子下山','金地藏','唐','唐诗','tang','','[]','空門寂寞汝思家，禮別雲房下九華。',64,'全唐诗/poet.tang.44000.json','["空門寂寞汝思家，禮別雲房下九華。", "愛向竹欄騎竹馬，懶於金地聚金沙。", "添瓶澗底休招月，烹茗甌中罷弄花。", "好去不須頻下淚，老僧相伴有煙霞。"]'),
('92079c52-ad70-4ab7-9ca9-bb921fd87199','題張僧繇醉僧圖','懷素','唐','唐诗','tang','','[]','人人送酒不曾沽，終日松間挂一壺。',32,'全唐诗/poet.tang.44000.json','["人人送酒不曾沽，終日松間挂一壺。", "草聖欲成狂便發，真堪畫入醉僧圖。"]'),
('150641ec-fdac-4c4b-b45d-7c8ddadf5e98','寄衡嶽僧','懷素','唐','唐诗','tang','','[]','祝融高座對寒峰，雲水昭丘幾萬重。',32,'全唐诗/poet.tang.44000.json','["祝融高座對寒峰，雲水昭丘幾萬重。", "五月衲衣猶近火，起來白鶴冷青松。"]'),
('6cadba7f-f388-457c-b615-f7397796da0f','酬皇甫冉西陵見寄','靈一','唐','唐诗','tang','','[]','西陵潮信滿，島嶼沒中流。',48,'全唐诗/poet.tang.44000.json','["西陵潮信滿，島嶼沒中流。", "越客依風水，相思南渡頭。", "寒光生極浦，落日映滄洲。", "何事揚帆去，空驚海上鷗。"]'),
('ad51183f-d0f6-4e7e-8aa2-cce71c4dfd70','溪行即事','靈一','唐','唐诗','tang','','[]','近夜山更碧，入林溪轉清。',48,'全唐诗/poet.tang.44000.json','["近夜山更碧，入林溪轉清。", "不知伏牛事，潭洞何從橫。", "野岸煙初合，平湖月未生。", "孤舟屢失道，但聽秋泉聲。"]'),
('2efc0d5b-e5cc-4a72-a6c8-edb76195778c','棲霞山夜坐','靈一','唐','唐诗','tang','','[]','山頭戒壇路，幽映雪岩側。',48,'全唐诗/poet.tang.44000.json','["山頭戒壇路，幽映雪岩側。", "四面青石牀，一峰苔蘚色。", "松風靜復起，月影開還黑。", "何獨乘夜來，殊非晝所得。"]'),
('cbbbc1cb-9e28-4758-a8d8-50d360249c3d','宿天柱觀','靈一','唐','唐诗','tang','','[]','石室初投宿，仙翁喜暫容。',48,'全唐诗/poet.tang.44000.json','["石室初投宿，仙翁喜暫容。", "花源隔水見，洞府過山逢。", "泉湧堦前地，雲生戶外峰。", "中宵自入定，非是欲降龍。"]'),
('a37d754c-e93f-461c-9c91-c92308277ac1','酬皇甫冉將赴無錫於雲門寺贈別','靈一','唐','唐诗','tang','','[]','湖南通古寺，來往意無涯。',48,'全唐诗/poet.tang.44000.json','["湖南通古寺，來往意無涯。", "欲識雲門路，千峰到若耶。", "春山子敬宅，古木謝敷家。", "自可長偕隱，那言相去賒。"]'),
('5cba3f40-7528-4901-b67a-3069257b7b68','宜豐新泉','靈一','唐','唐诗','tang','','[]','泉源新湧出，洞澈映纖雲。',48,'全唐诗/poet.tang.44000.json','["泉源新湧出，洞澈映纖雲。", "稍落芙蓉沼，初淹苔蘚文。", "素將空意合，淨與衆流分。", "每到清宵月，泠泠夢裏聞。"]'),
('bfa5282c-bdac-4770-9660-3212c5ed1d88','靜林精舍','靈一','唐','唐诗','tang','','[]','靜林溪路遠，蕭帝有遺蹤。',48,'全唐诗/poet.tang.44000.json','["靜林溪路遠，蕭帝有遺蹤。", "水擊羅浮磬，山鳴于闐鐘。", "燈傳三世火，樹老萬株松。", "無數煙霞色，空聞昔臥龍。"]'),
('6c55455c-6682-4f82-af61-b122c047b1ce','江行寄張舍人','靈一','唐','唐诗','tang','','[]','客程終日風塵苦，蓬轉還家未有期。',64,'全唐诗/poet.tang.44000.json','["客程終日風塵苦，蓬轉還家未有期。", "林色曉分殘雪後，角聲寒奏落帆時。", "月高星使東看遠，雲破霜鴻北度遲。", "流蕩此心難共說，千峰澄霽隔瓊枝。"]'),
('36ea9a24-b6ae-41b6-a9e1-8c65bd05a30a','送王穎悟歸左綿','靈一','唐','唐诗','tang','','[]','客意天南興已闌，不堪言別向仙官。',64,'全唐诗/poet.tang.44000.json','["客意天南興已闌，不堪言別向仙官。", "夢搖玉珮隨旄節，心到金華憶杏壇。", "荒郊極望歸雲盡，瘦馬空嘶落日殘。", "想得故山青靄裏，泉聲入夜獨潺潺。"]'),
('9b086fb1-24ae-44ff-8483-57392b349f9a','安公','靈一','唐','唐诗','tang','','[]','彌天稱聖哲，象法初繄賴。',72,'全唐诗/poet.tang.44000.json','["彌天稱聖哲，象法初繄賴。", "弘道識行藏，匡時知進退。", "秦王輕與舉，習生重酬對。", "學文古篆中，義顯心經內。", "法服應華夏，金言流海岱。", "西方浮雲間，更陪龍華會。"]'),
('d218dcc3-4b06-4df8-a786-a6da87b83343','林公','靈一','唐','唐诗','tang','','[]','支公信高逸，久向山林住。',72,'全唐诗/poet.tang.44000.json','["支公信高逸，久向山林住。", "時將孫許遊，豈以形骸遇。", "幸辭天子詔，復覽名臣疏。", "西晉尚虛無，南朝久淪悞。", "因談老莊意，乃盡逍遙趣。", "誰爲竹林賢，風流相比附。"]'),
('2fd77559-46a5-42d2-9798-697d53fe1617','遠公','靈一','唐','唐诗','tang','','["\u5e90\u5c71"]','遠公逢道安，一朝棄儒服。',72,'全唐诗/poet.tang.44000.json','["遠公逢道安，一朝棄儒服。", "真機久消歇，世教空拘束。", "誓入羅浮中，遂棲廬山曲。", "禪經初纂定，佛語新名目。", "鉢帽絕朝宗，簪裾翻拜伏。", "東林多隱士，爲我辭榮祿。"]'),
('496481f2-d29b-415d-bc50-be2b7828ed0f','雨後欲尋天目山問元駱二公溪路','靈一','唐','唐诗','tang','','[]','昨夜雲生天井東，春山一雨一回風。',32,'全唐诗/poet.tang.44000.json','["昨夜雲生天井東，春山一雨一回風。", "林花併逐溪流下，欲上龍池通不通。"]'),
('a259dbe2-8920-467f-a8ee-8b05c2aed4b1','題僧院','靈一','唐','唐诗','tang','','[]','虎溪閑月引相過，帶雪松枝挂薜蘿。',32,'全唐诗/poet.tang.44000.json','["虎溪閑月引相過，帶雪松枝挂薜蘿。", "無限青山行欲盡，白雲深處老僧多。"]'),
('2f3625d5-e292-474f-8d7b-5b60a5f8bb52','宿靜林寺','靈一','唐','唐诗','tang','','[]','山寺門前多古松，溪行欲到已聞鐘。',32,'全唐诗/poet.tang.44000.json','["山寺門前多古松，溪行欲到已聞鐘。", "中宵引領尋高頂，月照雲峰凡幾重。"]'),
('2a4ba762-2524-4dc1-b3e4-c83755418f16','再還宜豐寺','靈一','唐','唐诗','tang','','[]','再尋招隱地，重會息心期。',48,'全唐诗/poet.tang.44000.json','["再尋招隱地，重會息心期。", "樵客問歸日，山僧記別時。", "野雲陰遠甸，秋雨漲前陂。", "勿謂探形勝，吾今不好奇。"]'),
('e6c19e01-fde5-437d-9c29-9eb5b8fe87d1','春日山齋','靈一','唐','唐诗','tang','','[]','野逕東風起，山扉度日開。',48,'全唐诗/poet.tang.44000.json','["野逕東風起，山扉度日開。", "晴光拆紅萼，流水長青苔。", "逋客殊未去，芳時已再來。", "非關戀春草，自是欲裴回。"]'),
('99f29e16-c8cc-44c4-9986-8b78103c48aa','留別忠州故人','靈一','唐','唐诗','tang','','[]','一身無定處，萬里獨銷魂。',48,'全唐诗/poet.tang.44000.json','["一身無定處，萬里獨銷魂。", "芳草迷歸路，春流滴淚痕。", "幾時休旅食，何夜宿江村。", "欲識相思苦，空山啼暮猨。"]'),
('1677ecc0-38c9-4ef7-8bd0-7c95de73498a','送別','靈一','唐','唐诗','tang','','[]','憑高莫送遠，看欲斷歸心。',48,'全唐诗/poet.tang.44000.json','["憑高莫送遠，看欲斷歸心。", "別恨啼猨苦，相思流水深。", "翠雲南澗影，丹桂晚山陰。", "若未來雙鵠，遼城何更尋。"]'),
('11223579-1400-4587-8a47-15baae393c50','送冽寺主之京迎禪和尚','靈一','唐','唐诗','tang','','[]','禪門居此地，瞻望在虛空。',48,'全唐诗/poet.tang.44000.json','["禪門居此地，瞻望在虛空。", "水國月未上，蒼生如夢中。", "上人知機士，瓶錫慰樊籠。", "彼土諸梵衆，嗟君揚道風。"]'),
('1d2d3a7c-4f70-4194-b13b-89956213a605','送王法師之西川','靈一','唐','唐诗','tang','','[]','旅遊無近遠，要自別魂銷。',48,'全唐诗/poet.tang.44000.json','["旅遊無近遠，要自別魂銷。", "官柳鄉愁亂，春山客路遙。", "伴行芳草遠，緣興野花飄。", "計日功成後，還將輔聖朝。"]'),
('10d43809-955c-42c1-b1a5-595ab73c3292','送範律師往果州','靈一','唐','唐诗','tang','','[]','終南千古後，獨爾繼卿名。',48,'全唐诗/poet.tang.44000.json','["終南千古後，獨爾繼卿名。", "離障非今日，脩因是幾生。", "亂峰寒影暮，深澗野流清。", "遠客歸心苦，難爲此別情。"]'),
('10fd5f1a-f4b0-44de-a2fe-fe0ea9ec0452','送明素上人歸楚覲省','靈一','唐','唐诗','tang','','[]','能將疎懶背時人，不厭孤萍任此身。',64,'全唐诗/poet.tang.44000.json','["能將疎懶背時人，不厭孤萍任此身。", "江上昔年同出處，天涯今日共風塵。", "平湖舊隱應殘雪，芳草歸心未隔春。", "前路倍憐多勝事，到家知慶綵衣新。"]'),
('12c4c59c-1731-4a08-8451-b6196514c7fb','項王廟','靈一','唐','唐诗','tang','','["\u5e26\u6709\u5730\u540d", "\u548f\u53f2\u6000\u53e4", "\u5730\u540d"]','緬想咸陽事可嗟，楚歌哀怨思無涯。',64,'全唐诗/poet.tang.44000.json','["緬想咸陽事可嗟，楚歌哀怨思無涯。", "八千子弟歸何處，萬里鴻溝屬漢家。", "弓斷陣前爭日月，血流垓下定龍蛇。", "拔山力盡烏江水，今日悠悠空浪花。"]'),
('687672f5-42e2-44b3-b628-4945e3e13967','酬陳明府舟中見贈','靈一','唐','唐诗','tang','','[]','長溪通夜靜，素舸與人閑。',48,'全唐诗/poet.tang.44000.json','["長溪通夜靜，素舸與人閑。", "月影沈秋水，風聲落暮山。", "稻花千頃外，蓮葉兩河間。", "陶令多真意，相思一解顏。"]'),
('3dabe898-2356-4429-8e68-e6d63793a231','題東蘭若','靈一','唐','唐诗','tang','','[]','上入禪室路裴回，萬木清陰向日開。',64,'全唐诗/poet.tang.44000.json','["上入禪室路裴回，萬木清陰向日開。", "寒竹影侵行逕石，秋風聲入誦經臺。", "閑雲不繫從舒卷，狎鳥無機任往來。", "更惜片陽談妙理，歸時莫待暝鐘催。"]'),
('55f12ad3-7e94-457d-a19b-17d57fbe3a8b','送朱放','靈一','唐','唐诗','tang','','[]','苦見人間世，思歸洞裏天。',24,'全唐诗/poet.tang.44000.json','["苦見人間世，思歸洞裏天。", "縱令山鳥語，不廢野人眠。"]'),
('99a54334-fe8d-4855-9778-00d5932e37c7','歸岑山過惟審上人別業','靈一','唐','唐诗','tang','','[]','禪客無心憶薜蘿，自然行徑向山多。',32,'全唐诗/poet.tang.44000.json','["禪客無心憶薜蘿，自然行徑向山多。", "知君欲問人間事，始與浮雲共一過。"]'),
('0be3b57d-e63b-4c99-815d-d431059df121','於潛道中呈元八處士','靈一','唐','唐诗','tang','','[]','苕水灘行淺，潛州路漸深。',36,'全唐诗/poet.tang.44000.json','["苕水灘行淺，潛州路漸深。", "參差遠岫色，迢遞野人心。", "凍澗冰難釋，秋山日易陰。"]'),
('2453d4ef-e09d-4430-8a90-baaa296fb18a','送殷判官歸上都','靈一','唐','唐诗','tang','','[]','漾舟雲路客，來過夕陽時。',48,'全唐诗/poet.tang.44000.json','["漾舟雲路客，來過夕陽時。", "向背堪遺恨，逢迎宿未期。", "水容愁暮急，花影動春遲。", "別後王孫草，青青入夢思。"]'),
('9c35fd6f-e6d5-4e80-988d-c8e49214b0c9','贈別皇甫曾','靈一','唐','唐诗','tang','','[]','幽人從遠岳，過客愛春山。',48,'全唐诗/poet.tang.44000.json','["幽人從遠岳，過客愛春山。", "高駕能相送，孤遊且未還。", "紫苔封井石，綠竹掩柴關。", "若到雲峰外，齊心去住間。"]'),
('bf3f8a1c-6ec7-4128-9f03-9f75d8f4f34c','送陳允初卜居麻園','靈一','唐','唐诗','tang','','[]','欲向麻源隱，能尋謝客蹤。',48,'全唐诗/poet.tang.44000.json','["欲向麻源隱，能尋謝客蹤。", "空山幾千里，幽谷第三重。", "茅宇寧須葺，荷衣不待縫。", "因君見往事，爲我謝喬松。"]'),
('2825aaf0-0489-43a1-ae1a-2056f12e428f','秋題劉逸人林泉','靈一','唐','唐诗','tang','','[]','涼飆亂黃葉，遲客橘陰清。',48,'全唐诗/poet.tang.44000.json','["涼飆亂黃葉，遲客橘陰清。", "蘿徑封行跡，雲門閉野情。", "零林秋露響，穿竹暮煙輕。", "莫戀幽棲地，懷安却敗名。"]'),
('f57f07a2-433b-47cc-9c85-dae1683d1043','自大林與韓明府歸郭中精舍','靈一','唐','唐诗','tang','','[]','野客同舟楫，相攜復一歸。',48,'全唐诗/poet.tang.44000.json','["野客同舟楫，相攜復一歸。", "孤煙生暮景，遠岫帶春暉。", "不道還山是，誰云向郭非。", "禪門有通隱，喧寂共忘機。"]'),
('b786421e-8065-4df8-bcf9-8eb9e9dfe544','同使君宿大梁驛','靈一','唐','唐诗','tang','','["\u5e90\u5c71"]','旌旗江上出，花外捲簾空。',48,'全唐诗/poet.tang.44000.json','["旌旗江上出，花外捲簾空。", "夜色臨城月，春寒度水風。", "雖然行李別，且喜語音同。", "若問匡廬事，終身媿遠公。"]'),
('52c9a166-c7c9-4a7b-9fc0-40a78f7c810c','題黃公陶翰別業','靈一','唐','唐诗','tang','','[]','聞說花源堪避秦，幽尋數月不逢人。',64,'全唐诗/poet.tang.44000.json','["聞說花源堪避秦，幽尋數月不逢人。", "煙霞洞裏無雞犬，風雨林間有鬼神。", "黃公石上三芝秀，陶令門前五柳春。", "醉臥白雲閑入夢，不知何物是吾身。"]'),
('11d45373-18b3-4358-a460-7238dbce4ea7','哭衛尚書','靈一','唐','唐诗','tang','','[]','畫戟重門楚水陰，天涯欲暮共傷心。',64,'全唐诗/poet.tang.44000.json','["畫戟重門楚水陰，天涯欲暮共傷心。", "南荆雙戟痕猶在，北斗孤魂望已深。", "蓮花幕下悲風起，細柳營邊曉月臨。", "有路茫茫向誰問，感君空有淚霑襟。"]'),
('d3599744-2346-4d5d-861f-f70fb6c64256','贈靈澈禪師','靈一','唐','唐诗','tang','','[]','禪師來往翠微間，萬里千峰到剡山。',32,'全唐诗/poet.tang.44000.json','["禪師來往翠微間，萬里千峰到剡山。", "何時共到天台裏，身與浮雲處處閑。"]'),
('f3eef5d5-716a-4604-9c5f-e43622122eb2','將出宜豐寺留題山房','靈一','唐','唐诗','tang','','[]','池上蓮荷不自開，山中流水偶然來。',32,'全唐诗/poet.tang.44000.json','["池上蓮荷不自開，山中流水偶然來。", "若言聚散定由我，未是回時那得回。"]'),
('48c1155c-db42-4da7-9fe5-a3e5ff014f55','妙樂觀','靈一','唐','唐诗','tang','','[]','王喬所居空山觀，白雲至今凝不散。',96,'全唐诗/poet.tang.44000.json','["王喬所居空山觀，白雲至今凝不散。", "壇場月路幾千年，往往吹笙下天半。", "瀑布西行過石橋，黃精採根還採苗。", "忽見一人檠茶碗，篸花昨夜風吹滿。", "自言家處在東坡，白犬相隨邀我過。", "松間石上有棊局，能使樵人爛斧柯。"]'),
('c27027fb-17c5-4b5c-89de-c2ee9bccbbc8','與元居士青山潭飲茶','靈一','唐','唐诗','tang','','[]','野泉煙火白雲間，坐飲香茶愛此山。',32,'全唐诗/poet.tang.44000.json','["野泉煙火白雲間，坐飲香茶愛此山。", "巖下維舟不忍去，青溪流水暮潺潺。"]'),
('b157fafc-0570-4363-bd58-956ab9996f19','送人得蕩子歸倡婦','靈一','唐','唐诗','tang','','[]','垂涕憑回信，爲語柳園人。',24,'全唐诗/poet.tang.44000.json','["垂涕憑回信，爲語柳園人。", "情知獨難守，又是一陽春。"]'),
('c9d80fbd-8ad0-428b-bef1-9f80dc33859e','句','靈一','唐','唐诗','tang','','[]','濾泉侵月起，掃徑避蟲行。',12,'全唐诗/poet.tang.44000.json','["濾泉侵月起，掃徑避蟲行。"]'),
('bb3baba2-08b8-41f7-93c1-2556ccc9cd03','聽鶯歌','靈澈','唐','唐诗','tang','','[]','新鶯傍簷曉更悲，孤音清泠囀素枝。',170,'全唐诗/poet.tang.44000.json','["新鶯傍簷曉更悲，孤音清泠囀素枝。", "口邊血出語未盡，豈是怨恨人不知。", "不食枯桑葚，不銜苦李花。", "偶然弄樞機，婉轉凌煙霞。", "衆雛飛鳴何跼促，自覘游蜂啄枯木。", "玄猨何事朝夜啼，白鷺長在汀洲宿。", "黑鵰黃鶴豈不高，金籠玉鉤傷羽毛。", "三江七澤去不得，風煙日暮生波濤。", "飛去來，莫上高城頭，莫下空園裏。", "城頭鴟鳥拾羶腥，空園燕雀爭泥滓。", "願當結舌含白雲，五月六月一聲不可聞。"]'),
('d8f7faec-e05c-41d0-8274-563d67bb1ba2','歸湖南作','靈澈','唐','唐诗','tang','','[]','山邊水邊待月明，暫向人間借路行。',32,'全唐诗/poet.tang.44000.json','["山邊水邊待月明，暫向人間借路行。", "如今還向山邊去，只有湖水無行路。"]'),
('05eaa52a-410f-49fa-8b61-64993e5f99fe','初到汀州','靈澈','唐','唐诗','tang','','[]','初放到滄洲，前心詎解愁。',48,'全唐诗/poet.tang.44000.json','["初放到滄洲，前心詎解愁。", "舊交容不拜，臨老學梳頭。", "禪室白雲去，故山明月秋。", "幾年猶在此，北戶水南流。"]'),
('5eaa230b-69e8-41d4-8799-1af8ab21e870','九日和于使君思上京親故','靈澈','唐','唐诗','tang','','[]','清晨有高會，賓從出東方。',48,'全唐诗/poet.tang.44000.json','["清晨有高會，賓從出東方。", "楚俗風煙古，汀洲草木涼。", "山情來遠思，菊意在重陽。", "心憶華池上，從容鴛鷺行。"]'),
('f81e83bd-da8a-4732-8ccc-6598cfab1567','送道虔上人游方','靈澈','唐','唐诗','tang','','[]','律儀通外學，詩思入玄關。',48,'全唐诗/poet.tang.44000.json','["律儀通外學，詩思入玄關。", "煙景隨緣到，風姿與道閑。", "貫花留淨室，呪水度空山。", "誰識浮雲意，悠悠天地間。"]'),
('182ce674-154a-4774-9155-f52eb9be7d58','送鑒供奉歸蜀寧親','靈澈','唐','唐诗','tang','','[]','林間出定戀庭闈，聖主恩深暫許歸。',64,'全唐诗/poet.tang.44000.json','["林間出定戀庭闈，聖主恩深暫許歸。", "雙樹欲辭金錫冷，四花猶向玉階飛。", "梁山拂漢分清境，蜀雪和煙惹翠微。", "此去不須求綵服，紫衣全勝老萊衣。"]'),
('d75d10f2-7355-4692-b8be-fb480ec5bfd4','天姥岑望天台山','靈澈','唐','唐诗','tang','','[]','天台衆峯外，華頂當寒空。',24,'全唐诗/poet.tang.44000.json','["天台衆峯外，華頂當寒空。", "有時半不見，崔嵬在雲中。"]'),
('44407cb2-b65a-4b45-9d9d-490d27103f4f','遠公墓','靈澈','唐','唐诗','tang','','[]','古墓石稜稜，寒雲晚景凝。',24,'全唐诗/poet.tang.44000.json','["古墓石稜稜，寒雲晚景凝。", "空悲虎溪月，不見鴈門僧。"]'),
('fb83d515-8c51-4424-8e60-5b8d2bda2614','宿東林寺','靈澈','唐','唐诗','tang','','[]','天寒猛虎叫巖雪，林下無人空有月。',32,'全唐诗/poet.tang.44000.json','["天寒猛虎叫巖雪，林下無人空有月。", "千年像教今不聞，焚香獨爲鬼神說。"]'),
('15636371-7eb4-4a51-b5be-ad9c30842a99','簡寂觀','靈澈','唐','唐诗','tang','','[]','古松古柏巖壁間，猨攀鶴巢古枝折。',32,'全唐诗/poet.tang.44000.json','["古松古柏巖壁間，猨攀鶴巢古枝折。", "五月有霜六月寒，時見山翁來取雪。"]'),
('fc5ea508-8105-499e-abef-fd1aea6e6570','元日觀郭將軍早朝','靈澈','唐','唐诗','tang','','[]','欲曙九衢人更多，千條香燭照星河。',32,'全唐诗/poet.tang.44000.json','["欲曙九衢人更多，千條香燭照星河。", "今朝始見金吾貴，車馬縱橫避玉珂。"]'),
('70df7406-953a-4775-b8b3-cb9aec4fc282','東林寺酬韋丹刺史','靈澈','唐','唐诗','tang','','[]','年老心閑無外事，麻衣草座亦容身。',32,'全唐诗/poet.tang.44000.json','["年老心閑無外事，麻衣草座亦容身。", "相逢盡道休官好，林下何曾見一人。"]'),
('c9f86105-9b01-4a6e-85d7-61873c59af38','東林寺寄包侍御','靈澈','唐','唐诗','tang','','[]','古殿清陰山木春，池邊跂石一觀身。',32,'全唐诗/poet.tang.44000.json','["古殿清陰山木春，池邊跂石一觀身。", "誰能來此焚香坐，共作罏峯二十人。"]'),
('7dcfee10-85f3-4c5b-b2bd-82d2e9845a91','西林寄楊公','靈澈','唐','唐诗','tang','','[]','日日愛山歸已遲，閑閑空度少年時。',32,'全唐诗/poet.tang.44000.json','["日日愛山歸已遲，閑閑空度少年時。", "余身定寄林中老，心與長松片石期。"]'),
('cf42fa29-3234-4fd3-b21c-85dc95619905','荅徐廣叔四問','靈澈','唐','唐诗','tang','','[]','童子出家無第行，隨師乞食遣稱名。',32,'全唐诗/poet.tang.44000.json','["童子出家無第行，隨師乞食遣稱名。", "長沙豈敢論年幾，絳老惟知甲子生。"]'),
('daf40fe3-ecd8-4f43-a329-6b0f40ca8906','聞李處士亡','靈澈','唐','唐诗','tang','','[]','時時聞說故人死，日日自悲隨老身。',32,'全唐诗/poet.tang.44000.json','["時時聞說故人死，日日自悲隨老身。", "白髮不生應不得，青山長在屬何人。"]'),
('859e2308-e9d5-4472-9cd9-2885252df5f0','句','靈澈','唐','唐诗','tang','','[]','松樹有死枝，塚上唯莓苔。',160,'全唐诗/poet.tang.44000.json','["松樹有死枝，塚上唯莓苔。", "石門無人入，古木花不開。", "綠竹歲寒在，故人衰老多。", "月色靜中見，泉聲深處聞。", "古觀茅山下，諸峯欲曙時。", "真人是黃子，玉堂生紫芝。", "禪門至六祖，衣鉢無人得。", "古墓碑表折，荒壠松柏稀。", "秋深知氣正，家近覺山寒。", "山僧不記重陽日，因見茱萸憶去年。", "今非古獄下，莫向斗邊看。", "海月生殘夜，江春入暮年。", "窗風枯硯水，山雨慢琴弦。"]'),
('c04861a2-67e3-42e5-9ccc-f370843238e7','湘夫人祠','大易','唐','唐诗','tang','','[]','靈祠古木合，波颺大江濆。',48,'全唐诗/poet.tang.44000.json','["靈祠古木合，波颺大江濆。", "未□湘南雨，知爲何處雲。", "苔痕澀珠履，草色妒羅裙。", "妙鼓彤雲瑟，羈臣不可聞。"]'),
('f88cbc54-e083-4145-9217-f79a7082e150','贈司空拾遺','大易','唐','唐诗','tang','','[]','侍臣何事辭雲陛，江上微雲見雪花。',64,'全唐诗/poet.tang.44000.json','["侍臣何事辭雲陛，江上微雲見雪花。", "望閣未承丹鳳詔，掩門空對楚人家。", "陳琳草奏才還在，王粲登樓興未賒。", "高館更容塵外客，仍令歸路待瑤華。"]'),
('b6ff2497-569b-4120-a582-d535fb711f40','寄錢郎中','法照','唐','唐诗','tang','','[]','閉門深樹裏，閑足鳥來過。',48,'全唐诗/poet.tang.44000.json','["閉門深樹裏，閑足鳥來過。", "五馬不復貴，一僧誰奈何。", "藥苗家自有，香飯乞時多。", "寄語嬋娟客，將心向薜蘿。"]'),
('ffb26ef1-cdd2-4992-b294-f289c5136274','送清江上人','法照','唐','唐诗','tang','','[]','越人僧體古，清慮洗塵勞。',48,'全唐诗/poet.tang.44000.json','["越人僧體古，清慮洗塵勞。", "一國詩名遠，多生律行高。", "見山援葛藟，避世著方袍。", "早晚雲門去，儂應逐爾曹。"]'),
('b789d346-8be8-4699-9efd-6c8eb76b8e00','送無著禪師歸新羅','法照','唐','唐诗','tang','','[]','萬里歸鄉路，隨緣不算程。',48,'全唐诗/poet.tang.44000.json','["萬里歸鄉路，隨緣不算程。", "尋山百衲弊，過海一杯輕。", "夜宿依雲色，晨齋就水聲。", "何年持貝葉，却到漢家城。"]'),
('a3cabb82-133d-46a6-902d-91a2d1eba29e','游元象泊','釋泚','唐','唐诗','tang','','[]','空水潮色淨，澹然湖上心。',48,'全唐诗/poet.tang.44000.json','["空水潮色淨，澹然湖上心。", "舳艫輕且進，汀洲如可尋。", "秋風洄泝險，落日波濤深。", "寂寞武陵去，中流方至今。"]'),
('4391c2fd-e6a8-4010-a736-2140b795702c','北原別業','釋泚','唐','唐诗','tang','','[]','野外車騎絕，古村桑柘陰。',48,'全唐诗/poet.tang.44000.json','["野外車騎絕，古村桑柘陰。", "流鶯出谷靜，春草閉門深。", "學稼農爲業，忘情道作心。", "因知上皇日，鑿井在靈林。"]'),
('fd94beef-064d-4c50-87cd-7ecfe9fc1209','雜詩 一','龐藴','唐','唐诗','tang','','[]','未識龍宮莫說珠，識珠言說與君殊。',32,'全唐诗/poet.tang.44000.json','["未識龍宮莫說珠，識珠言說與君殊。", "空拳只是嬰兒信，豈得將來誑老夫。"]'),
('cb36e4cc-2743-4522-8bb7-4adf213bd836','雜詩 二','龐藴','唐','唐诗','tang','','[]','萬法從心起，心生萬法生。',48,'全唐诗/poet.tang.44000.json','["萬法從心起，心生萬法生。", "法生同日了，來去在虛行。", "寄語脩道人，空生慎勿生。", "如能達此理，不動出深坑。"]'),
('68f4eb4f-573e-4918-80e2-ef374211f4d6','雜詩 三','龐藴','唐','唐诗','tang','','[]','極目觀前境，寂寞無一人。',24,'全唐诗/poet.tang.44000.json','["極目觀前境，寂寞無一人。", "迴頭看後底，影亦不隨身。"]'),
('bb25d196-f370-4bc0-a101-b339e8d94366','雜詩 四','龐藴','唐','唐诗','tang','','[]','神識苟能無罣礙，廓周法界等虛空。',32,'全唐诗/poet.tang.44000.json','["神識苟能無罣礙，廓周法界等虛空。", "不假坐禪持戒律，超然解脫豈勞功。"]'),
('e619ce93-b8f8-4353-a176-6a9e3d2f8a18','雜詩 五','龐藴','唐','唐诗','tang','','[]','日用事無別，惟吾自偶偕。',48,'全唐诗/poet.tang.44000.json','["日用事無別，惟吾自偶偕。", "頭頭非取舍，處處勿張乖。", "朱紫誰爲號，青山絕點埃。", "神通幷妙用，運水及搬柴。"]'),
('696f593c-3ff8-4ae6-b491-99d732219066','雜詩 六','龐藴','唐','唐诗','tang','','[]','十方同聚會，個個學無爲。',24,'全唐诗/poet.tang.44000.json','["十方同聚會，個個學無爲。", "此是選佛場，心空及第歸。"]'),
('f76bc373-d980-42d4-88d0-282f58a305cd','雜詩 七','龐藴','唐','唐诗','tang','','[]','熖水無魚下底鉤，覓魚無處笑君愁。',32,'全唐诗/poet.tang.44000.json','["熖水無魚下底鉤，覓魚無處笑君愁。", "可憐谷隱老禪伯，被唾如何見亦羞。"]'),
('05791273-8a39-45ac-b858-dc2d370cb10f','歸山作','護國','唐','唐诗','tang','','[]','諠靜各有路，偶隨心所安。',96,'全唐诗/poet.tang.44000.json','["諠靜各有路，偶隨心所安。", "縱然在朝市，終不忘林巒。", "四皓將拂衣，二疏能挂冠。", "窓前隱逸傳，每日三時看。", "靳尚那可論，屈原亦可歎。", "至今黃泉下，名及青雲端。", "松牖見初月，花間禮古壇。", "何處論心懷，世上空漫漫。"]'),
('d629a68c-097f-4af3-872d-c8e596bd0e48','題醴陵玉仙觀歌','護國','唐','唐诗','tang','','[]','王喬一去空仙觀，白雲至今凝不散。',96,'全唐诗/poet.tang.44000.json','["王喬一去空仙觀，白雲至今凝不散。", "星垣松殿幾千秋，往往笙歌天下半。", "瀑布西行過石橋，黃精採根還採苗。", "路逢一人擎藥椀，松花夜雨風吹滿。", "自言家住在東坡，白犬相隨邀我過。", "南山石上有棊局，曾使樵夫爛斧柯。"]'),
('9e7364d8-49f0-4e93-84ff-638d2d64d0de','訪雲母山僧','護國','唐','唐诗','tang','','[]','森然古巖裏，淨行一番僧。',48,'全唐诗/poet.tang.44000.json','["森然古巖裏，淨行一番僧。", "松下濾寒水，佛前挑夜燈。", "蓮花國土異，貝葉梵書能。", "想到空王境，無心問愛憎。"]'),
('d6b8647f-4683-4732-b077-f3c576151f73','題王班水亭','護國','唐','唐诗','tang','','[]','湖上見秋色，曠然如爾懷。',48,'全唐诗/poet.tang.44000.json','["湖上見秋色，曠然如爾懷。", "豈惟歡隴畝，兼亦外形骸。", "待月歸山寺，彈琴坐暝齋。", "布衣閑自貴，何用謁天階。"]'),
('5ecd2cd4-c617-4a8f-a676-79c2a8997ae7','山中寄王員外','護國','唐','唐诗','tang','','[]','爲問幽蘭桂，空山復若何。',48,'全唐诗/poet.tang.44000.json','["爲問幽蘭桂，空山復若何。", "芬芳終有分，採折更誰過。", "望在軒階近，恩霑雨露多。", "移居儻得地，長願接瓊柯。"]'),
('398cc8c4-da35-473c-939d-61e627e91973','許州鄭使君孩子','護國','唐','唐诗','tang','','[]','毛骨貴天生，肌膚片玉明。',48,'全唐诗/poet.tang.44000.json','["毛骨貴天生，肌膚片玉明。", "見人空解笑，弄物不知名。", "國器嗟猶小，門風望益清。", "抱來芳樹下，時引鳳雛聲。"]'),
('3ee851c9-58ad-4870-984b-2c84a58fad04','愴故人舊居','護國','唐','唐诗','tang','','[]','惆悵至日暮，寒鴉啼樹林。',48,'全唐诗/poet.tang.44000.json','["惆悵至日暮，寒鴉啼樹林。", "破階苔色厚，殘壁雨痕深。", "命與時不遇，福爲禍所侵。", "空餘行逕在，令我歎人吟。"]'),
('1e1e8c15-4626-4de5-8739-8005dba3f17e','逢靈道士','護國','唐','唐诗','tang','','[]','浮丘山上見黃冠，松栢森森登古壇。',64,'全唐诗/poet.tang.44000.json','["浮丘山上見黃冠，松栢森森登古壇。", "一莖青竹以爲杖，數顆仙桃仍未餐。", "長安市裏仍賣卜，武陵溪畔每燒丹。", "縮地往來無定所，花源到處路漫漫。"]'),
('29ef36ed-0890-4fd2-b73b-08339655a268','別盛安','護國','唐','唐诗','tang','','[]','情人取次幾淹留，別後南州與北州。',64,'全唐诗/poet.tang.44000.json','["情人取次幾淹留，別後南州與北州。", "月色爲憐今夜客，砧聲那似去年秋。", "欲除豺虎論三略，莫對雲山詠四愁。", "親故相逢且借問，古來無種是王侯。"]'),
('a227f318-8a89-4199-aa8d-4e01e98aae78','傷蔡處士','護國','唐','唐诗','tang','','[]','篋中遺草是琅玕，對此空令灑淚看。',64,'全唐诗/poet.tang.44000.json','["篋中遺草是琅玕，對此空令灑淚看。", "三徑尚餘行跡在，數螢猶是映書殘。", "晨光不借泉門曉，暝色唯添隴樹寒。", "欲問皇天天更遠，有才無命說應難。"]'),
('5c2bb0e0-4898-4eb6-b6c6-0df522282332','臨川道中','護國','唐','唐诗','tang','','[]','出谷入谷路回轉，秋風已至歸期晚。',32,'全唐诗/poet.tang.44000.json','["出谷入谷路回轉，秋風已至歸期晚。", "舉頭何處望來蹤，萬仞千山鳥飛遠。"]'),
('fadc3151-ead3-4a78-a688-34c4e66314f9','贈張駙馬斑竹柱杖','護國','唐','唐诗','tang','','[]','此君與我在雲溪，勁節奇文勝杖藜。',32,'全唐诗/poet.tang.44000.json','["此君與我在雲溪，勁節奇文勝杖藜。", "爲有歲寒堪贈遠，玉階行處願提攜。"]'),
('970a828c-5164-46af-a661-daf6adef7c9a','病愈寄友','法振','唐','唐诗','tang','','[]','哀樂暗成疾，臥中芳月移。',48,'全唐诗/poet.tang.44000.json','["哀樂暗成疾，臥中芳月移。", "西山有清士，孤嘯不可追。", "擣藥晝林靜，汲泉陰澗遲。", "微蹤與麋鹿，遠謝求羊知。"]'),
('61f1c072-a1bb-4cf2-8393-6b28b2a57636','程評事西園之作','法振','唐','唐诗','tang','','[]','誰向春鶯道，名園已共知。',48,'全唐诗/poet.tang.44000.json','["誰向春鶯道，名園已共知。", "簷前迴水影，城上出花枝。", "搖拂煙雲動，登臨翰墨隨。", "相招能不厭，山舍爲君移。"]'),
('33872d17-5603-4d5f-9d69-e190efbd8f62','陳九溪中草堂','法振','唐','唐诗','tang','','[]','溪草落濺濺，魚飛入稻田。',48,'全唐诗/poet.tang.44000.json','["溪草落濺濺，魚飛入稻田。", "早寒臨洞月，輕素卷簾煙。", "䪻幘題新句，蓑衣象古賢。", "曙花閑秀色，三十六峰前。"]'),
('7c9b08e1-29cd-4037-a859-28a49f2a16b6','題天長阮少府湖上客歸','法振','唐','唐诗','tang','','[]','孤櫂移官舍，新農寄楚田。',48,'全唐诗/poet.tang.44000.json','["孤櫂移官舍，新農寄楚田。", "晴林渡海日，春草長湖煙。", "臥對閑鷗戲，談經稚子賢。", "佳期更何許，應向嘯臺前。"]'),
('2dca8305-fd75-4ef3-a86c-bdceb099759d','題萬山許鍊師','法振','唐','唐诗','tang','','[]','道成人不識，流水響空山。',48,'全唐诗/poet.tang.44000.json','["道成人不識，流水響空山。", "花暗軒窓外，雲隨坐臥間。", "驗圖名已久，絕粒事長閑。", "更欲崑崙去，羞看絳節還。"]'),
('0d5f8fe5-e5d2-49bf-839a-9dba06c8a431','河源破賊後贈袁將軍','法振','唐','唐诗','tang','','[]','白羽三千駐，蕭蕭萬里行。',48,'全唐诗/poet.tang.44000.json','["白羽三千駐，蕭蕭萬里行。", "出關深漢壘，帶月破蕃營。", "蔓草河原色，悲笳碎葉聲。", "欲朝王母殿，前路駐高旌。"]'),
('3c1e1520-c4ea-4c7c-a4e8-a2db3113bfcd','越中贈程先生','法振','唐','唐诗','tang','','[]','紗帽度殘春，虛舟寄一身。',48,'全唐诗/poet.tang.44000.json','["紗帽度殘春，虛舟寄一身。", "溪邊逢越女，花裏問秦人。", "古塞連山靜，陰霞落海新。", "有時城郭去，暗與酒家親。"]'),
('58ab86f4-dbb9-4dc2-ae00-4d49233dd83c','送常大夫赴朔方','法振','唐','唐诗','tang','','[]','關山今不掩，軍候鳥先知。',48,'全唐诗/poet.tang.44000.json','["關山今不掩，軍候鳥先知。", "大漢嫖姚入，烏孫部曲隨。", "高旌天外駐，寒角月中吹。", "歸到長安第，花應再滿枝。"]'),
('a313f472-a62c-45df-90cc-d4f0fa508732','送人遊閩越','法振','唐','唐诗','tang','','[]','不須行借問，爲爾話閩中。',48,'全唐诗/poet.tang.44000.json','["不須行借問，爲爾話閩中。", "海島陰晴日，江帆來去風。", "道游玄度宅，身寄朗陵公。", "此別何傷遠，如今關塞通。"]'),
('12b1b340-0cb9-4ddb-b1e5-b7758e47ca29','送褚先生海上尋封鍊師','法振','唐','唐诗','tang','','[]','潮落風初定，天吳避客舟。',72,'全唐诗/poet.tang.44000.json','["潮落風初定，天吳避客舟。", "近承三殿旨，欲向五湖游。", "不厭烏皮几，新縫鶴氅裘。", "明珠漂斷岸，陰火映中流。", "華蓋芝童引，神丹桂女收。", "懸知居縹緲，因爲識浮丘。"]'),
('96c807aa-8284-4bff-995d-e53848d30ee4','送韓侍御自使幕巡海北','法振','唐','唐诗','tang','','[]','微雨空山夜洗兵，繡衣朝拂海雲清。',64,'全唐诗/poet.tang.44000.json','["微雨空山夜洗兵，繡衣朝拂海雲清。", "幕中運策心應苦，馬上吟詩卷已成。", "離亭不惜花源醉，古道猶看蔓草生。", "因說元戎能破敵，高歌一曲隴關情。"]'),
('a36ddea5-8195-42d5-a684-16a9b01ced63','張舍人南谿別業','法振','唐','唐诗','tang','','[]','新田繞屋半春耕，藜杖閑門引客行。',64,'全唐诗/poet.tang.44000.json','["新田繞屋半春耕，藜杖閑門引客行。", "山翠自成微雨色，谿花不隱亂泉聲。", "漁家遠到堪留興，公府懸知欲厭名。", "入夜更宜明月滿，雙童喚出解吹笙。"]'),
('3a040e1c-e431-499e-a0d3-f2375f744ef4','別盧使君歸故柵村','法振','唐','唐诗','tang','','[]','歸風白馬引嘶聲，落日猶看楚客情。',64,'全唐诗/poet.tang.44000.json','["歸風白馬引嘶聲，落日猶看楚客情。", "塞口竹緣空戍沒，潮頭沙擁慢岡成。", "松田且欲親耕種，郡守何偏問姓名。", "東道宿程投故柵，依依漁父解相迎。"]'),
('36b5947b-2140-4c62-9dce-33b00e0eb4c8','丹陽浦送客之海上','法振','唐','唐诗','tang','','[]','不到終南向幾秋，移居更欲近滄洲。',64,'全唐诗/poet.tang.44000.json','["不到終南向幾秋，移居更欲近滄洲。", "風吹雨色連村暗，潮擁菱花出岸浮。", "漠漠望中春自豔，寥寥泊處夜堪愁。", "如君豈得空高枕，只益天書遣遠求。"]'),
('a363d7df-7ac4-4a52-a920-b8839410ca1b','月夜泛舟','法振','唐','唐诗','tang','','[]','西塞長雲盡，南湖片月斜。',24,'全唐诗/poet.tang.44000.json','["西塞長雲盡，南湖片月斜。", "漾舟人不見，臥入武陵花。"]'),
('2fb4c0b8-9e27-4faf-b223-2cb218feb6cc','送友人之上都','法振','唐','唐诗','tang','','[]','玉帛徵賢楚客稀，猨啼相送武陵歸。',32,'全唐诗/poet.tang.44000.json','["玉帛徵賢楚客稀，猨啼相送武陵歸。", "湖頭望入桃花去，一片春帆帶雨飛。"]'),
('e6cf796d-47d6-443e-bbe3-4f2422ab0744','句','法振','唐','唐诗','tang','','[]','畫鼓催來錦臂襄，小娥雙起整霓裳。',16,'全唐诗/poet.tang.44000.json','["畫鼓催來錦臂襄，小娥雙起整霓裳。"]'),
('5d47e8be-e0ba-4942-b6a1-e1684e3f39d6','早發陝州途中贈嚴祕書','清江','唐','唐诗','tang','','[]','此身雖不繫，憂道亦勞生。',72,'全唐诗/poet.tang.44000.json','["此身雖不繫，憂道亦勞生。", "萬里江湖夢，千山雨雪行。", "人家依舊壘，關路閉層城。", "未盡交河虜，猶屯細柳兵。", "艱難嗟遠客，棲託賴深情。", "貧病吾將有，精修許少卿。"]'),
('934fbd4a-4df4-47a7-9dc4-bc25b52b3af3','早春書情寄河南崔少府','清江','唐','唐诗','tang','','[]','春日春風至，陽和似不均。',72,'全唐诗/poet.tang.44000.json','["春日春風至，陽和似不均。", "病身空益老，愁鬢不知春。", "宇宙成遺物，光陰促幻身。", "客遊傷末路，心事向行人。", "道薄猶懷土，時難欲厭貧。", "微才如可寄，赤縣有鄉親。"]'),
('9dfb39b4-ae3c-4bb3-9f01-53b70ffc20cc','春遊司直城西鸕鶿谿別業','清江','唐','唐诗','tang','','[]','別墅軍城下，閑諠未可齊。',120,'全唐诗/poet.tang.44000.json','["別墅軍城下，閑諠未可齊。", "春深花蝶夢，曉隔柳煙鞞。", "韶景浮寒水，疎楊映綠堤。", "沿洄看竹色，來往聽鶯啼。", "久慢持生術，多親種藥畦。", "家貧知素行，心苦見清溪。", "越客初投分，南枝得寄棲。", "禪機空寂寞，雅趣賴招攜。", "本寺重江外，遊方二室西。", "裴回戀知己，日夕草萋萋。"]'),
('a4a57aed-cd42-417f-b1b9-00e183448196','夕次襄邑','清江','唐','唐诗','tang','','[]','何處戒吾道，經年遠路中。',48,'全唐诗/poet.tang.44000.json','["何處戒吾道，經年遠路中。", "客心猶向北，河水自歸東。", "古戍鳴寒角，疎林振夕風。", "輕舟惟載月，那與故人同。"]'),
('26c6bc29-5e78-4cdb-8b36-b068e89af845','宿嚴維宅簡章八元','清江','唐','唐诗','tang','','[]','佳期曾不遠，甲第即南鄰。',48,'全唐诗/poet.tang.44000.json','["佳期曾不遠，甲第即南鄰。", "惠愛偏相及，經過豈厭頻。", "秋寒林葉動，夕霽月華新。", "莫話羈棲事，平原是主人。"]'),
('7887d2d9-3655-45b1-a556-349d95304058','贈淮西賈兵馬使','清江','唐','唐诗','tang','','[]','破虜功成百戰場，天書新拜漢中郎。',64,'全唐诗/poet.tang.44000.json','["破虜功成百戰場，天書新拜漢中郎。", "映門旌斾春風起，對客弦歌白日長。", "階下鬬雞花乍發，營南試馬柳初黃。", "由來吳楚多同調，感激逢君共異鄉。"]'),
('1864aa5b-f2ea-4e19-8d6f-b28511dbdc4f','送堅上人歸杭州天竺寺','清江','唐','唐诗','tang','','[]','十年勞負笈，經論化中朝。',48,'全唐诗/poet.tang.44000.json','["十年勞負笈，經論化中朝。", "流水知鄉近，和風惜別遙。", "雲山零夜雨，花岸上春潮。", "歸臥南天竺，禪心更寂寥。"]'),
('f3d72feb-7141-4da9-935c-39da0b15738f','送贊律師歸嵩山','清江','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u4eba"]','禪意歸心急，山深定易安。',48,'全唐诗/poet.tang.44000.json','["禪意歸心急，山深定易安。", "清貧修道苦，孝友別家難。", "雪路侵溪轉，花宮映嶽看。", "到時瞻塔暮，松月向人寒。"]'),
('ab1108a9-1317-4fb4-bec4-2f02dbc12674','上都酬章十八兄','清江','唐','唐诗','tang','','[]','每歎經年別，人生有幾年。',48,'全唐诗/poet.tang.44000.json','["每歎經年別，人生有幾年。", "關河長問道，風雨獨隨緣。", "寓蝶成莊夢，懷人識禰賢。", "徽猷不及此，空媿白華篇。"]'),
('366a47e4-b1df-48c2-965f-e3e6295412c6','登樓望月寄鳳翔李少尹','清江','唐','唐诗','tang','','[]','陌上涼風槐葉凋，夕陽秋露濕寒條。',64,'全唐诗/poet.tang.44000.json','["陌上涼風槐葉凋，夕陽秋露濕寒條。", "登樓望月楚山上，月到樓南山獨遙。", "心送秦人趨鳳闕，月隨陽鴈極煙霄。", "軒車不重無名客，此地誰能訪寂寥。"]'),
('85f65a5e-2acb-48ba-817d-e2741c02e04c','湘川懷古','清江','唐','唐诗','tang','','[]','瀟湘連汨羅，復對九嶷河。',48,'全唐诗/poet.tang.44000.json','["瀟湘連汨羅，復對九嶷河。", "浪勢屈原塚，竹聲漁父歌。", "地荒征騎少，天暖浴禽多。", "脉脉東流水，古今同奈何。"]'),
('4c6782e2-c072-4db5-926d-cd2a40009e7b','七夕','清江','唐','唐诗','tang','','[]','七夕景迢迢，相逢只一宵。',48,'全唐诗/poet.tang.44000.json','["七夕景迢迢，相逢只一宵。", "月爲開帳燭，雲作渡河橋。", "映水金冠動，當風玉珮搖。", "惟愁更漏促，離別在明朝。"]'),
('eca40cb9-f19d-4bee-919e-010293f506e5','長安臥病','清江','唐','唐诗','tang','','[]','身世足堪悲，空房臥病時。',48,'全唐诗/poet.tang.44000.json','["身世足堪悲，空房臥病時。", "卷簾花雨滴，掃石竹陰移。", "已覺生如夢，堪嗟壽不知。", "未能通法性，詎可免支離。"]'),
('a1624979-ef20-428f-9a71-4932ac6d22b8','送婆羅門','清江','唐','唐诗','tang','','["\u9001\u522b"]','雪嶺金河獨向東，吳山楚澤意無窮。',32,'全唐诗/poet.tang.44000.json','["雪嶺金河獨向東，吳山楚澤意無窮。", "如今白首鄉心盡，萬里歸程在夢中。"]'),
('882c5540-ae02-437a-b50f-ce6f18bb703f','喜皇甫大夫同宿大梁驛','清江','唐','唐诗','tang','','["\u5e90\u5c71"]','江頭旌斾去，花外卷簾空。',48,'全唐诗/poet.tang.44000.json','["江頭旌斾去，花外卷簾空。", "夜色臨城月，春聲渡水風。", "也知行李別，蹔喜話言同。", "若問廬山事，終身愧遠公。"]'),
('f7f4a4fe-6bef-4cf0-aa48-5c8534a8b344','酬姚補闕南仲雲溪館中戲題隨書見寄','清江','唐','唐诗','tang','','[]','寺溪臨使府，風景借仁祠。',48,'全唐诗/poet.tang.44000.json','["寺溪臨使府，風景借仁祠。", "補衮周官貴，能名漢主慈。", "臥雲知獨處，望月憶同時。", "忽枉緘中贈，瓊瑤滿手持。"]'),
('f21e1426-ed83-4fe3-af8b-3195630a708d','喜嚴侍御蜀還贈嚴祕書','清江','唐','唐诗','tang','','[]','往年分首出咸秦，木落花開秋又春。',64,'全唐诗/poet.tang.44000.json','["往年分首出咸秦，木落花開秋又春。", "江客不曾知蜀路，旅魂何處訪情人。", "當時望月思文友，今日迎驄見近臣。", "多羨二龍同漢代，繡衣芸閣共榮親。"]'),
('b3737b9a-376f-4a0e-a852-6389802ceca9','送韋參軍江陵','清江','唐','唐诗','tang','','[]','槐花落盡柳陰清，蕭索涼天楚客情。',64,'全唐诗/poet.tang.44000.json','["槐花落盡柳陰清，蕭索涼天楚客情。", "海上舊山無的信，東門歸路不堪行。", "身隨幻境勞多事，跡學禪心厭有名。", "公子道存知不棄，欲依劉表住南荆。"]'),
('b5485622-5ffb-4f27-98cd-f89ca13d82f1','月夜有懷黃端公兼簡朱孫二判官','清江','唐','唐诗','tang','','[]','月照疎林驚鵲飛，羈人此夜共無依。',96,'全唐诗/poet.tang.44000.json','["月照疎林驚鵲飛，羈人此夜共無依。", "青門旅寓身空老，白首頭陀力漸微。", "屢向曲池陪逸少，幾回戎幕接玄暉。", "四科弟子稱文學，五馬諸侯是繡衣。", "江雁往來曾不定，野雲搖曳本無機。", "修行未盡身將盡，欲向東山掩舊扉。"]'),
('a2012b95-b50d-4000-a720-148e3a6323be','精舍遇雨','清江','唐','唐诗','tang','','[]','空門寂寂淡吾身，溪雨微微洗客塵。',32,'全唐诗/poet.tang.44000.json','["空門寂寂淡吾身，溪雨微微洗客塵。", "臥向白雲情未盡，任他黃鳥醉芳春。"]'),
('a279670d-cb7a-4208-b9f3-7d63da2247cd','小雪','清江','唐','唐诗','tang','','[]','落雪臨風不厭看，更多還恐蔽林巒。',32,'全唐诗/poet.tang.44000.json','["落雪臨風不厭看，更多還恐蔽林巒。", "愁人正在書窗下，一片飛來一片寒。"]'),
('d003895f-9092-4a7f-b842-0c3a1e131254','句','清江','唐','唐诗','tang','','[]','萬木無一葉，客心悲此時。',12,'全唐诗/poet.tang.44000.json','["萬木無一葉，客心悲此時。"]'),
('27643374-5bbd-47de-a805-f1718a214935','送呂郎中赴滄州','無可','唐','唐诗','tang','','[]','出守滄州去，西風送斾旌。',48,'全唐诗/poet.tang.44000.json','["出守滄州去，西風送斾旌。", "路遙經幾郡，地盡到孤城。", "拜廟千山綠，登樓遍海清。", "何人共東望，日向積濤生。"]'),
('5ecec768-e1d4-4231-a59a-34eda00963f8','書馬如文石門居','無可','唐','唐诗','tang','','[]','別業逸高情，暮泉喧客亭。',48,'全唐诗/poet.tang.44000.json','["別業逸高情，暮泉喧客亭。", "林迴天闕近，雨過石門青。", "野果誰來拾，山禽獨臥聽。", "要迎文會友，時復掃柴扃。"]'),
('f8687f09-0ec3-4c94-a2f3-7118449ba8ff','送章正字秩滿東歸','無可','唐','唐诗','tang','','[]','朝衣登別席，春色滿秦關。',48,'全唐诗/poet.tang.44000.json','["朝衣登別席，春色滿秦關。", "芸閣吏誰替，海門身又還。", "尋僧流水僻，見月遠林閑。", "雖是忘機者，難齊去住間。"]'),
('00cedd54-c856-4eab-b0f3-e6be6dcddfb4','賦得望遠山送客歸','無可','唐','唐诗','tang','','[]','遙山寒雨過，正向暮天橫。',48,'全唐诗/poet.tang.44000.json','["遙山寒雨過，正向暮天橫。", "隱隱凌雲出，蒼蒼與水平。", "何時凝厚地，幾處映孤城。", "歸客秋風裏，迴看傷別情。"]'),
('ee890bde-8ee6-40b5-b127-1692d7e4f6d5','送宜春裴宰是將軍旻之孫','無可','唐','唐诗','tang','','[]','垂白方爲縣，徒知大父雄。',48,'全唐诗/poet.tang.44000.json','["垂白方爲縣，徒知大父雄。", "山春南去棹，楚夜北飛鴻。", "疊嶂和雲滅，孤城與嶺通。", "誰知持惠花，一境動清風。"]'),
('b9aa147e-5a46-46ce-8bdb-c568d055b95f','送朴山人歸日本','無可','唐','唐诗','tang','','[]','海霽晚帆開，應無鄉信催。',48,'全唐诗/poet.tang.44000.json','["海霽晚帆開，應無鄉信催。", "水從荒外積，人指日邊迴。", "望國乘風久，浮天絕島來。", "儻因華夏使，書札轉悠哉。"]'),
('80ae35ac-4792-4fed-a111-32e95d4fb546','送姚宰任吉州安福縣','無可','唐','唐诗','tang','','[]','落絮滿衣裳，攜琴問酒鄉。',48,'全唐诗/poet.tang.44000.json','["落絮滿衣裳，攜琴問酒鄉。", "挂帆南入楚，到縣半浮湘。", "吏散翠禽下，庭閑斑竹長。", "人安宜遠泛，沙上蕙蘭香。"]'),
('7ae6f4f3-3a61-44c4-b61b-20ab85d9b44a','送李少府之任臨邛','無可','唐','唐诗','tang','','[]','邛南方作尉，調補一何卑。',48,'全唐诗/poet.tang.44000.json','["邛南方作尉，調補一何卑。", "發論唯公幹，承家乃帝枝。", "山長風褭棧，江蔭石和澌。", "舊井王孫宅，還尋獨有期。"]'),
('599dccb6-9f23-4eaa-b657-e1d27f18bc35','遊山寺','無可','唐','唐诗','tang','','[]','千峰路盤盡，林寺昔何名。',48,'全唐诗/poet.tang.44000.json','["千峰路盤盡，林寺昔何名。", "步步入山影，房房聞水聲。", "多年人跡斷，殘照石陰清。", "自可求居止，安閑過此生。"]'),
('9ae48cba-4fe7-4a9e-9ec7-b183b3f26ebf','酬姚員外見過林下','無可','唐','唐诗','tang','','[]','掃苔迎五馬，蒔藥過申鐘。',48,'全唐诗/poet.tang.44000.json','["掃苔迎五馬，蒔藥過申鐘。", "鶴共林僧見，雲隨野客逢。", "入樓山隔水，滴斾露垂松。", "日暮題詩去，空知雅調重。"]'),
('2613c223-087f-4e53-a9b1-233825d60cdd','寄華州馬戴','無可','唐','唐诗','tang','','[]','三峰待秋上，鳥外挂衣巾。',48,'全唐诗/poet.tang.44000.json','["三峰待秋上，鳥外挂衣巾。", "猶見無窮景，應非暫往身。", "水寒仙掌路，山遠華陽人。", "欲問壇邊月，尋思闕復新。"]'),
('3ea092bf-b5e6-4a61-b64a-14f509ea81a1','秋夜寄青龍寺空貞二上人','無可','唐','唐诗','tang','','[]','夜來思道侶，木葉向人飄。',48,'全唐诗/poet.tang.44000.json','["夜來思道侶，木葉向人飄。", "精舍池邊古，秋山樹下遙。", "磬寒徹幾里，雲白已經宵。", "未得同居止，蕭然自寂寥。"]'),
('ab0597d1-78d6-49f3-a6ea-72c400e4203a','過杏溪寺寄姚員外','無可','唐','唐诗','tang','','[]','門徑衆峰頭，盤巖復轉溝。',48,'全唐诗/poet.tang.44000.json','["門徑衆峰頭，盤巖復轉溝。", "雲僧隨樹老，杏水落江流。", "峽狖有時到，秦人今日遊。", "謝公多晚眺，此景在南樓。"]'),
('93363b37-54c5-4331-aec4-9788f3eecce5','送僧歸中條','無可','唐','唐诗','tang','','[]','夜葉動飄飄，寒來話數宵。',48,'全唐诗/poet.tang.44000.json','["夜葉動飄飄，寒來話數宵。", "卷經歸鳥外，轉雪過山椒。", "舊長松杉大，難行水石遙。", "元戎宗內學，應就白雲招。"]'),
('66e55178-5606-407a-a758-a5708b2612df','送人罷舉東遊','無可','唐','唐诗','tang','','[]','東堂今已負，況此遠行難。',48,'全唐诗/poet.tang.44000.json','["東堂今已負，況此遠行難。", "兼雨風聲過，連天草色乾。", "鴻嘶荒壘閉，兵燒廣川寒。", "若向龍門宿，懸知拭淚看。"]'),
('0530cce2-a459-41a3-a9ea-db89ac122bc4','金州冬月陪太宗遊池','無可','唐','唐诗','tang','','[]','殘臘雪紛紛，林間起送君。',48,'全唐诗/poet.tang.44000.json','["殘臘雪紛紛，林間起送君。", "苦吟行迥野，投跡向寒雲。", "絕頂晴多去，幽泉凍不聞。", "唯應草堂寺，高枕脫人羣。"]'),
('b3a399cd-6019-4c79-81c7-ebc92bf92d4d','寄青龍寺原上人','無可','唐','唐诗','tang','','["\u5199\u666f", "\u51ac\u5929"]','斂屨入寒竹，安禪過漏聲。',48,'全唐诗/poet.tang.44000.json','["斂屨入寒竹，安禪過漏聲。", "高杉殘子落，深井凍痕生。", "罷磬風枝動，懸燈雪屋明。", "何當招我宿，乘月上方行。"]'),
('cd186dc1-43b5-40f3-a888-9a75c4e95289','秋寄從兄賈島','無可','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','暝蟲喧暮色，默思坐西林。',48,'全唐诗/poet.tang.44000.json','["暝蟲喧暮色，默思坐西林。", "聽雨寒更徹，開門落葉深。", "昔因京邑病，併起洞庭心。", "亦是吾兄事，遲迴共至今。"]'),
('e38f801e-1ab7-4b85-aa62-5ab3238deda2','新年','無可','唐','唐诗','tang','','["\u6292\u60c5", "\u8282\u65e5", "\u65b0\u5e74"]','燃燈朝復夕，漸作長年身。',48,'全唐诗/poet.tang.44000.json','["燃燈朝復夕，漸作長年身。", "紫閣未歸日，青門又見春。", "掩關寒過盡，開定草生新。", "自有林中趣，誰驚歲去頻。"]'),
('e795761d-bcdf-4ad1-a68b-b4a5cee77333','夏日送崔秀才遊南','無可','唐','唐诗','tang','','[]','南方山水地，念子爲貧遊。',48,'全唐诗/poet.tang.44000.json','["南方山水地，念子爲貧遊。", "縱是逢佳景，那能緩旅愁。", "夕陽行遠道，煩暑在孤舟。", "莫向巴江過，猨啼促淚流。"]'),
('d7499059-41dc-4492-a640-0e2756a1d627','晚秋酬姚合見寄','無可','唐','唐诗','tang','','[]','新命起高眠，江湖空浩然。',48,'全唐诗/poet.tang.44000.json','["新命起高眠，江湖空浩然。", "木衰猶有菊，燕去即無蟬。", "分察千官內，孤懷遠嶽邊。", "蕭條人外寺，暌阻又經年。"]'),
('16cd1399-09ed-4caa-b204-17ef7300d18d','暮秋宿友人居','無可','唐','唐诗','tang','','[]','招我郊居宿，開門但苦吟。',48,'全唐诗/poet.tang.44000.json','["招我郊居宿，開門但苦吟。", "秋眠山燒盡，暮歇竹園深。", "寒浦鴻相呌，風窗月欲沈。", "翻嫌坐禪石，不在此松陰。"]'),
('dc5b9550-1690-4a7a-90d7-b65b853888c0','送李騎曹之武寧','無可','唐','唐诗','tang','','[]','一歲一歸寧，涼天數騎行。',48,'全唐诗/poet.tang.44000.json','["一歲一歸寧，涼天數騎行。", "河來當塞曲，山遠與沙平。", "縱獵旗風卷，聽笳帳月生。", "新鴻引寒色，迴日滿京城。"]'),
('2d0c158a-37ec-457a-91d7-bec3ac504634','秋日寄厲玄先輩','無可','唐','唐诗','tang','','[]','楊柳起秋色，故人猶未還。',48,'全唐诗/poet.tang.44000.json','["楊柳起秋色，故人猶未還。", "別離俱自苦，少壯豈能閑。", "夜雨吟殘燭，秋城憶遠山。", "何當一相見，語默此林間。"]'),
('5fad3912-8afd-45f4-93e2-b88f32a87d30','冬晚與諸文士會太僕田卿宅','無可','唐','唐诗','tang','','[]','從容啓華館，饌玉復燒蘭。',48,'全唐诗/poet.tang.44000.json','["從容啓華館，饌玉復燒蘭。", "是歲茲旬盡，良宵幾刻殘。", "風迴松竹動，人息斗牛寒。", "此後思良集，須期月再圓。"]'),
('57ea902a-21be-4363-838c-87127eb912b9','贈詩僧','無可','唐','唐诗','tang','','[]','寒山對水塘，竹葉影侵堂。',48,'全唐诗/poet.tang.44000.json','["寒山對水塘，竹葉影侵堂。", "洗藥冰生岸，開門月滿牀。", "病多身又老，枕倦夜兼長。", "來謁吾曹者，呈詩問否臧。"]'),
('d2df576c-77d6-4cea-a28a-fb214b0ce6ae','寒夜過叡川師院','無可','唐','唐诗','tang','','[]','長生推獻壽，法坐四朝登。',50,'全唐诗/poet.tang.44000.json','["長生推獻壽，法坐四朝登。", "問難無[彊]敵，聲名掩古僧。", "絕塵苔積地，栖竹鳥驚燈。", "語默俱忘寐，殘窗半月稜。"]'),
('e8b8103e-8d1c-4294-8073-4149d63f323c','送顥法師往太原講兼呈李司徒','無可','唐','唐诗','tang','','[]','近臘辭精舍，幷州謁尚公。',48,'全唐诗/poet.tang.44000.json','["近臘辭精舍，幷州謁尚公。", "路長山忽盡，塞廣雪無窮。", "講席開晴壘，禪衣涉遠風。", "聞經諸弟子，應滿此門中。"]'),
('5e8a82b8-429e-4f18-beba-0ef50e8d3f7d','冬日諸禪自商山禮正師真塔迴見訪','無可','唐','唐诗','tang','','[]','久思今忽來，雙屨汚青苔。',48,'全唐诗/poet.tang.44000.json','["久思今忽來，雙屨汚青苔。", "拂雪從山起，過房禮塔迴。", "偈留閑夜作，禪請暫時開。", "欲作孤雲去，賦詩余不才。"]'),
('a033d766-5bd1-4fe8-b96f-017305b28c8d','題青龍寺縱公房','無可','唐','唐诗','tang','','[]','從誰得法印，不離上方傳。',48,'全唐诗/poet.tang.44000.json','["從誰得法印，不離上方傳。", "夕磬城霜下，寒房竹月圓。", "煙殘衰木畔，客住積雲邊。", "未隱滄洲去，時來於此禪。"]'),
('5abdd571-5f2f-4e52-9aa3-5f7e7ebfac4d','贈圭峰禪師','無可','唐','唐诗','tang','','[]','絕壑禪林底，泉分落石層。',48,'全唐诗/poet.tang.44000.json','["絕壑禪林底，泉分落石層。", "霧交高頂草，雲隱下方燈。", "朝滿傾心客，溪連學道僧。", "半旬持一食，此事有誰能。"]'),
('1fd46bb8-c1e4-44f8-a8e8-b7d642b83e36','陪姚合遊金州南池','無可','唐','唐诗','tang','','[]','柳暗清波漲，衝萍復漱苔。',48,'全唐诗/poet.tang.44000.json','["柳暗清波漲，衝萍復漱苔。", "張筵白鳥起，掃岸使君來。", "洲島秋應沒，荷花晚盡開。", "高城吹角絕，騶馭尚裴回。"]'),
('90bb95bd-c0b8-487d-924a-ba3729be1f61','金州別姚合','無可','唐','唐诗','tang','','[]','日日西亭上，春留到夏殘。',48,'全唐诗/poet.tang.44000.json','["日日西亭上，春留到夏殘。", "言之離別易，勉以道途難。", "山出一千里，溪行三百灘。", "松間樓裏月，秋入五陵看。"]'),
('5a2c21e1-134f-418a-b4d4-e7b63cfe4a68','夏日送田中丞赴蔡州','無可','唐','唐诗','tang','','[]','出守汝南城，應多戀闕情。',48,'全唐诗/poet.tang.44000.json','["出守汝南城，應多戀闕情。", "地遙人久望，風起斾初行。", "楚廟繁蟬斷，淮田細雨生。", "賞心知有處，蔣宅古津平。"]'),
('a3cd1615-4f9f-49b0-8c5d-a191318af012','菊','無可','唐','唐诗','tang','','[]','東籬搖落後，密豔被寒催。',48,'全唐诗/poet.tang.44000.json','["東籬搖落後，密豔被寒催。", "夾雨驚新拆，經霜忽盡開。", "野香盈客袖，禁蘂泛天杯。", "不共春蘭竝，悠揚遠蝶來。"]'),
('73773614-a641-42a4-8cce-9556d4934097','松','無可','唐','唐诗','tang','','[]','枝幹怪鱗皴，烟梢出澗新。',48,'全唐诗/poet.tang.44000.json','["枝幹怪鱗皴，烟梢出澗新。", "屈盤高極目，蒼翠遠驚人。", "待鶴移陰過，聽風落子頻。", "青青寒木外，自與九霄鄰。"]'),
('ae92a828-11c5-4b90-817f-ff7593ea559b','蘭','無可','唐','唐诗','tang','','[]','蘭色結春光，氛氳掩衆芳。',48,'全唐诗/poet.tang.44000.json','["蘭色結春光，氛氳掩衆芳。", "過門階露葉，尋澤徑連香。", "畹靜風吹亂，亭秋雨引長。", "靈鈞曾采擷，紉珮掛荷裳。"]'),
('f753a071-7a97-4c0b-9e75-f3207d0672bf','隕葉','無可','唐','唐诗','tang','','[]','遶巷夾溪紅，蕭條逐北風。',48,'全唐诗/poet.tang.44000.json','["遶巷夾溪紅，蕭條逐北風。", "別林遺宿鳥，浮水載鳴蟲。", "石小埋初盡，枝長落未終。", "帶霜書麗什，閑讀白雲中。"]'),
('bd10ed68-78f0-47c3-b870-92ad1ede2802','李常侍書堂','無可','唐','唐诗','tang','','[]','結構因墳籍，簷前竹未生。',48,'全唐诗/poet.tang.44000.json','["結構因墳籍，簷前竹未生。", "塗油窗日早，閱槧幌風輕。", "息架蛩驚客，垂燈雨過城。", "已應窮古史，師律孰齊名。"]'),
('f0c5d0d6-752c-4537-88dd-16afdca6305d','寄和蔡州田郎中','無可','唐','唐诗','tang','','[]','遺跡仍留蔡，幽人出漢朝。',48,'全唐诗/poet.tang.44000.json','["遺跡仍留蔡，幽人出漢朝。", "門深荒徑在，臺迥數峰遙。", "岸石欹相倚，窗松偃未凋。", "尋思方一去，豈待使君招。"]'),
('a45c1977-b24a-4636-afdd-14fe66feac7a','經貞女祠','無可','唐','唐诗','tang','','[]','朝賽暮還祈，開唐復歷隋。',48,'全唐诗/poet.tang.44000.json','["朝賽暮還祈，開唐復歷隋。", "精誠山雨至，歲月廟松衰。", "窺穴龍潭黑，過門鳥道危。", "不同巫峽女，來往楚王祠。"]'),
('37b1bed6-dcd3-48c5-9674-f507da9c7b37','行漢水晚次神灘阻風','無可','唐','唐诗','tang','','[]','驚風山半起，舟子忽停橈。',48,'全唐诗/poet.tang.44000.json','["驚風山半起，舟子忽停橈。", "岸荻吹先亂，灘聲落更跳。", "聽松今欲暮，過島或明朝。", "若盡平生趣，東浮看石橋。"]'),
('ad7b2d19-b4b3-465b-9f37-0b8ef2030199','送田中丞使西戎','無可','唐','唐诗','tang','','[]','朝元下赤墀，玉節使西夷。',48,'全唐诗/poet.tang.44000.json','["朝元下赤墀，玉節使西夷。", "關隴風迴首，河湟雪灑旗。", "磧砂行幾月，戎帳到何時。", "應盡平生志，高全大國儀。"]'),
('847d5d0e-ac42-42bc-b704-f596c2ae5754','送董正字歸覲毘陵','無可','唐','唐诗','tang','','[]','暫辭讐校去，未發見新鴻。',48,'全唐诗/poet.tang.44000.json','["暫辭讐校去，未發見新鴻。", "路入江波上，人歸楚邑東。", "山遙晴出樹，野極暮連空。", "何以念兄弟，應思潔膳同。"]'),
('37909002-c9a7-4720-8123-0d4023d62cea','送邵錫及第歸湖州','無可','唐','唐诗','tang','','[]','春關鳥罷啼，歸慶浙煙西。',48,'全唐诗/poet.tang.44000.json','["春關鳥罷啼，歸慶浙煙西。", "郡守招延重，鄉人慕仰齊。", "橘青逃暑寺，茶長隔湖溪。", "乘暇知高眺，微應辨會稽。"]'),
('5859de0c-22b4-4bd0-b536-b51dd99fc6b3','送薛重中丞充太原副使','無可','唐','唐诗','tang','','[]','中司出華省，副相晉陽行。',48,'全唐诗/poet.tang.44000.json','["中司出華省，副相晉陽行。", "書答偏州啓，籌參上將營。", "踏沙夜馬細，吹雨曉笳清。", "正報胡塵滅，桃花汾水生。"]'),
('360ae234-18b7-4b26-baef-2062786d4610','送靈武李侍御','無可','唐','唐诗','tang','','[]','靈州天一涯，幕客似還家。',48,'全唐诗/poet.tang.44000.json','["靈州天一涯，幕客似還家。", "地得江南壤，程分磧裏砂。", "禁鹽調上味，麥穗結秋花。", "前席因籌畫，清吟塞日斜。"]'),
('8117787b-d81d-4685-8290-9f17702e4884','冬夜姚侍御宅送李廓少府','無可','唐','唐诗','tang','','[]','王事圭峰下，將還禁漏餘。',48,'全唐诗/poet.tang.44000.json','["王事圭峰下，將還禁漏餘。", "偶歡新歲近，惜別後期疎。", "雪罷見來吏，川昏聊整車。", "獨吟多暇日，應寄柏臺書。"]'),
('baac66a9-7ae0-4f28-b6db-1c4946013390','送喻鳧及第歸陽羨','無可','唐','唐诗','tang','','[]','姓字載科名，無過子最榮。',48,'全唐诗/poet.tang.44000.json','["姓字載科名，無過子最榮。", "宗中初及第，江上覲難兄。", "月向波濤沒，茶連洞壑生。", "石橋高思在，且爲看東坑。"]'),
('fd80a088-f7c8-44ec-897b-2189e12ff79e','送沅江宋明府即開府璟之孫','無可','唐','唐诗','tang','','[]','初聞從事日，鄂渚動芳菲。',48,'全唐诗/poet.tang.44000.json','["初聞從事日，鄂渚動芳菲。", "一遂鈞衡薦，今爲長吏歸。", "人臨沅水望，鴈映楚山飛。", "唯有傳聲政，家風重發揮。"]'),
('d4a45677-b8c3-4c8a-baf0-422e3a4cf050','送薛秀才遊河中兼投任郎中留後','無可','唐','唐诗','tang','','[]','詩古賦縱橫，令人畏後生。',48,'全唐诗/poet.tang.44000.json','["詩古賦縱橫，令人畏後生。", "駕言遊禹跡，知己在蒲城。", "日射雲煙散，風吹草木榮。", "孤吟臨寇境，莫問請長纓。"]'),
('c2201bb1-c41e-4c91-8696-fe91280f5c43','寄姚諫議','無可','唐','唐诗','tang','','[]','鳴鞭靜路塵，籍籍諫垣臣。',48,'全唐诗/poet.tang.44000.json','["鳴鞭靜路塵，籍籍諫垣臣。", "函疏辭專密，爐香立獨親。", "篋多臨水作，窗宿臥雲人。", "危坐開寒紙，燈前起草頻。"]'),
('3de65749-fe62-4aa3-9107-2377893203d8','大理正任二十和江淹擬古詩二十章寄示','無可','唐','唐诗','tang','','[]','不啻迴青眼，應疑似碧雲。',48,'全唐诗/poet.tang.44000.json','["不啻迴青眼，應疑似碧雲。", "古風真往哲，雅道濫朝聞。", "活獄威豪右，銷時賴典墳。", "如何經濟意，未克致吾君。"]'),
('ef632490-cfd7-44b0-8b52-23ff0d8bfd4b','寄殿院薛侍御','無可','唐','唐诗','tang','','[]','名高意本閑，浮俗自難攀。',48,'全唐诗/poet.tang.44000.json','["名高意本閑，浮俗自難攀。", "佐蜀連錢出，朝天獬豸還。", "迴翔歷清院，彈奏迥離班。", "休澣通玄旨，留僧晝掩關。"]'),
('29147d93-a1a1-4396-aa11-aa0aebf19be9','禪林寺','無可','唐','唐诗','tang','','[]','台山朝佛隴，勝地絕埃氛。',48,'全唐诗/poet.tang.44000.json','["台山朝佛隴，勝地絕埃氛。", "冷色石橋月，素光華頂雲。", "遠泉和雪溜，幽磬帶松聞。", "終斷游方念，爐香繼此焚。"]'),
('e9c9e03c-2625-48a2-b996-802c83ca2cb1','奉和裴舍人春日杜城舊事','無可','唐','唐诗','tang','','[]','早晚辭綸綍，觀農下杜西。',48,'全唐诗/poet.tang.44000.json','["早晚辭綸綍，觀農下杜西。", "草新池似鏡，麥暖土如泥。", "鵷鷺依川宿，驊騮向野嘶。", "春來詩更苦，松韻亦含淒。"]'),
('7a992026-4e07-4311-915b-a21abd8cdc6e','酬厲侍御秋中思歸樹石所居見寄','無可','唐','唐诗','tang','','[]','三峰居接近，數里躡雲行。',48,'全唐诗/poet.tang.44000.json','["三峰居接近，數里躡雲行。", "深去通仙境，思歸厭宦名。", "月從高掌出，泉向亂松鳴。", "坐石眠霞侶，秋來短褐成。"]'),
('742ef325-7040-47e5-ba0a-153885ce51d3','奉和段著作山居呈諸同志三首次本韻 一','無可','唐','唐诗','tang','','[]','香花懷道侶，巾舃立雙童。',48,'全唐诗/poet.tang.44000.json','["香花懷道侶，巾舃立雙童。", "解印鴛鴻內，抽毫水石中。", "履溫行燒地，衣赤動霞風。", "又似朝天去，諸僧不可同。"]'),
('5701b9e2-c755-47a4-873a-09165b755143','奉和段著作山居呈諸同志三首次本韻 二','無可','唐','唐诗','tang','','[]','官辭中祕府，疎放野麋齊。',48,'全唐诗/poet.tang.44000.json','["官辭中祕府，疎放野麋齊。", "偃仰青霄近，登臨白日低。", "折腰窺乳竇，定足涉冰溪。", "染翰揮嵐翠，僧名幾處題。"]'),
('f22ed7e9-699c-4656-8776-1a3a5047221a','奉和段著作山居呈諸同志三首次本韻 三','無可','唐','唐诗','tang','','[]','蹔收丹陛跡，獨往亂山居。',48,'全唐诗/poet.tang.44000.json','["蹔收丹陛跡，獨往亂山居。", "入雪知人遠，眠雲覺俗虛。", "足垂巖頂石，纓濯洞中渠。", "只見僧酬答，新歸絕壑書。"]'),
('792658ad-996a-4ac4-bef1-fd1f925410d7','春日送麗處士歸龍山','無可','唐','唐诗','tang','','[]','愛弟直霜臺，家山羨獨迴。',48,'全唐诗/poet.tang.44000.json','["愛弟直霜臺，家山羨獨迴。", "出門時返顧，何日更西來。", "柳亦臨關發，花應到越開。", "漁舟誰伴上，依舊恣沿洄。"]'),
('9877e2df-6ae2-4695-8297-6d8b6f4d4a1e','寄興善寺崔律師','無可','唐','唐诗','tang','','[]','沐浴前朝像，深秋白髮師。',48,'全唐诗/poet.tang.44000.json','["沐浴前朝像，深秋白髮師。", "從來居此寺，未省有東池。", "幽石叢圭片，孤松動雪枝。", "頃曾聽道話，別起遠山思。"]'),
('6aacd0bf-50f6-4d12-8ea8-8600264a0f89','送清散遊太白山','無可','唐','唐诗','tang','','[]','卷經歸太白，躡蘚別蘿龕。',48,'全唐诗/poet.tang.44000.json','["卷經歸太白，躡蘚別蘿龕。", "若履浮雲上，須看積翠南。", "倚身松入漢，瞑目月離潭。", "此境堪長往，塵中事可諳。"]'),
('a50d78f2-d718-48b2-899c-3d650599e235','冬晚姚諫議宅會送元緒上人歸南山','無可','唐','唐诗','tang','','[]','禪客詩家見，凝寒忽告還。',48,'全唐诗/poet.tang.44000.json','["禪客詩家見，凝寒忽告還。", "分題迴諫筆，留偈在商關。", "盤徑緣高雪，閑房在半山。", "自知麋鹿性，亦欲離人間。"]'),
('9c80fac5-46e1-40f6-8599-455d65183fdc','送契公自桂陽赴南海','無可','唐','唐诗','tang','','[]','南行登嶺首，與俗洗煩埃。',48,'全唐诗/poet.tang.44000.json','["南行登嶺首，與俗洗煩埃。", "磬罷孤舟發，禪移積瘴開。", "中餐湘鳥下，朝講海人來。", "莫便將經卷，炎方去不迴。"]'),
('b72efd2c-ee9c-415f-b8c7-e4c6e1fbd06f','冬中與諸公會宿姚端公宅懷永樂殷侍御','無可','唐','唐诗','tang','','[]','柱史靜開筵，所思何地偏。',48,'全唐诗/poet.tang.44000.json','["柱史靜開筵，所思何地偏。", "故人爲縣吏，五老遠峰前。", "賓榻寒侵樹，公庭夜落泉。", "會當隨假務，一就白雲禪。"]'),
('b9fcba60-5f82-4d7c-9134-8173aa472fa0','同劉秀才宿見贈','無可','唐','唐诗','tang','','[]','浮雲流水心，只是愛山林。',48,'全唐诗/poet.tang.44000.json','["浮雲流水心，只是愛山林。", "共恨多年別，相逢一夜吟。", "既能持苦節，勿謂少知音。", "憶就西池宿，月圓松竹深。"]'),
('6292240b-8d8b-4c2e-93bb-01fb7f684af6','官池上','無可','唐','唐诗','tang','','[]','迥疏城闕內，寒瀉出雲波。',48,'全唐诗/poet.tang.44000.json','["迥疏城闕內，寒瀉出雲波。", "岸廣山魚到，汀閑海鷺過。", "泛溝侵道急，流葉入宮多。", "移舸浮中沚，清宵徹曉河。"]'),
('1db834be-c4ca-4552-a1e8-96ef9b55a5ca','中秋月','無可','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蟾宜天地靜，三五對堦蓂。',48,'全唐诗/poet.tang.44000.json','["蟾宜天地靜，三五對堦蓂。", "照耀超諸夜，光芒掩衆星。", "影寒池更澈，露冷樹銷青。", "枉值中秋半，長乖宿洞庭。"]'),
('d3b8c73d-f1d7-4937-a386-8a58cd42df76','雪','無可','唐','唐诗','tang','','[]','松亞竹珊珊，心知萬井歡。',48,'全唐诗/poet.tang.44000.json','["松亞竹珊珊，心知萬井歡。", "山明迷舊逕，溪滿漲新瀾。", "客醉瑤臺曙，兵防玉塞寒。", "紅樓知有酒，誰肯學袁安。"]'),
('0aedb99f-597e-4c5d-9298-1ca2941a284e','宿西嶽白石院','無可','唐','唐诗','tang','','["\u534e\u5c71"]','白石上嵌空，寒雲西復東。',48,'全唐诗/poet.tang.44000.json','["白石上嵌空，寒雲西復東。", "瀑流懸住處，雛鶴失禪中。", "岳壁松多古，壇基雪不通。", "未能親近去，擁褐媿相同。"]'),
('ab64fb15-44fc-4ad7-8164-74627f1299ee','送僧','無可','唐','唐诗','tang','','[]','四海無拘繫，行心興自濃。',48,'全唐诗/poet.tang.44000.json','["四海無拘繫，行心興自濃。", "百年三事衲，萬里一枝筇。", "夜減當晴影，春消過雪蹤。", "白雲深處去，知宿在何峰。"]'),
('3e890612-c660-4adb-af77-f6515add9568','送贊律師歸嵩山','無可','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u4eba"]','禪意歸心急，山深定易安。',48,'全唐诗/poet.tang.44000.json','["禪意歸心急，山深定易安。", "清貧脩道苦，孝友別家難。", "雪路尋溪轉，花宮映嶽看。", "到時孤塔暮，松月向人寒。"]'),
('ef597c18-00ae-470b-a44b-02c631fbff37','春晚喜悟禪師自琉璃上方見過','無可','唐','唐诗','tang','','[]','琉璃師到城，談性外諸經。',48,'全唐诗/poet.tang.44000.json','["琉璃師到城，談性外諸經。", "下嶺雪霜在，近人林木清。", "苔痕深草履，瀑布滴銅瓶。", "樂問山中事，宵言徹曉星。"]'),
('97e0c005-215f-49c6-abe3-6b2653145082','秋暮與諸文士集宿姚端公所居','無可','唐','唐诗','tang','','[]','宵清月復圓，共集侍臣筵。',48,'全唐诗/poet.tang.44000.json','["宵清月復圓，共集侍臣筵。", "獨寡區中學，空論樹下禪。", "風多秋晚竹，雲盡夜深天。", "此會東西去，堪愁又隔年。"]'),
('23761c5d-3d9a-4609-9f6a-19d720285748','客中聞從兄島遊蒲絳因寄','無可','唐','唐诗','tang','','["\u9ec4\u6cb3"]','遙遙行李心，蒼野入寒深。',48,'全唐诗/poet.tang.44000.json','["遙遙行李心，蒼野入寒深。", "吟待黃河雪，眠聽絳郡砧。", "差期逢缺月，訪信出空林。", "何處孤燈下，只聞嘹唳禽。"]'),
('f7d64016-a1e2-4f3b-b16e-124ff2448863','送李長吉之任東井','無可','唐','唐诗','tang','','[]','江盤棧轉虛，候吏拜行車。',48,'全唐诗/poet.tang.44000.json','["江盤棧轉虛，候吏拜行車。", "家世維城後，官資宰邑初。", "市饒黃犢賣，田躡白雲鉏。", "萬里千山路，何因欲寄書。"]'),
('3a3e7928-8562-4c91-8b78-23055b2c7295','宿安國簡公院','無可','唐','唐诗','tang','','[]','雨後清涼境，因還欲不回。',48,'全唐诗/poet.tang.44000.json','["雨後清涼境，因還欲不回。", "井甘桐有露，竹迸地多苔。", "幡映宮牆動，香從御苑來。", "青龍舊經疏，寥落有誰開。"]'),
('384bf196-1ffe-447a-942e-da1b6dc8741e','京中別崔固','無可','唐','唐诗','tang','','[]','積雨晴時近，西風葉滿泉。',48,'全唐诗/poet.tang.44000.json','["積雨晴時近，西風葉滿泉。", "相逢嵩嶽客，共聽楚城蟬。", "宿館橫秋島，歸帆張遠田。", "別君還寂寞，不似剡中年。"]'),
('5e428dfd-4a72-409c-bac6-c1d1a9a49af6','中秋夜隴州徐常侍座中詠月','無可','唐','唐诗','tang','','[]','隴城秋月滿，太守待停歌。',48,'全唐诗/poet.tang.44000.json','["隴城秋月滿，太守待停歌。", "與鶴來松杪，開煙出海波。", "氣籠星欲盡，光滿露初多。", "若遣山僧說，高明不可過。"]'),
('f662e694-8414-4068-afa9-2ee0ebe3338e','中秋江驛示韋益','無可','唐','唐诗','tang','','[]','莫惜三更坐，難銷萬里情。',48,'全唐诗/poet.tang.44000.json','["莫惜三更坐，難銷萬里情。", "同看一片月，俱在廣州城。", "淚逐金波滿，魂隨夜鵲驚。", "支頤鄉思斷，無語到雞鳴。"]'),
('1f7e8ca2-66a8-4c08-bbec-d0e2f7094417','中秋臺看月','無可','唐','唐诗','tang','','[]','海雨洗煙埃，月從空碧來。',48,'全唐诗/poet.tang.44000.json','["海雨洗煙埃，月從空碧來。", "水光籠草樹，練影挂樓臺。", "皓耀迷鯨口，晶熒失蚌胎。", "宵分凭欄望，應合見蓬萊。"]'),
('b55c317d-2aff-44b4-8310-024921857243','中秋夜南樓寄友人','無可','唐','唐诗','tang','','[]','海月出白浪，湖光射高樓。',48,'全唐诗/poet.tang.44000.json','["海月出白浪，湖光射高樓。", "朗吟無綠酒，賤價買清秋。", "氣冷魚龍寂，輪高星漢幽。", "他鄉此夜客，對酌經多愁。"]'),
('0e50281c-4c74-4af1-8b52-2eccc6e8c280','弔從兄島','無可','唐','唐诗','tang','','[]','盡日歎沉淪，孤高碣石人。',48,'全唐诗/poet.tang.44000.json','["盡日歎沉淪，孤高碣石人。", "詩名從蓋代，謫宦竟終身。", "蜀集重編否，巴儀薄葬新。", "青門臨舊卷，欲見永無因。"]'),
('7e9b0466-dd5e-41c0-bbdd-a578d46a9503','題崔駙馬林亭','無可','唐','唐诗','tang','','["\u592a\u6e56"]','宮花野藥半相和，藤蔓參差惜不科。',64,'全唐诗/poet.tang.44000.json','["宮花野藥半相和，藤蔓參差惜不科。", "纖草連門留徑細，高樓出樹見山多。", "洞中避暑青苔滿，池上吟詩白鳥過。", "更買太湖千片石，疊成雲頂綠㠁峨。"]'),
('5ad107ad-9c84-4927-832c-bb1069a3e799','送韓校書赴江西','無可','唐','唐诗','tang','','[]','車馬東門別，揚帆過楚津。',72,'全唐诗/poet.tang.44000.json','["車馬東門別，揚帆過楚津。", "花繁期到幕，雪在已離秦。", "吟落江沙月，行飛驛騎塵。", "猨聲孤島雨，草色五湖春。", "折葦鳴風岸，遙煙起暮蘋。", "鄱江連郡府，高興寄何人。"]'),
('84f9b32b-8f70-47bc-bb74-ad0a91521b8d','送姚中丞赴陝州','無可','唐','唐诗','tang','','[]','二陝周分地，恩除左掖臣。',72,'全唐诗/poet.tang.44000.json','["二陝周分地，恩除左掖臣。", "門闌開幕重，槍甲下天新。", "夾道行霜騎，迎風滿草人。", "河流銀漢水，城賽鐵牛神。", "意氣思高謝，依違許上陳。", "何妨向紅斾，自與白雲親。"]'),
('104c25dc-b030-4c2b-8a7c-8e18e1d553ee','送李使君赴瓊州兼五州招討使','無可','唐','唐诗','tang','','[]','分竹雄兼使，南方到海行。',72,'全唐诗/poet.tang.44000.json','["分竹雄兼使，南方到海行。", "臨門雙斾引，隔嶺五州迎。", "猨鶴同枝宿，蘭蕉夾道生。", "雲垂前騎失，山豁去帆輕。", "雨霧蒸秋岸，浪濤震夜城。", "政閑開迥閣，欹枕島風清。"]'),
('5982642f-9c57-4a22-9e82-75c00f9760c6','送姚明府赴招義縣','無可','唐','唐诗','tang','','[]','濠梁古縣城，結束赴王程。',72,'全唐诗/poet.tang.44000.json','["濠梁古縣城，結束赴王程。", "道路攜家去，波濤隔月行。", "車臨芳草下，吏踏落花迎。", "暮郭山遙見，春洲鳥不驚。", "風煙譙國遠，桑柘楚田平。", "何以書能化，長淮徹海清。"]'),
('8dc67a62-e46e-4df3-a84d-6645ca9d4224','送杜司馬再遊蜀中','無可','唐','唐诗','tang','','[]','爲客應非願，愁成欲別時。',72,'全唐诗/poet.tang.44000.json','["爲客應非願，愁成欲別時。", "還遊蜀國去，不惜杜陵期。", "劍水啼猨在，關林轉棧遲。", "日光低峽口，雨勢出蛾眉。", "山迥逢殘角，雲開識遠夷。", "勿令雙鬢髮，併向錦城衰。"]'),
('1a2ddadf-e786-4ecb-88fc-7393dd62efdb','贈王將軍','無可','唐','唐诗','tang','','[]','勳高絕少年，分衛玉階前。',120,'全唐诗/poet.tang.44000.json','["勳高絕少年，分衛玉階前。", "雄勇明王重，溫恭執友賢。", "功書唐史滿，名到虜庭偏。", "劒彩浮龍影，衣香襲御煙。", "搜書秋霽閣，走馬夕陽田。", "急兔投深草，瞋鷹下半天。", "野人盈邸第，朝客醉盤筵。", "位在將軍列，官隨憲府遷。", "刻心思報國，吁氣欲開邊。", "選帥如公議，須知少比肩。"]'),
('d6680cc6-ca76-45ef-8a53-9c9970b4edd4','寄羽林盧大夫將軍','無可','唐','唐诗','tang','','[]','將軍直禁闈，繡服耀金羈。',72,'全唐诗/poet.tang.44000.json','["將軍直禁闈，繡服耀金羈。", "羽衛九天靜，英豪四塞知。", "望雲回朔鴈，隔水射宮麋。", "舊國無歸思，秋堂夢戰時。", "門風荀氏敵，劒藝霍家推。", "計日旌旄下，蕭蕭萬馬隨。"]'),
('af076467-cfb2-4f87-8524-111e7c9443d4','書事寄萬年厲員外','無可','唐','唐诗','tang','','["\u9ec4\u5c71"]','帝城皆劇縣，令尹美居東。',216,'全唐诗/poet.tang.44000.json','["帝城皆劇縣，令尹美居東。", "遂拜趙張下，暫離星象中。", "擁歸從北闕，送上動南宮。", "舉起盆中日，驅行草上風。", "不驚盧犬吠，漸見夏臺空。", "紫禁黃山遶，滄溟素滻通。", "封疆親日月，邑里出王公。", "逐盜千門啓，興祥五稼豐。", "胥徒迎曉集，賦稅共秋終。", "條教關天道，歌謠入聖聰。", "土膏寒麥覆，人海晝塵蒙。", "廨宇松連翠，朝街日散紅。", "文塲新桂茂，粉署舊蘭崇。", "留客把盈爵，抽毫詠早鴻。", "前騶潘岳貴，故里邵平窮。", "勸隱蓮峰久，期耕樹谷同。", "鳧飛將去葉，劒氣尚埋豐。", "何必華陰土，方垂拂拭功。"]'),
('338d2e85-f87e-4b2d-8dcb-6bdc72151737','小雪','無可','唐','唐诗','tang','','[]','片片互玲瓏，飛揚玉漏終。',144,'全唐诗/poet.tang.44000.json','["片片互玲瓏，飛揚玉漏終。", "乍微全滿地，漸密更無風。", "集物圓方別，連雲遠近同。", "作膏凝瘠土，呈瑞下深宮。", "氣射重衣透，花窺小隙通。", "飄秦增舊嶺，發漢攬長空。", "迥冒巢松鶴，孤鳴穴島蟲。", "過三知臘盡，盈尺賀年豐。", "委積休聞竹，稀疎漸見鴻。", "蓋沙資澶漫，灑海助沖融。", "草木潛加潤，山河更益雄。", "因知天地力，覆育有全功。"]'),
('c2249df1-73be-40c8-8862-d4e20902a054','和賓客相國詠雪詩','無可','唐','唐诗','tang','','[]','近臘千巖白，迎春四氣催。',192,'全唐诗/poet.tang.44000.json','["近臘千巖白，迎春四氣催。", "雲陰連海起，風急度山來。", "盡日隋堤絮，經冬越嶺梅。", "豔疑歌處散，輕似舞時迴。", "道蘊詩傳麗，相如賦騁才。", "霽添松篠媚，寒積蕙蘭猜。", "暗漲宮池水，平封輦路埃。", "燭龍初照耀，巢鶴乍裴回。", "簷日瓊先挂，牆風粉旋摧。", "五門環玉壘，雙闕封瑤臺。", "綺席陵寒坐，珠簾遠曙開。", "靈芝霜下秀，仙桂月中栽。", "卷幌書千帙，援琴酒百杯。", "垂休編太史，呈瑞表中台。", "皓夜迷三徑，浮光徹九垓。", "茲辰是豐歲，歌詠屬良哉。"]'),
('30534dae-0840-4636-9b31-7263ba0b418a','中秋夜君山脚下看月','無可','唐','唐诗','tang','','[]','洶湧吹蒼霧，朦朣吐玉盤。',96,'全唐诗/poet.tang.44000.json','["洶湧吹蒼霧，朦朣吐玉盤。", "雨師清滓穢，川后掃波瀾。", "氣射繁星滅，光籠八表寒。", "來驅雲漲晚，路上碧霄寬。", "熠燿遊何在，蟾蜍食漸難。", "棹飛銀電碎，林映白虹攢。", "水魄連空合，霜輝壓樹乾。", "夜深高不動，天下仰頭看。"]'),
('bdb09d2d-c20f-4ff6-a5a5-214eae70d405','哭張籍司業','無可','唐','唐诗','tang','','[]','先生抱衰疾，不起茂陵間。',72,'全唐诗/poet.tang.44000.json','["先生抱衰疾，不起茂陵間。", "夕臨諸孤少，荒居弔客還。", "遺文禪東岳，留語葬鄉山。", "多雨銘旌故，殘燈素帳閑。", "樂章誰與集，壠樹即堪攀。", "神理今難問，予將呌帝關。"]'),
('452638c1-0384-4cc4-bf3d-9fb44c6c8845','寄題廬山二林寺','無可','唐','唐诗','tang','','["\u5e90\u5c71"]','廬岳東南秀，香花惠遠蹤。',240,'全唐诗/poet.tang.44000.json','["廬岳東南秀，香花惠遠蹤。", "名齊松嶺峻，氣比沃州濃。", "積岫連何處，幽崖越幾重。", "雙流湓隱隱，九派棹憧憧。", "山限東西寺，林交旦暮鐘。", "半天傾瀑溜，數郡見鑪峰。", "巖竝金繩道，潭分玉像容。", "江微匡俗路，日杲晉朝松。", "椶逕新苞拆，梅籬故葉壅。", "嵐光生疊砌，霞焰發高墉。", "窗籟虛聞狖，庭煙黑過龍。", "定僧仙嶠起，逋客虎溪逢。", "濩落垂楊戶，荒涼種杏封。", "塔留紅舍利，池吐白芙蓉。", "畫壁披雲見，禪衣對鶴縫。", "喧經泉滴瀝，沒履草丰茸。", "翠竇欹攀乳，苔橋側杖筇。", "探奇盈夢想，搜峭滌心胸。", "冥奧終難盡，登臨惜未從。", "上方薇蕨滿，歸去養乖慵。"]'),
('9b47dded-b15a-43d4-bca8-de97a7d81f70','御溝水','無可','唐','唐诗','tang','','[]','鑿禁疏雲數道開，垂風岸柳拂青苔。',32,'全唐诗/poet.tang.44000.json','["鑿禁疏雲數道開，垂風岸柳拂青苔。", "銀波玉沫空池去，曾歷千巖萬壑來。"]'),
('728abe7b-c6bb-4b5f-b25f-bd97bea61e09','中秋月彩如晝寄上南海從翁侍御','無可','唐','唐诗','tang','','[]','海靜天高景氣殊，鯨睛失彩蚌潛珠。',32,'全唐诗/poet.tang.44000.json','["海靜天高景氣殊，鯨睛失彩蚌潛珠。", "不知今夜越臺上，望見瀛洲方丈無。"]'),
('b8f0e764-21df-4b21-8980-96c205607d78','奉酬于中丞使君郡齋臥病見示一首','皎然','唐','唐诗','tang','','[]','宿昔祖師教，了空無不可。',252,'全唐诗/poet.tang.44000.json','["宿昔祖師教，了空無不可。", "枯槁未死身，理心寄行坐。", "仁公施春令，和風來澤我。", "生成一草木，大道無負荷。", "論入空王室，明月開心胸。", "性起妙不染，心行寂無蹤。", "若非禪中侶，君爲雷次宗。", "比聞朝端名，今貽郡齋作。", "真思凝瑤瑟，高情屬雲鶴。", "抉得驪龍珠，光彩曜掌握。", "若作詩中友，君爲謝康樂。", "盤薄西山氣，貯在君子衿。", "澄澹秋水影，用爲字人心。", "羣物如鳧鷖，遊翺愛清深。", "格居第一品，高步凌前躅。", "精義究天人，四坐聽不足。", "伊昔柳太守，曾賞汀洲蘋。", "如何五百年，重見江南春。", "公每省往事，詠歌懷昔辰。", "以茲得高臥，任物化自淳。", "還因訪禪隱，知有雪山人。"]'),
('14aa628d-c0e4-4bf2-9943-689c8a2999b8','贈李中丞洪一首','皎然','唐','唐诗','tang','','[]','深沈閫外畧，奕世當榮寄。',276,'全唐诗/poet.tang.44000.json','["深沈閫外畧，奕世當榮寄。", "地裂大將封，家傳介珪瑞。", "至今漳河俗，猶受仁人賜。", "公初鎮惟邢，決勝無精兵。", "重圍逼大敵，六月守孤城。", "政用仁恕立，恩由賞罰明。", "遂令麾下士，感德不顧生。", "於時聞王師，諸將兵頗黷。", "天子狩南漢，煙塵滿函谷。", "純臣獨耿介，下士多反覆。", "明公仗忠節，一言感萬夫。", "物性如蒺蔾，化作春蘭敷。", "見說金被爍，終期玉有瑜。", "移官萬里道，君子情何如。", "伊昔避事心，乃是方袍客。", "頓了空王旨，仍高致君策。", "安知七十年，一朝值宗伯。", "言如及清風，醒然開我懷。", "宴息與遊樂，不將衣褐乖。", "海底取明月，鯨波不可度。", "上有巨蟒吞，下有毒龍護。", "一與吾師言，乃於中心悟。", "咄哉冥冥子，胡爲自塵汚。"]'),
('1e0bba31-6b98-45ef-844b-ecfba931bde8','杼山禪居寄贈東溪吳處士馮一首','皎然','唐','唐诗','tang','','[]','青雲何潤澤，下有賢人隱。',156,'全唐诗/poet.tang.44000.json','["青雲何潤澤，下有賢人隱。", "路入菱湖深，跡與黃鶴近。", "野風吹白芷，山月搖清軫。", "詩祖吳叔庠，致君名不盡。", "身當青山秀，文體多郢聲。", "澄澈湘水碧，泬寥楚山青。", "時人格不同，至今罕知名。", "昔賢敦師友，此道君獨行。", "既得廬霍趣，乃高雷遠情。", "別時春風多，掃盡雪山雪。", "爲君中夜起，孤坐石上月。", "悠然遺塵想，邈矣達性說。", "故人不在茲，幽桂惜未結。"]'),
('76d78e8e-6424-4da6-8282-9cab52d94c96','妙喜寺高房期靈澈上人不至重招之一首','皎然','唐','唐诗','tang','','[]','晨起峰頂心，懷人望空碧。',132,'全唐诗/poet.tang.44000.json','["晨起峰頂心，懷人望空碧。", "掃雪開寺門，灑水淨僧席。", "言笑形外阻，風儀想中覿。", "馳心驚葉動，傾耳聞泉滴。", "豈慮咆虎逢，乍疑崩湍隔。", "前期或不顧，知爾隳常格。", "如今誰山下，秋霖步淅瀝。", "吾亦聊自得，行禪荷輕策。", "松聲暢幽情，山意導遐跡。", "舉目無世人，題詩足奇石。", "貧山何所有，特此邀來客。"]'),
('3fa2b1aa-7277-42f4-8610-6dc0046307b0','奉和薛員外誼贈湯評事衡反招隱之跡兼見寄十二韻','皎然','唐','唐诗','tang','','[]','喜友稱高儒，曠懷美無度。',144,'全唐诗/poet.tang.44000.json','["喜友稱高儒，曠懷美無度。", "近爲東田誘，遂耽西山趣。", "庭有介隱心，得無雲泉誤。", "府公中司貴，頻貽咫尺素。", "郡佐仙省高，亦贈瓊瑤句。", "誚茲長往志，紆彼獨遊步。", "禪子方外期，夢想山中路。", "艱難親稼穡，晨夕苦煙霧。", "曷若孟嘗門，日榮國士遇。", "鏗鏘聆綺瑟，攀折邇瓊樹。", "幽踐隨鹿麋，久期怨蟾兔。", "情同不繫舟，有跡道所惡。"]'),
('863868eb-c356-4066-8d37-07024b992182','荅黎士曹黎生前適越後之楚','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','楚木紛如麻，高松自孤直。',216,'全唐诗/poet.tang.44000.json','["楚木紛如麻，高松自孤直。", "願得苦寒枝，與君比顏色。", "故鄉眇天末，羇旅滄江隅。", "委質在忠信，苦心無變渝。", "何繇表名義，贈君金轆轤。", "何以美知才，投我懸黎珠。", "遽爲千里別，南風思越絕。", "愛君隨海鷗，倚櫂宿沙月。", "不栖惡木上，肯蹈巴蛇穴。", "一上蕭然峰，擬蹤幽人轍。", "晨興獨西望，郢水期泝沿。", "夜到洞庭月，秋經雲夢天。", "黎生知吾道，此地不潸然。", "欲寄楚人住，學拏漁子船。", "奈何北風至，攪我窗中弦。", "遊子動歸思，江蘺亦綿綿。", "篋中封禪書，欲獻無由緣。", "豈乏晨風翼，翻飛到日邊。"]'),
('fe93054f-edf0-47ee-80ce-7b3c3ca17c79','荅豆盧次方','皎然','唐','唐诗','tang','','[]','吾愛道交論，爲高貴世名。',168,'全唐诗/poet.tang.44000.json','["吾愛道交論，爲高貴世名。", "昔稱柴桑令，今聞豆盧生。", "彼生清淮氣，獨鍾文中彩。", "近作公讌詩，如逢何柳在。", "吾用古人耳，採君四坐珍。", "賢士勝朝暉，溫溫無冬春。", "朝暉爍我肌，賢士清我神。", "微爾與雲鵠，幽懷何由申。", "別來秋風至，獨坐楚山碧。", "高月當清冥，禪心正寂歷。", "增波徒相駭，人遠情不隔。", "有書遺瓊什，以代貂襜褕。", "風教凌越絕，聲名掩吳趨。", "懸璧安可酬，徙倚還踟躕。"]'),
('dd7907df-caea-403d-8ec3-a16933e56943','荅蘇州韋應物郎中','皎然','唐','唐诗','tang','','[]','詩教殆淪缺，庸音互相傾。',180,'全唐诗/poet.tang.44000.json','["詩教殆淪缺，庸音互相傾。", "忽觀風騷韻，會我夙昔情。", "蕩漾學海資，鬱爲詩人英。", "格將寒松高，氣與秋江清。", "何必鄴中作，可爲千載程。", "受辭分虎竹，萬里臨江城。", "到日掃煩政，況今休黷兵。", "應憐禪家子，林下寂無營。", "跡隳世上華，心得道中精。", "脫畧文字累，免爲外物攖。", "書衣流埃積，硯石駮蘚生。", "恨未識君子，空傳手中瓊。", "安可誘我性，始願愆素誠。", "爲無鸑鷟音，繼公雲和笙。", "吟之向禪藪，反媿幽松聲。"]'),
('11c10589-06ec-4659-834d-3563b52b2426','荅鄭方回','皎然','唐','唐诗','tang','','[]','獨禪外念入，中夜不成定。',240,'全唐诗/poet.tang.44000.json','["獨禪外念入，中夜不成定。", "顧我顦顇容，澤君陽春詠。", "詞貞思且逸，瓊彩何暉映。", "如聆雲和音，況覩聲名盛。", "琴語掩爲聞，山心聲宜聽。", "是時寒光澈，萬境澄以淨。", "高秋日月清，中氣天地正。", "遠情偶茲夕，道用增寥敻。", "思君處虛空，一操不可更。", "時美城北徐，家承谷口鄭。", "軒車未有轍，蒿蘭且同徑。", "莊生誡近名，夫子罕言命。", "是以耕楚田，曠然殊獨行。", "萎蕤鸞鳳彩，特達珪璋性。", "通隱嘉黃綺，高儒重荀孟。", "世汚我未起，道蹇吾猶病。", "逸翮思冥冥，潛鱗樂游泳。", "宗師許學外，恨不逢孔聖。", "說詩迷頹靡，偶俗傷趨競。", "此道誰共詮，因君情欲罄。"]'),
('00db1630-ec79-4fa8-8234-54283b8cccad','答俞校書冬夜','皎然','唐','唐诗','tang','','[]','夜閑禪用精，空界亦清迥。',120,'全唐诗/poet.tang.44000.json','["夜閑禪用精，空界亦清迥。", "子真仙曹吏，好我如宗炳。", "一宿覿幽勝，形清煩慮屏。", "新聲殊激楚，麗句同歌郢。", "遺此感予懷，沈吟忘夕永。", "月彩散瑤碧，示君禪中境。", "真思在杳冥，浮念寄形影。", "遙得四明心，何須蹈岑嶺。", "詩情聊作用，空性惟寂靜。", "若許林下期，看君辭簿領。"]'),
('ec22288f-c16f-40fa-96b0-dc2d6fafbe4a','妙喜寺達公禪齋寄李司直公孫房都曹德裕從事方舟顏武康士騁四十二韻','皎然','唐','唐诗','tang','','[]','我祖傳六經，精義思朝徹。',288,'全唐诗/poet.tang.44000.json','["我祖傳六經，精義思朝徹。", "方舟頗周覽，逸書亦備閱。", "墨家傷刻薄，儒氏知優劣。", "弱植庶可彫，苦心未嘗輟。", "中年慕仙術，永願傳其訣。", "歲駐若木景，日餐瓊禾屑。", "嬋娟羨門子，斯語豈徒設。", "天上生白榆，葳蕤信好折。", "實可反柔顏，花堪養玄髮。", "求之性分外，業棄金亦竭。", "藥化成白雲，形彫辭素穴。", "一聞西天旨，初禪已無熱。", "涓子非我宗，然公有真訣。", "却尋丘壑趣，始與纓紱別。", "野飯敵膏粱，山楹代藻梲。", "與君北巖侶，遊寓日常昳。", "靜對春谷泉，晴披陽林雪。", "境清覺神王，道勝知機滅。", "詣寂長杳冥，忘歸暫采擷。", "物生豈有心，麗容俟予別。", "桂子何蓂苓，琪葩亦皎潔。", "此木生意高，亦與衆芳列。", "賞墨識屢換，省躬悟彌切。", "微尚若不虧，足以全吾節。"]'),
('84ad15d8-b61c-4bbf-b028-70e11b96e74f','遙酬袁使君高春暮行縣過報德寺見懷','皎然','唐','唐诗','tang','','[]','江春行求瘼，偶與真境期。',96,'全唐诗/poet.tang.44000.json','["江春行求瘼，偶與真境期。", "見說三陵下，前朝開佛祠。", "停舟仰麗剎，繡組發香墀。", "咫尺空界色，天人花落時。", "盛游限羸疾，悚踴瞻旌旗。", "峰翠羨閑步，松聲入遙思。", "素高淮陽理，況負東山姿。", "迨此一登覽，深情見新詩。"]'),
('7c1c148f-d4f6-4a08-bc8f-228106284683','冬日遙和盧使君幼平綦毋居士遊法華寺高頂臨湖亭','皎然','唐','唐诗','tang','','[]','仁坊標絕境，廉守躡高蹤。',84,'全唐诗/poet.tang.44000.json','["仁坊標絕境，廉守躡高蹤。", "天曉纔分剎，風傳欲盡鐘。", "城中歸路遠，湖上碧山重。", "水照千花界，雲開七葉峰。", "寒芳艾綬滿，空翠白綸濃。", "逸韻知難繼，佳遊恨不逢。", "仍聞撫禪石，爲我久從容。"]'),
('c4ef89c2-674e-4c3c-9892-ad52c474ea35','秋日遙和盧使君遊何山寺宿敭上人房論湼槃經義','皎然','唐','唐诗','tang','','[]','江郡當秋景，期將道者同。',60,'全唐诗/poet.tang.44000.json','["江郡當秋景，期將道者同。", "跡高憐竹寺，夜靜賞蓮宮。", "古磬清霜下，寒山曉月中。", "詩情緣境發，法性寄筌空。", "翻譯推南本，何人繼謝公。"]'),
('95de409d-5e91-4f3b-b39d-873c74579ceb','酬秦山人系題贈','皎然','唐','唐诗','tang','','[]','出齋步杉影，手自開禪扉。',48,'全唐诗/poet.tang.44000.json','["出齋步杉影，手自開禪扉。", "花滿不汚地，雲多從觸衣。", "思山石蘚淨，款客露葵肥。", "果得宗居士，論心到極微。"]'),
('bf099252-29af-429e-8444-28b0e9805236','奉酬袁使君高寺院新亭對雨','皎然','唐','唐诗','tang','','[]','茲亭跡素淺，勝事併隨公。',48,'全唐诗/poet.tang.44000.json','["茲亭跡素淺，勝事併隨公。", "法界飄香雨，禪窗灑竹風。", "浮煙披夕景，高鶴下秋空。", "冥寂四山久，寧期此會同。"]'),
('1434b681-cc52-4fc3-a1ea-930df29e3c36','奉酬顏使君真卿見過郭中寺寺無山水之賞故予述其意以荅焉','皎然','唐','唐诗','tang','','[]','州西柳家寺，禪舍隱人間。',48,'全唐诗/poet.tang.44000.json','["州西柳家寺，禪舍隱人間。", "證性輕觀水，棲心不買山。", "履聲知客貴，雲影悟身閑。", "彥會前賢事，方今可得攀。"]'),
('e7ae1828-8451-46ef-a30c-1ee2b6b0892e','酬烏程楊明府華雨後小亭對月見呈','皎然','唐','唐诗','tang','','[]','夜涼喜無訟，霽色搖閑情。',48,'全唐诗/poet.tang.44000.json','["夜涼喜無訟，霽色搖閑情。", "暑退不因雨，陶家風自清。", "凝弦停片景，發詠靜秋聲。", "何事禪中隱，詩題忽記名。"]'),
('b28b276e-7015-400d-a642-534e35758344','自蘇州訪醫迴酬盧士關判官見贈','皎然','唐','唐诗','tang','','[]','尋醫初疾理，忽憶故山雲。',48,'全唐诗/poet.tang.44000.json','["尋醫初疾理，忽憶故山雲。", "遠訪桑公子，還依柳使君。", "周旋承惠愛，佩服比蘭薰。", "從事因高唱，秋風起處聞。"]'),
('90a36d5a-67b6-4084-afc0-14ef6b3befc9','題沈道士新亭','皎然','唐','唐诗','tang','','[]','何處好攀躋，新亭俯舊溪。',48,'全唐诗/poet.tang.44000.json','["何處好攀躋，新亭俯舊溪。", "坐中千里近，簷下四山低。", "小浦依林曲，迴塘遶郭西。", "桃花春滿地，歸路莫相迷。"]'),
('a9f9aeeb-77f2-4a32-9dfa-1cabef93e1aa','送盧仲舒移家海陵','皎然','唐','唐诗','tang','','[]','世故多離散，東西不可嗟。',48,'全唐诗/poet.tang.44000.json','["世故多離散，東西不可嗟。", "小秦非本國，楚塞復移家。", "海島無鄰里，鹽居少物華。", "山中吟夜月，相送在天涯。"]'),
('7ff16065-3607-457f-b38a-86605468b818','陪盧使君登樓送方巨之還京','皎然','唐','唐诗','tang','','[]','萬里汀洲上，東樓欲別難。',48,'全唐诗/poet.tang.44000.json','["萬里汀洲上，東樓欲別難。", "春風潮水漫，正月柳條寒。", "旅逸逢漁浦，清高愛鳥冠。", "雲山寧不起，今日向長安。"]'),
('46b91254-d158-4763-9ff5-8a9d678b7ff5','同裴錄事樓上望','皎然','唐','唐诗','tang','','[]','退食高樓上，湖山向晚晴。',48,'全唐诗/poet.tang.44000.json','["退食高樓上，湖山向晚晴。", "桐花落萬井，月影出重城。", "水竹涼風起，簾幃暑氣清。", "蕭蕭獨無事，因見涖人情。"]'),
('be5a8c29-513d-4b1a-bb04-037e10dbc296','寓興','皎然','唐','唐诗','tang','','[]','天下生白榆，白榆直上連天根。',78,'全唐诗/poet.tang.44000.json','["天下生白榆，白榆直上連天根。", "高枝不知幾萬丈，世人仰望徒攀援。", "誰能上天採其子，種向人間笑桃李。", "因問老仙求種法，老仙咍我愚不答。", "始知此道無所成，還如瞽夫學長生。"]'),
('d6a5e687-73c2-46a9-9834-54af759f2f62','寄常一上人','皎然','唐','唐诗','tang','','[]','雁塞五山臨汗漫，雲州一路出青冥。',32,'全唐诗/poet.tang.44000.json','["雁塞五山臨汗漫，雲州一路出青冥。", "何因請住嘉祥寺，內史新修湖上亭。"]'),
('1583aebb-74a9-4e41-b852-d87700cdb8eb','送祕上人遊京','皎然','唐','唐诗','tang','','[]','共君方異路，山伴與誰同。',48,'全唐诗/poet.tang.44000.json','["共君方異路，山伴與誰同。", "日冷行人少，時清古鎮空。", "煖瓶和雪水，鳴錫帶江風。", "撩亂終南色，遙應入夢中。"]'),
('9c49f610-d0f1-4d1b-944c-6a3141dfecec','賦得啼猨送客','皎然','唐','唐诗','tang','','[]','萬里巴江外，三聲月峽深。',48,'全唐诗/poet.tang.44000.json','["萬里巴江外，三聲月峽深。", "何年有此路，幾客共霑襟。", "斷壁分垂影，流泉入苦吟。", "悽涼離別後，聞此更傷心。"]'),
('d9f6c9fa-2003-451e-bba8-6af25298e8be','南樓望月','皎然','唐','唐诗','tang','','[]','夜月家家望，亭亭愛此樓。',48,'全唐诗/poet.tang.44000.json','["夜月家家望，亭亭愛此樓。", "纖雲溪上斷，疎柳影中秋。", "漸映千峰出，遙分萬派流。", "關山誰復見，應獨起邊愁。"]'),
('565d931a-ff49-4f37-b633-524b48c2f4f0','尋陸鴻漸不遇','皎然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9690\u58eb", "\u8bbf\u53cb", "\u751f\u6d3b", "\u4e94\u8a00\u5f8b\u8bd7"]','移家雖帶郭，野徑入桑麻。',48,'全唐诗/poet.tang.44000.json','["移家雖帶郭，野徑入桑麻。", "近種籬邊菊，秋來未著花。", "扣門無犬吠，欲去問西家。", "報道山中去，歸時每日斜。"]'),
('376733c2-fa07-4423-b494-fca090ba1a7d','懷舊山','皎然','唐','唐诗','tang','','[]','一坐西林寺，從來未下山。',48,'全唐诗/poet.tang.44000.json','["一坐西林寺，從來未下山。", "不因尋長者，無事到人間。", "宿雨愁爲客，寒花笑未還。", "空懷舊山月，童子念經閑。"]'),
('33e086a3-db83-407e-ac80-5775ab6cf3d7','宿吳匡山破寺','皎然','唐','唐诗','tang','','["\u5e90\u5c71"]','雙峰百戰後，真界滿塵埃。',48,'全唐诗/poet.tang.44000.json','["雙峰百戰後，真界滿塵埃。", "蔓草緣空壁，悲風起故臺。", "野花寒更發，山月暝還來。", "何事池中水，東流獨不迴。"]'),
('9cbfa6fb-822d-4eb3-a6c3-01921a9383c2','九月十日','皎然','唐','唐诗','tang','','[]','愛殺柴桑隱，名溪近訟庭。',48,'全唐诗/poet.tang.44000.json','["愛殺柴桑隱，名溪近訟庭。", "掃沙開野步，搖舸出閑汀。", "宿簡邀詩伴，餘花在酒瓶。", "悠然南望意，自有峴山情。"]'),
('ba29d8ca-702d-48e6-a5e7-8bccaed81eee','秋晚宿破山寺','皎然','唐','唐诗','tang','','[]','秋風落葉滿空山，古寺殘燈石壁間。',32,'全唐诗/poet.tang.44000.json','["秋風落葉滿空山，古寺殘燈石壁間。", "昔日經行人去盡，寒雲夜夜自飛還。"]'),
('314751bd-00d3-4388-ad5e-c4430f917f25','青陽上人院說金陵故事','皎然','唐','唐诗','tang','','[]','君說南朝全盛日，秣陵才子更多人。',32,'全唐诗/poet.tang.44000.json','["君說南朝全盛日，秣陵才子更多人。", "千年秋色古池館，誰見齊王西邸春。"]'),
('08728318-88da-47ec-bb71-db8eb83d3f48','送僧之京師','皎然','唐','唐诗','tang','','[]','綿綿渺渺楚雲繁，萬里西歸望國門。',32,'全唐诗/poet.tang.44000.json','["綿綿渺渺楚雲繁，萬里西歸望國門。", "禪子初心易悽斷，秋風莫上少陵原。"]'),
('f710670c-48ba-4092-b77b-2e1646203272','送許丞還洛陽','皎然','唐','唐诗','tang','','[]','剡茗情來亦好斟，空門一別肯霑襟。',32,'全唐诗/poet.tang.44000.json','["剡茗情來亦好斟，空門一別肯霑襟。", "悲風不動罷瑤軫，忘却洛陽歸客心。"]'),
('b3a3c964-8842-45b3-9160-e32e0778230d','題湖上草堂','皎然','唐','唐诗','tang','','[]','山居不買剡中山，湖上千峰處處閑。',32,'全唐诗/poet.tang.44000.json','["山居不買剡中山，湖上千峰處處閑。", "芳草白雲留我住，世人何事得相關。"]'),
('6a4d651e-2ecd-4a05-a234-f34af7a8b66b','酬李司直縱諸公冬日遊妙喜寺題照昱二上人房寄長城潘丞述','皎然','唐','唐诗','tang','','[]','達賢貴貞隱，常懼跡不滅。',84,'全唐诗/poet.tang.44000.json','["達賢貴貞隱，常懼跡不滅。", "遂與永公期，遺身坐林樾。", "華軒何轔轔，爲我到幽絕。", "心境寒草花，空門青山月。", "潘生獨不見，清景屢盈缺。", "林下常寂寥，人間自離別。", "何時解輕佩，來稅丘中轍。"]'),
('0a940d3e-b268-40e5-9a07-9591322ce4dd','贈烏程李明府伯宜沈兵曹仲昌','皎然','唐','唐诗','tang','','[]','水國苦彫瘵，東臯豈遺黍。',72,'全唐诗/poet.tang.44000.json','["水國苦彫瘵，東臯豈遺黍。", "雲陰無盡時，日出常帶雨。", "昨夜西溪漲，扁舟入簷廡。", "野人同鳥巢，暴客若蜂聚。", "歲晏無斗粟，寄身欲何所。", "空羨鸞鶴姿，翩翩自輕舉。"]'),
('e0bbf92a-b334-46a1-b662-e6334826f43c','奉酬顏使君真卿王員外圓宿寺兼送員外使迴','皎然','唐','唐诗','tang','','[]','魯公邀省客，貧寺人過少。',72,'全唐诗/poet.tang.44000.json','["魯公邀省客，貧寺人過少。", "錦帳惟野花，竹屏有窗篠。", "朝行石色淨，夜聽泉聲小。", "釋事情已高，依禪境無擾。", "超遙長路首，悵望空林杪。", "離思從此生，還將此心了。"]'),
('9a805605-bfd7-47f6-8473-d1b428ab883b','杼山上峰和顏使君真卿袁侍御五韻賦得印字仍期明日登開元寺樓之會','皎然','唐','唐诗','tang','','[]','道情寄遠岳，放曠臨千仞。',60,'全唐诗/poet.tang.44000.json','["道情寄遠岳，放曠臨千仞。", "香路延絳騶，華泉寫金印。", "日欹諸天近，雨過三華潤。", "留客雲外心，忘機松中韻。", "靈嘉早晚期，爲布東山信。"]'),
('b55470ee-c645-4315-a91a-44b5dc412267','同薛員外誼喜雨詩兼上楊使君','皎然','唐','唐诗','tang','','[]','積旱忽飛澍，烝民心亦傾。',96,'全唐诗/poet.tang.44000.json','["積旱忽飛澍，烝民心亦傾。", "郊雲不待族，雨色飛江城。", "燋稼濯又發，敗荷滋更榮。", "時隨霧縠重，乍集柳絲輕。", "一宿恐魚飛，數朝徵鸛鳴。", "毒暑澄爲冷，高塵滌還清。", "乃知陰隲數，制在造化情。", "及此接歡賀，臨風聞頌聲。"]'),
('9778f6d6-c727-43b1-b7a2-687b81baa8f6','南湖春泛有客自北至說友人岑元和見懷因叙相思之志以寄焉','皎然','唐','唐诗','tang','','[]','故人隔楚水，日夕望芳洲。',180,'全唐诗/poet.tang.44000.json','["故人隔楚水，日夕望芳洲。", "春草思眇眇，征雲暮悠悠。", "心期無形影，跡曠成阻修。", "有客江上至，知君佐雄州。", "鏗鏹佩蒼玉，躞蹀驅絳騶。", "伊昔中峰心，從來非此流。", "資予長生訣，希彼高山儔。", "此情今如何，宿昔師吾謀。", "別後謁禪老，更添石室籌。", "深見人間世，飄如水上漚。", "蟬號齊王邸，月苦隋帝樓。", "聲華盡冥寞，麋鹿徒呦呦。", "我有一字教，坐然遺此憂。", "何煩脫珪組，不用辭王侯。", "祗在名位中，空門兼可遊。"]'),
('3a783ec4-b803-431d-8593-df60fde235cc','同薛員外誼久旱感懷寄兼呈上楊使君','皎然','唐','唐诗','tang','','[]','皇天鑒不昧，愐想何亢極。',132,'全唐诗/poet.tang.44000.json','["皇天鑒不昧，愐想何亢極。", "絲雨久愆期，綺霞徒相惑。", "陰雲舒又卷，濯枝安可得。", "涸井不纍瓶，乾溪一憑軾。", "赤地芳草死，飆塵驚四塞。", "戎寇夜刺閨，民荒歲傷國。", "賴以王猷盛，中原無凶慝。", "楊公當此晨，省災常旰食。", "獨感下堂雨，偏嘉越境域。", "秋郊天根見，我疆看稼穡。", "請迴雲漢詩，爲君歌樂職。"]'),
('eec34419-ad78-42b4-84b9-ac0a05a15fa9','兵後早春登故鄣南樓望崑山寺白鶴觀示清道人幷沈道士','皎然','唐','唐诗','tang','','[]','新陽故樓上，眇眇傷遐睠。',168,'全唐诗/poet.tang.44000.json','["新陽故樓上，眇眇傷遐睠。", "違世情易忘，羇時得無倦。", "春歸華柳發，世故陵谷變。", "擾擾陌上心，悠悠夢中見。", "蒼林有靈境，杳映遙可羨。", "春日倚東峰，華泉落西甸。", "鐘聲在空碧，幡影搖蔥蒨。", "緬想山中人，神期如會面。", "別離芳月積，岐路浮雲徧。", "正□入空門，仙君依苦縣。", "隳形捨簪紱，烹玉思精鍊。", "事外宜我心，人間豈予戀。", "身遺世自薄，道勝名必賤。", "耳目何所娛，白雲與黃卷。"]'),
('dafc03ab-f819-4a5c-a94d-e3211612b9c3','酬烏程楊明府華將赴渭北對月見懷','皎然','唐','唐诗','tang','','[]','釋印及秋夜，身閑境亦清。',108,'全唐诗/poet.tang.44000.json','["釋印及秋夜，身閑境亦清。", "風襟自瀟灑，月意何高明。", "聞說武安君，萬里驅妖精。", "開府集秀士，先招士林英。", "晉家用元凱，亦是魯諸生。", "北望撫長劒，感君知已行。", "邊塵昏玉帳，殺氣凝金鐙。", "大敵折齊俎，一書下聊城。", "翻飛青雲路，宿昔滄洲情。"]'),
('531b5d8a-136f-491e-9da0-11c9dfdc5d7c','酬邢端公濟春日蘇臺有呈袁州李使君兼書幷寄辛陽王三侍御','皎然','唐','唐诗','tang','','[]','大賢當佐世，堯時難退身。',96,'全唐诗/poet.tang.44000.json','["大賢當佐世，堯時難退身。", "如何丹霄侶，却在滄江濱。", "柳色變又徧，鶯聲聞亦頻。", "賴逢宜春守，共賞南湖春。", "營道知止足，飾躬無緇磷。", "家將詩流近，跡與禪僧親。", "放曠臨海門，翺翔望雲津。", "雖高空王說，不久山中人。"]'),
('9f4d5a97-3172-4a94-9293-96be6cb07db7','奉和裴使君清春夜南堂聽陳山人彈白雪','皎然','唐','唐诗','tang','','[]','春宵凝麗思，閑坐開南圍。',84,'全唐诗/poet.tang.44000.json','["春宵凝麗思，閑坐開南圍。", "郢客彈白雪，紛綸發金徽。", "散從天上至，集向瓊臺飛。", "弦上凝颯颯，虛中想霏霏。", "通幽鬼神駭，合道精鑒稀。", "變態風更入，含情月初歸。", "方知阮太守，一聽識其微。"]'),
('b765d611-2817-4494-b383-e3eab2604eee','荅孟秀才','皎然','唐','唐诗','tang','','[]','羸疾依小院，空閑趣自深。',60,'全唐诗/poet.tang.44000.json','["羸疾依小院，空閑趣自深。", "躡苔憐靜色，掃樹共芳陰。", "物外好風至，意中佳客尋。", "虛名誰欲累，世事我無心。", "投贈荷君芷，馨香滿幽襟。"]'),
('2951b1a7-89bc-48c3-9b4d-f96c9648e995','酬崔侍御見贈','皎然','唐','唐诗','tang','','[]','買得東山後，逢君小隱時。',48,'全唐诗/poet.tang.44000.json','["買得東山後，逢君小隱時。", "五湖遊不厭，柏署跡如遺。", "市隱何妨道，禪棲不廢詩。", "與君爲此說，長破小乘疑。"]'),
('108d711a-7647-4c50-bd1e-da1562f34446','贈柳喜得嵩山法門自號嵩山老','皎然','唐','唐诗','tang','','[]','一見嵩山老，吾生恨太遲。',24,'全唐诗/poet.tang.44000.json','["一見嵩山老，吾生恨太遲。", "問君年幾許，曾出上皇時。"]'),
('212043ae-d73e-4655-9560-6289a8976e62','酬李補闕紓','皎然','唐','唐诗','tang','','[]','不住東林寺，雲泉處處行。',24,'全唐诗/poet.tang.44000.json','["不住東林寺，雲泉處處行。", "近臣那得識，禪客本無名。"]'),
('741cdc50-fca8-4b9b-9147-3fc5c34c55bd','湖南蘭若示大乘諸公','皎然','唐','唐诗','tang','','[]','未到無爲岸，空憐不繫舟。',24,'全唐诗/poet.tang.44000.json','["未到無爲岸，空憐不繫舟。", "東山白雲意，歲晚尚悠悠。"]'),
('19fb967f-b3f4-442c-89f5-832803878b94','兵後經永安法空寺寄悟禪師','皎然','唐','唐诗','tang','','[]','常說人間法自空，何言出世法還同。',64,'全唐诗/poet.tang.44000.json','["常說人間法自空，何言出世法還同。", "微蹤舊是香林下，餘燼今成火宅中。", "後夜池心生素月，春天樹色起悲風。", "吾知世代相看盡，誰悟浮生似影公。"]'),
('6b2e7509-c3ae-42b6-9a70-62ac0046e378','春日杼山寄贈李員外縱','皎然','唐','唐诗','tang','','[]','南山唯與北山鄰，古樹連拳伴我身。',64,'全唐诗/poet.tang.44000.json','["南山唯與北山鄰，古樹連拳伴我身。", "黃鶴有心多不住，白雲無事獨相親。", "閑持竹錫深看水，嬾繫麻衣出見人。", "欲掇幽芳聊贈遠，郎官那賞石門春。"]'),
('2569a5e8-696a-439d-88e8-516a3560f86f','酬秦山人贈別二首 一','皎然','唐','唐诗','tang','','[]','知君高隱占賢星，卷葉時時注佛經。',64,'全唐诗/poet.tang.44000.json','["知君高隱占賢星，卷葉時時注佛經。", "姓被名公題舊里，詩將麗句號新亭。", "來觀新月依清室，欲漱香泉護觸瓶。", "我有主人江太守，如何相伴住禪靈。"]'),
('d857eb0a-4c2c-4af9-bf0f-013fc83b804c','酬秦山人贈別二首 二','皎然','唐','唐诗','tang','','[]','誰知臥病不妨禪，跡寄詩流性似偏。',64,'全唐诗/poet.tang.44000.json','["誰知臥病不妨禪，跡寄詩流性似偏。", "葉示黃金童子愛，書題青字古人傳。", "時高獨鶴來雲外，每羨閑花在眼前。", "對此留君還欲別，應思石瀃訪春泉。"]'),
('6b477609-0d51-4a2b-ab3c-f568bb5e19c2','山居示靈澈上人','皎然','唐','唐诗','tang','','["\u611f\u609f", "\u6625\u5929", "\u5199\u666f", "\u5c71"]','晴明路出山初暖，行踏春蕪看茗歸。',64,'全唐诗/poet.tang.44000.json','["晴明路出山初暖，行踏春蕪看茗歸。", "乍削柳枝聊代札，時窺雲影學裁衣。", "身閑始覺隳名是，心了方知苦行非。", "外物寂中誰似我，松聲草色共無機。"]'),
('c6e76531-1973-40a9-b4d4-a9e109cffb3f','遙和康錄事李侍御萼小寒食夜重集康氏園林','皎然','唐','唐诗','tang','','[]','習家寒食會何頻，應恐流芳不待人。',64,'全唐诗/poet.tang.44000.json','["習家寒食會何頻，應恐流芳不待人。", "已愛治書詩句逸，更聞從事酒名新。", "庭蕪暗積承雙履，林蘤雷飛灑幅巾。", "誰見柰園時節共，還持綠茗賞殘春。"]'),
('07f9f636-65eb-4f34-b0de-3af51576a7c6','釋裴循春愁','皎然','唐','唐诗','tang','','[]','蝶舞鶯歌喜歲芳，柳絲褭褭蕙帶長。',32,'全唐诗/poet.tang.44000.json','["蝶舞鶯歌喜歲芳，柳絲褭褭蕙帶長。", "江南春色共君有，何事君心獨自傷。"]'),
('2d6a979c-d58b-46f2-b6bc-b2a16c9b176d','西白溪期裴方舟不至','皎然','唐','唐诗','tang','','[]','望君不見復何情，野草閑雲處處生。',32,'全唐诗/poet.tang.44000.json','["望君不見復何情，野草閑雲處處生。", "應向秦時武陵路，花間寂歷一人行。"]'),
('4a94e78d-5747-40ab-a800-41fd44b2abb3','勞山憶棲霞寺道素上人久期不至','皎然','唐','唐诗','tang','','[]','遠寺蕭蕭獨坐心，山情自得趣何深。',80,'全唐诗/poet.tang.44000.json','["遠寺蕭蕭獨坐心，山情自得趣何深。", "泉聲稍滴芙蓉漏，月影纔分鸚鵡林。", "滿地雲輕長礙屣，繞松風近每吹襟。", "貪閑不記前心偈，念別聊爲出世吟。", "更待花開徧山雪，山山相似若爲尋。"]'),
('68af631d-9665-40e5-8431-5bb3e81b9853','酬秦山人出山見呈','皎然','唐','唐诗','tang','','[]','手攜酒榼共書幃，迴語長松我即歸。',32,'全唐诗/poet.tang.44000.json','["手攜酒榼共書幃，迴語長松我即歸。", "若是出山機已息，嶺雲何事背君飛。"]'),
('5a4f4d23-320a-449d-b5e4-4f1bf37c3ffa','酬秦山人見尋','皎然','唐','唐诗','tang','','[]','左右香童不識君，擔簦訪我領鷗羣。',32,'全唐诗/poet.tang.44000.json','["左右香童不識君，擔簦訪我領鷗羣。", "山僧待客無俗物，唯有窗前片碧雲。"]'),
('cb7a9cbc-2b89-4d6d-a19c-78d6d10db9fc','宿法華寺簡靈澈上人','皎然','唐','唐诗','tang','','[]','至道無機但杳冥，孤燈寒竹自青熒。',32,'全唐诗/poet.tang.44000.json','["至道無機但杳冥，孤燈寒竹自青熒。", "不知何處小乘客，一夜風來聞誦經。"]'),
('6ac30981-e79e-4260-a0e6-fc98530e04dd','潛別離','皎然','唐','唐诗','tang','','[]','烏頭雖黑白有時，唯有潛離與暗別，彼此甘心無後期。',24,'全唐诗/poet.tang.44000.json','["烏頭雖黑白有時，唯有潛離與暗別，彼此甘心無後期。"]'),
('59af369d-0a5a-42d0-a9e6-81d2d555570f','奉酬袁使君高春遊鶺鴒峰蘭若見懷','皎然','唐','唐诗','tang','','[]','鶺鴒中峰近，高奇古人遺。',84,'全唐诗/poet.tang.44000.json','["鶺鴒中峰近，高奇古人遺。", "常欲乞此地，養松挂藤絲。", "昨聞雙旌出，一川花滿時。", "恨無翔雲步，遠赴關山期。", "躋險與誰賞，折芳應自怡。", "遙知忘歸趣，喜得春景遲。", "已見郢人唱，新題石門詩。"]'),
('5ff4a393-5302-4e3f-a50e-f1d215acffa8','荅裴濟從事','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','遲遲雲鶴意，奮翅知有期。',96,'全唐诗/poet.tang.44000.json','["遲遲雲鶴意，奮翅知有期。", "三秉綱紀局，累登清白資。", "應懷青塘居，蕙草沒前墀。", "舊月照秋水，廢田留故陂。", "至今高風在，爲君吹桂枝。", "昨逢洞庭客，果得故人詩。", "何異王內史，來招道林師。", "欲攜山侶出，難與白雲辭。"]'),
('9613a13b-9388-4984-9626-cb66afb315ae','白雲上人精舍尋杼山禪師兼示崔子向何山道上人','皎然','唐','唐诗','tang','','[]','望遠涉寒水，懷人在幽境。',144,'全唐诗/poet.tang.44000.json','["望遠涉寒水，懷人在幽境。", "爲高皎皎姿，及愛蒼蒼嶺。", "果見栖禪子，潺湲灌真頂。", "積疑一念破，澄息萬緣靜。", "世事花上塵，惠心空中境。", "清閑誘我性，遂使腸慮屏。", "許共林客遊，欲從山王請。", "木栖無名樹，水汲忘機井。", "持此一日高，未肯謝箕潁。", "夕霽山態好，空月生俄頃。", "識妙聆細泉，悟深滌清茗。", "此心誰得失，笑向西林永。"]'),
('780d237f-2675-490f-8fa1-747021ce863a','酬薛員外誼苦熱行見寄','皎然','唐','唐诗','tang','','[]','六月金數伏，茲辰日在庚。',120,'全唐诗/poet.tang.44000.json','["六月金數伏，茲辰日在庚。", "炎曦爍肌膚，毒霧昏性情。", "安得奮輕翮，超遙出雲征。", "不知天地心，如何匠生成。", "火德燒百卉，瑤草不及榮。", "省客當此時，忽貽懷中瓊。", "捧翫煩袂滌，嘯歌美風生。", "遲君佐元氣，調使四序平。", "中令霜不祓，大餘氣常貞。", "江南詩騷客，休吟苦熱行。"]'),
('2d138595-e6e1-4241-b59a-6d61d3db897d','採實心竹杖寄贈李萼侍御','皎然','唐','唐诗','tang','','[]','竹杖裁碧鮮，步林賞高直。',60,'全唐诗/poet.tang.44000.json','["竹杖裁碧鮮，步林賞高直。", "實心去內矯，全節無外飾。", "行藥聊自持，扶危資爾力。", "初生在榛莽，孤秀豈封殖。", "干雪不死枝，贈君期君識。"]'),
('9eef0b94-1966-40ca-b6af-bedac75ced7a','酬薛員外誼見戲一首','皎然','唐','唐诗','tang','','[]','方知正始作，麗掩碧雲詩。',72,'全唐诗/poet.tang.44000.json','["方知正始作，麗掩碧雲詩。", "文彩盈懷袖，風規發詠思。", "遺弓逢大敵，摩壘怯偏師。", "頻有移書讓，多慙繫組遲。", "淺才迂且拙，虛譽喜還疑。", "猶倚披沙鑒，長歌向子期。"]');
